/// Emacs `diary-lunar-phases`: the sexp diary entry that reports a moon phase on
/// the date it is listed for — so this reports today's phase, if today has one.
/// (`calendar-lunar-phases` lists the whole month's.)
fn diary_lunar_phases(cx: &mut Context) {
    let today = diary_today();
    let phase = zmax_core::calendar::lunar_phases_in_month(today.year, today.month)
        .into_iter()
        .find(|(d, _)| *d == today);
    match phase {
        Some((_, name)) => cx.editor.set_status(format!("Today: {name}")),
        None => cx.editor.set_status("No lunar phase today"),
    }
}

/// The default location used by the sunrise/sunset diary entries. Emacs reads
/// `calendar-latitude` / `calendar-longitude`; zmax has no such variable yet,
/// so the same default `calendar-sunrise-sunset` uses is used here.
const DIARY_LAT: f64 = 40.7128;
const DIARY_LON: f64 = -74.0060;

/// Emacs `diary-sunrise-sunset`: the sexp diary entry reporting today's sunrise
/// and sunset (at the default location, in UTC — zmax has no
/// `calendar-latitude`/`-longitude`/`-time-zone` variables).
fn diary_sunrise_sunset(cx: &mut Context) {
    let today = diary_today();
    match zmax_core::calendar::sunrise_sunset_utc(today, DIARY_LAT, DIARY_LON) {
        Some((rise, set)) => cx.editor.set_status(format!(
            "Sunrise {} UTC, sunset {} UTC ({DIARY_LAT},{DIARY_LON})",
            zmax_core::calendar::format_hm(rise),
            zmax_core::calendar::format_hm(set),
        )),
        None => cx
            .editor
            .set_status("No sunrise/sunset today at the default location (polar day/night)"),
    }
}

/// Emacs `diary-hebrew-sabbath-candles`: the sexp diary entry giving Friday's
/// candle-lighting time — 18 minutes before sunset (Emacs's
/// `diary-hebrew-sabbath-candles-minutes` default). Reports nothing on the other
/// six days, as the entry does.
fn diary_hebrew_sabbath_candles(cx: &mut Context) {
    const CANDLE_MINUTES: f64 = 18.0;
    let today = diary_today();
    // 5 = Friday (0 = Sunday), the day the Sabbath begins at sunset.
    if zmax_core::calendar::weekday(today) != 5 {
        cx.editor
            .set_status("Sabbath candles: only on Friday (the Sabbath begins at sunset)");
        return;
    }
    match zmax_core::calendar::sunrise_sunset_utc(today, DIARY_LAT, DIARY_LON) {
        Some((_, set)) => {
            let candles = set - CANDLE_MINUTES / 60.0;
            cx.editor.set_status(format!(
                "Sabbath candles {} UTC (sunset {} UTC, {CANDLE_MINUTES:.0} min before)",
                zmax_core::calendar::format_hm(candles),
                zmax_core::calendar::format_hm(set),
            ));
        }
        None => cx
            .editor
            .set_status("No sunset today at the default location (polar day/night)"),
    }
}

/// Emacs `diary-fancy-display`: show the day's entries in the "fancy" (headed)
/// format. zmax has no separate *Fancy Diary* buffer, so the entries are
/// reported (dated header + each entry) in the echo area.
fn diary_fancy_display(cx: &mut Context) {
    let today = diary_today();
    let entries = diary_entries();
    let hits = zmax_core::diary::sorted_entries_for(&entries, today);
    if hits.is_empty() {
        cx.editor
            .set_status("Diary: no entries for today".to_string());
        return;
    }
    let header = zmax_core::diary::format_daily_styled(today, diary_style());
    let body = hits
        .iter()
        .map(|e| e.display_text(today))
        .collect::<Vec<_>>()
        .join("; ");
    cx.editor
        .set_status(format!("{}— {}", header.trim_end(), body));
}

/// Emacs `diary-simple-display`: the day's entries in the "simple" (unheaded)
/// format — each entry text, in time order, with no dated header. zmax has no
/// separate *Diary* buffer, so the entries are reported in the echo area.
fn diary_simple_display(cx: &mut Context) {
    let today = diary_today();
    let entries = diary_entries();
    let hits = zmax_core::diary::sorted_entries_for(&entries, today);
    if hits.is_empty() {
        cx.editor
            .set_status("Diary: no entries for today".to_string());
        return;
    }
    let body = hits
        .iter()
        .map(|e| e.display_text(today))
        .collect::<Vec<_>>()
        .join("; ");
    cx.editor.set_status(format!("Diary: {body}"));
}

/// Emacs `diary-include-other-diary-files`: pull in the entries of files named
/// by `#include "FILE"` directives at the top of the diary. `diary_entries`
/// already splices includes; standalone this reports how many files/entries the
/// diary pulls in.
fn diary_include_other_diary_files(cx: &mut Context) {
    let includes = match std::fs::read_to_string(diary_path()) {
        Ok(text) => zmax_core::diary::include_paths(&text),
        Err(_) => Vec::new(),
    };
    if includes.is_empty() {
        cx.editor
            .set_status("Diary: no #include directives".to_string());
        return;
    }
    let total = diary_entries().len();
    cx.editor.set_status(format!(
        "Diary: {} #include file{} ({} entries total): {}",
        includes.len(),
        if includes.len() == 1 { "" } else { "s" },
        total,
        includes.join(", ")
    ));
}

/// Emacs `diary-mark-included-diary-files`: mark the calendar dates carrying
/// entries from `#include`d files. zmax marks all diary dates uniformly (the
/// included entries are already spliced into `diary_entries`); standalone this
/// reports how many of this month's days are marked, includes counted.
fn diary_mark_included_diary_files(cx: &mut Context) {
    let entries = diary_entries();
    let today = diary_today();
    let dim = zmax_core::calendar::days_in_month(today.year, today.month);
    let marked = (1..=dim)
        .filter(|&d| {
            zmax_core::diary::has_entry(
                &entries,
                zmax_core::calendar::Date::new(today.year, today.month, d),
            )
        })
        .count();
    cx.editor.set_status(format!(
        "Diary (with includes): {marked} marked date{} in {} {}",
        if marked == 1 { "" } else { "s" },
        zmax_core::calendar::MONTH_NAMES[(today.month - 1) as usize],
        today.year
    ));
}

/// The iCalendar file path (`~/diary.ics`), the export target / import source.
fn icalendar_path() -> std::path::PathBuf {
    zmax_stdx::path::home_dir()
        .map(|h| h.join("diary.ics"))
        .unwrap_or_else(|_| std::path::PathBuf::from("diary.ics"))
}

/// Append imported diary `lines` to the diary file and report the count.
fn icalendar_append_to_diary(cx: &mut Context, lines: Vec<String>) {
    if lines.is_empty() {
        cx.editor
            .set_status("icalendar: no events to import".to_string());
        return;
    }
    let path = diary_path();
    let mut contents = std::fs::read_to_string(&path).unwrap_or_default();
    if !contents.is_empty() && !contents.ends_with('\n') {
        contents.push('\n');
    }
    for line in &lines {
        contents.push_str(line);
        contents.push('\n');
    }
    if let Err(e) = std::fs::write(&path, &contents) {
        cx.editor
            .set_error(format!("icalendar: cannot write {}: {e}", path.display()));
        return;
    }
    cx.editor.set_status(format!(
        "icalendar: imported {} event{} into {}",
        lines.len(),
        if lines.len() == 1 { "" } else { "s" },
        path.display()
    ));
}

/// Write `export` to the `.ics` file and report the outcome.
fn icalendar_write_export(cx: &mut Context, export: zmax_core::icalendar::Export) {
    let out = icalendar_path();
    if let Err(e) = std::fs::write(&out, &export.ics) {
        cx.editor
            .set_error(format!("icalendar: cannot write {}: {e}", out.display()));
        return;
    }
    cx.editor.set_status(format!(
        "icalendar: exported {} event{} to {} ({} skipped)",
        export.exported,
        if export.exported == 1 { "" } else { "s" },
        out.display(),
        export.skipped
    ));
}

/// Emacs `icalendar-export-file`: convert the diary file to `~/diary.ics`.
fn icalendar_export_file(cx: &mut Context) {
    let text = std::fs::read_to_string(diary_path()).unwrap_or_default();
    let entries = zmax_core::diary::parse_file_with_style(&text, diary_style());
    let export = zmax_core::icalendar::export_entries(&entries, diary_today());
    icalendar_write_export(cx, export);
}

/// Emacs `icalendar-export-region`: convert the diary entries in the selected
/// region to `~/diary.ics`.
fn icalendar_export_region(cx: &mut Context) {
    let region = {
        let (view, doc) = current!(cx.editor);
        let text = doc.text().slice(..);
        let sel = doc.selection(view.id).primary();
        text.slice(sel.from()..sel.to()).to_string()
    };
    let entries = zmax_core::diary::parse_file_with_style(&region, diary_style());
    let export = zmax_core::icalendar::export_entries(&entries, diary_today());
    icalendar_write_export(cx, export);
}

/// Emacs `icalendar-import-file`: import `~/diary.ics` into the diary file.
fn icalendar_import_file(cx: &mut Context) {
    let src = icalendar_path();
    match std::fs::read_to_string(&src) {
        Ok(text) => {
            let lines = zmax_core::icalendar::import_ical(&text);
            icalendar_append_to_diary(cx, lines);
        }
        Err(e) => cx
            .editor
            .set_error(format!("icalendar: cannot read {}: {e}", src.display())),
    }
}

/// Emacs `icalendar-import-buffer`: import the current buffer's iCalendar text
/// into the diary file.
fn icalendar_import_buffer(cx: &mut Context) {
    let text = {
        let (_view, doc) = current!(cx.editor);
        doc.text().to_string()
    };
    let lines = zmax_core::icalendar::import_ical(&text);
    icalendar_append_to_diary(cx, lines);
}

/// Emacs `diary-sort-entries`: sort the day's diary display by the time at the
/// start of each entry. The display commands already sort, so standalone this
/// reports the time-ordered entries for today.
fn diary_sort_entries(cx: &mut Context) {
    let today = diary_today();
    let entries = diary_entries();
    let hits = zmax_core::diary::sorted_entries_for(&entries, today);
    if hits.is_empty() {
        cx.editor
            .set_status("Diary: no entries to sort for today".to_string());
        return;
    }
    let body = hits
        .iter()
        .map(|e| e.display_text(today))
        .collect::<Vec<_>>()
        .join(" · ");
    cx.editor.set_status(format!("Diary (by time): {body}"));
}

/// Emacs `diary-print-entries` (`p` in the Diary display): print today's diary
/// display. Emacs sends the diary buffer to `print-buffer`; zmax renders the
/// same text through [`zmax_core::ps_print`] and pipes it to `lpr`, which is
/// what every other `ps-print-*` command here does.
fn diary_print_entries(cx: &mut Context) {
    use zmax_core::ps_print::{to_postscript, PsOptions};
    let today = diary_today();
    let entries = diary_entries();
    let hits = zmax_core::diary::sorted_entries_for(&entries, today);
    if hits.is_empty() {
        cx.editor.set_status("Diary: no entries for today to print");
        return;
    }
    let title = format!("Diary for {}", diary_style().date_string(today));
    let mut body = format!("{title}\n\n");
    for e in &hits {
        body.push_str(&e.display_text(today));
        body.push('\n');
    }
    let ps = to_postscript(
        &body,
        &PsOptions {
            title,
            ..Default::default()
        },
    );
    ps_lpr(cx.editor, &ps);
}

/// Emacs `diary-day-of-year`: report the day-of-year string for today.
fn diary_day_of_year(cx: &mut Context) {
    cx.editor
        .set_status(zmax_core::diary::day_of_year_string(diary_today()));
}

