/// Emacs `diff-mode`: open the unified-diff viewer on the working-tree `git diff`.
fn diffmode(cx: &mut Context) {
    let cwd = std::env::current_dir().unwrap_or_else(|_| std::path::PathBuf::from("."));
    let diff_text = std::process::Command::new("git")
        .arg("diff")
        .current_dir(&cwd)
        .output()
        .ok()
        .filter(|o| o.status.success())
        .map(|o| String::from_utf8_lossy(&o.stdout).into_owned())
        .filter(|s| !s.trim().is_empty())
        .unwrap_or_else(|| {
            "--- a/example.txt\n+++ b/example.txt\n@@ -1,2 +1,2 @@\n context\n-old line\n+new line\n"
                .to_string()
        });
    open_overlay(cx, move |_editor| {
        Ok(Box::new(crate::ui::diffmode::DiffMode::new(diff_text)) as Box<dyn Component>)
    });
}

/// Line index of point in the current document (0-based).
fn diff_point_line(cx: &mut Context) -> (usize, String) {
    let (view, doc) = current_ref!(cx.editor);
    let text = doc.text();
    let slice = text.slice(..);
    let cursor = doc.selection(view.id).primary().cursor(slice);
    (slice.char_to_line(cursor), text.to_string())
}

/// Replace the whole current document with `new_text` via one transaction.
fn diff_replace_buffer(cx: &mut Context, new_text: String) {
    let (view, doc) = current!(cx.editor);
    let text = doc.text();
    let len = text.len_chars();
    let tx = Transaction::change(text, std::iter::once((0, len, Some(new_text.into()))));
    doc.apply(&tx, view.id);
}

/// Emacs `diff-hunk-kill` (M-k): delete the hunk at point (and its file header
/// if it was the file's only hunk).
fn diff_hunk_kill(cx: &mut Context) {
    let (line, full) = diff_point_line(cx);
    match zmax_core::diffmode::diff_hunk_kill(&full, line) {
        Some(new) => {
            diff_replace_buffer(cx, new);
            cx.editor.set_status("Killed hunk");
        }
        None => cx
            .editor
            .set_status("diff-hunk-kill: point is not in a hunk"),
    }
}

/// Emacs `diff-file-kill` (M-K): delete the whole file section at point.
fn diff_file_kill(cx: &mut Context) {
    let (line, full) = diff_point_line(cx);
    match zmax_core::diffmode::diff_file_kill(&full, line) {
        Some(new) => {
            diff_replace_buffer(cx, new);
            cx.editor.set_status("Killed file section");
        }
        None => cx
            .editor
            .set_status("diff-file-kill: point is not in a file section"),
    }
}

/// Emacs `diff-split-hunk` (C-c C-s): split the unified hunk at point into two.
fn diff_split_hunk(cx: &mut Context) {
    let (line, full) = diff_point_line(cx);
    match zmax_core::diffmode::diff_split_hunk(&full, line) {
        Some(new) => {
            diff_replace_buffer(cx, new);
            cx.editor.set_status("Split hunk");
        }
        None => cx
            .editor
            .set_status("diff-split-hunk: point must be on a body line inside a unified hunk"),
    }
}

/// Emacs `diff-ignore-whitespace-hunk` (C-c C-w): re-diff the hunk at point
/// ignoring whitespace — every `-`/`+` pair that differs only in spaces and tabs
/// collapses to a context line, and the `@@` lengths are recomputed.
fn diff_ignore_whitespace_hunk(cx: &mut Context) {
    let (line, full) = diff_point_line(cx);
    match zmax_core::diffmode::diff_ignore_whitespace_hunk(&full, line) {
        Some(new) if new == full => cx
            .editor
            .set_status("diff-ignore-whitespace-hunk: no whitespace-only change in this hunk"),
        Some(new) => {
            diff_replace_buffer(cx, new);
            cx.editor
                .set_status("Re-diffed the hunk ignoring whitespace");
        }
        None => cx
            .editor
            .set_status("diff-ignore-whitespace-hunk: point is not in a unified hunk"),
    }
}

/// Emacs `diff-reverse-direction` (C-c C-r): swap the direction of the diff.
fn diff_reverse_direction(cx: &mut Context) {
    let (_line, full) = diff_point_line(cx);
    let new = zmax_core::diffmode::diff_reverse_direction(&full);
    diff_replace_buffer(cx, new);
    cx.editor.set_status("Reversed diff direction");
}

/// Emacs `diff-context->unified` (C-c C-u): convert a context diff to unified.
fn diff_context_to_unified(cx: &mut Context) {
    let (_line, full) = diff_point_line(cx);
    let new = zmax_core::diffmode::diff_context_to_unified(&full);
    diff_replace_buffer(cx, new);
    cx.editor.set_status("Converted context diff to unified");
}

/// Emacs `diff-unified->context` (C-c C-w — inverse of the above).
fn diff_unified_to_context(cx: &mut Context) {
    let (_line, full) = diff_point_line(cx);
    let new = zmax_core::diffmode::diff_unified_to_context(&full);
    diff_replace_buffer(cx, new);
    cx.editor.set_status("Converted unified diff to context");
}

/// Emacs `diff-delete-trailing-whitespace`: strip trailing whitespace from the
/// added lines in the buffer (in-buffer only; does not edit source files).
fn diff_delete_trailing_whitespace(cx: &mut Context) {
    let (_line, full) = diff_point_line(cx);
    let new = zmax_core::diffmode::diff_delete_trailing_whitespace(&full);
    diff_replace_buffer(cx, new);
    cx.editor
        .set_status("Deleted trailing whitespace from added lines");
}

/// Emacs `diff-restrict-view` (C-c C-n): narrow the buffer to the hunk at point.
fn diff_restrict_view(cx: &mut Context) {
    let (line, full) = diff_point_line(cx);
    match zmax_core::diffmode::hunk_line_bounds(&full, line) {
        Some((start, end)) => {
            let (view, doc) = current!(cx.editor);
            let text = doc.text();
            let slice = text.slice(..);
            let cstart = slice.line_to_char(start.min(slice.len_lines()));
            let cend = if end >= slice.len_lines() {
                text.len_chars()
            } else {
                slice.line_to_char(end)
            };
            doc.narrow_to(cstart, cend);
            let _ = view;
            cx.editor
                .set_status("Restricted view to hunk (widen to undo)");
        }
        None => cx
            .editor
            .set_status("diff-restrict-view: point is not in a hunk"),
    }
}

/// Resolve a diff-relative path against the cwd, then the diff buffer's dir.
fn diff_resolve_target(cx: &mut Context, rel: &str) -> Option<std::path::PathBuf> {
    let cwd = std::env::current_dir().ok();
    if let Some(base) = &cwd {
        let p = base.join(rel);
        if p.exists() {
            return Some(p);
        }
    }
    let (_view, doc) = current_ref!(cx.editor);
    if let Some(dir) = doc.path().and_then(|p| p.parent()) {
        let p = dir.join(rel);
        if p.exists() {
            return Some(p);
        }
    }
    cwd.map(|b| b.join(rel))
}

/// Emacs `diff-apply-hunk` (C-c C-a): apply the hunk at point to its target file.
fn diff_apply_hunk(cx: &mut Context) {
    use zmax_core::diffmode::{apply_hunk, file_line_bounds, hunk_line_bounds, parse};
    let (line, full) = diff_point_line(cx);
    let (Some((fs, fe)), Some((hs, he))) =
        (file_line_bounds(&full, line), hunk_line_bounds(&full, line))
    else {
        cx.editor
            .set_status("diff-apply-hunk: point is not in a hunk");
        return;
    };
    let all: Vec<&str> = full.lines().collect();
    let first_hunk = (fs..fe).find(|&i| all[i].starts_with("@@")).unwrap_or(hs);
    let mut snippet = String::new();
    for &idx in all.iter().take(first_hunk).skip(fs) {
        snippet.push_str(idx);
        snippet.push('\n');
    }
    for &idx in all.iter().take(he).skip(hs) {
        snippet.push_str(idx);
        snippet.push('\n');
    }
    let d = parse(&snippet);
    let Some(file) = d.files.first() else {
        cx.editor
            .set_status("diff-apply-hunk: could not parse the hunk");
        return;
    };
    let Some(hunk) = file.hunks.first() else {
        cx.editor.set_status("diff-apply-hunk: no hunk at point");
        return;
    };
    let rel = if file.new_path.is_empty() {
        file.old_path.clone()
    } else {
        file.new_path.clone()
    };
    let Some(target) = diff_resolve_target(cx, &rel) else {
        cx.editor
            .set_status(format!("diff-apply-hunk: cannot locate target {rel}"));
        return;
    };
    let Ok(content) = std::fs::read_to_string(&target) else {
        cx.editor
            .set_status(format!("diff-apply-hunk: cannot read {}", target.display()));
        return;
    };
    match apply_hunk(&content, hunk) {
        Ok(patched) => match std::fs::write(&target, patched) {
            Ok(()) => cx
                .editor
                .set_status(format!("Applied hunk to {}", target.display())),
            Err(e) => cx
                .editor
                .set_status(format!("diff-apply-hunk: write failed: {e}")),
        },
        Err(e) => cx.editor.set_status(format!("diff-apply-hunk: {e}")),
    }
}

/// Emacs `diff-refresh-hunk` (`C-c C-d`): re-diff the hunk at point — collapse
/// any `-`/`+` pair that is no longer a change back into a context line and
/// recompute the `@@` counts from the body.
fn diff_refresh_hunk(cx: &mut Context) {
    let (line, full) = diff_point_line(cx);
    match zmax_core::diffmode::diff_refresh_hunk(&full, line) {
        Some(new) if new == full => cx
            .editor
            .set_status("diff-refresh-hunk: the hunk is already minimal"),
        Some(new) => {
            diff_replace_buffer(cx, new);
            cx.editor.set_status("Re-diffed the hunk");
        }
        None => cx
            .editor
            .set_status("diff-refresh-hunk: point is not in a unified hunk"),
    }
}

/// Emacs `diff-ediff-patch`: apply this patch buffer to its target file and open
/// the result in the side-by-side (ediff) view, so the patch can be reviewed
/// hunk by hunk before it is written back — `ediff-patch-file` on the current
/// buffer.
fn diff_ediff_patch(cx: &mut Context) {
    use zmax_core::diffmode::{apply_file_diff, file_line_bounds, parse};
    let (line, full) = diff_point_line(cx);
    // The file section point is in (a patch buffer can hold several).
    let section = match file_line_bounds(&full, line) {
        Some((fs, fe)) => full
            .lines()
            .skip(fs)
            .take(fe - fs)
            .collect::<Vec<_>>()
            .join("\n"),
        None => full.clone(),
    };
    let d = parse(&section);
    let Some(file) = d.files.first() else {
        cx.editor
            .set_error("diff-ediff-patch: no patch in this buffer");
        return;
    };
    let rel = if file.new_path.is_empty() {
        file.old_path.clone()
    } else {
        file.new_path.clone()
    };
    let Some(target) = diff_resolve_target(cx, &rel) else {
        cx.editor
            .set_error(format!("diff-ediff-patch: cannot locate target {rel}"));
        return;
    };
    let Ok(original) = std::fs::read_to_string(&target) else {
        cx.editor.set_error(format!(
            "diff-ediff-patch: cannot read {}",
            target.display()
        ));
        return;
    };
    let patched = match apply_file_diff(&original, file) {
        Ok(patched) => patched,
        Err(e) => {
            cx.editor.set_error(format!("diff-ediff-patch: {e}"));
            return;
        }
    };
    // Open the target file, then diff the file on disk (left) against the patched
    // text (right). Applying in the ediff view writes the merged result back.
    if let Err(e) = cx.editor.open(&target, Action::Replace) {
        cx.editor.set_error(format!(
            "diff-ediff-patch: cannot open {}: {e}",
            target.display()
        ));
        return;
    }
    let doc_id = doc!(cx.editor).id();
    let name = target
        .file_name()
        .map(|n| n.to_string_lossy().into_owned())
        .unwrap_or(rel);
    let view =
        crate::ui::merge::DiffView::new(format!("{name} ⇔ patched"), doc_id, &original, &patched);
    cx.callback.push(Box::new(
        move |compositor: &mut Compositor, _cx: &mut compositor::Context| {
            compositor.push(Box::new(view));
        },
    ));
}

/// Emacs `add-change-log-entry-other-window` as Diff mode binds it (`C-x 4 a` in
/// a diff buffer): start a ChangeLog entry for the file — and the function — the
/// hunk at point belongs to, rather than for the buffer being visited.
fn diff_add_change_log_entry_other_window(cx: &mut Context) {
    let (line, full) = diff_point_line(cx);
    let lines: Vec<&str> = full.lines().collect();
    let Some((fs, _fe)) = zmax_core::diffmode::file_line_bounds(&full, line) else {
        cx.editor
            .set_error("add-change-log-entry: point is not in a diff file section");
        return;
    };
    // The file this section patches: its `+++ b/<path>` header.
    let Some(file) = lines
        .iter()
        .skip(fs)
        .take(line.saturating_sub(fs) + 1)
        .rev()
        .chain(lines.iter().skip(fs))
        .find_map(|l| {
            let rest = l.strip_prefix("+++ ")?;
            let path = rest.split('\t').next().unwrap_or(rest).trim();
            let path = path.strip_prefix("b/").unwrap_or(path);
            (path != "/dev/null" && !path.is_empty()).then(|| path.to_string())
        })
    else {
        cx.editor
            .set_error("add-change-log-entry: no `+++` header for this section");
        return;
    };
    // The function the hunk at point falls in — git writes it after the `@@`.
    let symbol = zmax_core::diffmode::hunk_line_bounds(&full, line)
        .and_then(|(hs, _)| lines.get(hs).copied())
        .and_then(|header| header.splitn(3, "@@").nth(2))
        .map(str::trim)
        .filter(|c| !c.is_empty())
        .and_then(|context| {
            // Reuse the ChangeLog module's name extraction (it is what
            // `log-edit-generate-changelog-from-diff` uses on the same text).
            let entry = zmax_core::changelog::entries_from_diff(&format!(
                "+++ b/{file}\n@@ -1 +1 @@ {context}\n"
            ));
            entry
                .first()
                .and_then(|l| zmax_core::changelog::source_at(l).and_then(|(_, symbol)| symbol))
        });
    let path = change_log_file(cx.editor);
    let header = change_log_header();
    let existing = std::fs::read_to_string(&path).unwrap_or_default();
    let entry = zmax_core::changelog::insert_entry(
        &existing,
        &header,
        &zmax_core::changelog::file_line(&file, symbol.as_deref()),
    );
    change_log_insert(cx, &path, &entry);
}

/// Emacs `diff-apply-buffer`: apply every hunk in the diff buffer to its files.
fn diff_apply_buffer(cx: &mut Context) {
    use zmax_core::diffmode::{apply_file_diff, parse};
    let (_line, full) = diff_point_line(cx);
    let d = parse(&full);
    if d.files.is_empty() {
        cx.editor.set_status("diff-apply-buffer: no diff in buffer");
        return;
    }
    let mut applied = 0usize;
    let mut failed: Vec<String> = Vec::new();
    for file in &d.files {
        let rel = if file.new_path.is_empty() {
            file.old_path.clone()
        } else {
            file.new_path.clone()
        };
        let Some(target) = diff_resolve_target(cx, &rel) else {
            failed.push(rel);
            continue;
        };
        let Ok(content) = std::fs::read_to_string(&target) else {
            failed.push(target.display().to_string());
            continue;
        };
        match apply_file_diff(&content, file) {
            Ok(patched) if std::fs::write(&target, &patched).is_ok() => applied += 1,
            _ => failed.push(target.display().to_string()),
        }
    }
    if failed.is_empty() {
        cx.editor
            .set_status(format!("Applied all hunks to {applied} file(s)"));
    } else {
        cx.editor.set_status(format!(
            "Applied {applied} file(s); failed: {}",
            failed.join(", ")
        ));
    }
}

/// Emacs `picture-mode`: draw ASCII pictures on a 2-D canvas.
fn picture(cx: &mut Context) {
    open_overlay(cx, |_editor| {
        Ok(Box::new(crate::ui::picture::Picture::new()) as Box<dyn Component>)
    });
}

/// Emacs `table.el` (M-x table-insert): edit a text table.
fn table(cx: &mut Context) {
    open_overlay(cx, |_editor| {
        Ok(Box::new(crate::ui::table::TableEditor::new()) as Box<dyn Component>)
    });
}

/// The ASCII table found around point: its char range in the buffer, the parsed
/// [`Table`](zmax_core::table::Table), and the `(row, col)` of the cell the
/// caret sits in. Backs the `table-*` commands that operate on the table at
/// point (recognize/justify/split/widen/…).
struct TableCtx {
    start: usize,
    end: usize,
    /// The buffer line the table's first line sits on — its identity for
    /// `table-recognize` / `table-unrecognize`.
    start_line: usize,
    table: zmax_core::table::Table,
    row: usize,
    col: usize,
}

/// Find the contiguous run of ASCII-table lines (each trimmed line starting with
/// `+` or `|`) containing `cursor`, parse it, and locate the caret's cell.
fn table_at_point(text: &Rope, cursor: usize) -> Option<TableCtx> {
    use zmax_core::table::{cell_at_position, recognize};
    let slice = text.slice(..);
    let n_lines = slice.len_lines();
    let cursor_line = slice.char_to_line(cursor);
    let is_tbl = |line: usize| -> bool {
        if line >= n_lines {
            return false;
        }
        let s: String = slice.line(line).chars().collect();
        let t = s.trim_start();
        t.starts_with('+') || t.starts_with('|')
    };
    if !is_tbl(cursor_line) {
        return None;
    }
    let mut first = cursor_line;
    while first > 0 && is_tbl(first - 1) {
        first -= 1;
    }
    let mut last = cursor_line;
    while last + 1 < n_lines && is_tbl(last + 1) {
        last += 1;
    }
    let start = slice.line_to_char(first);
    let end = if last + 1 < n_lines {
        slice.line_to_char(last + 1)
    } else {
        slice.len_chars()
    };
    let block: String = slice.slice(start..end).chars().collect();
    let table = recognize(&block)?;
    let line_in_block = cursor_line - first;
    let col_in_line = cursor - slice.line_to_char(cursor_line);
    let (row, col) = cell_at_position(&block, line_in_block, col_in_line).unwrap_or((0, 0));
    Some(TableCtx {
        start,
        end,
        start_line: first,
        table,
        row,
        col,
    })
}

/// [`table_at_point`] for the primary caret of the current view — but only if the
/// table is *recognized*: `table-unrecognize` leaves the text alone and makes the
/// table inert, so the at-point commands must not see it.
fn table_at_cursor(cx: &mut Context) -> Option<TableCtx> {
    let (view, doc) = current_ref!(cx.editor);
    let text = doc.text();
    let cursor = doc.selection(view.id).primary().cursor(text.slice(..));
    let tc = table_at_point(text, cursor)?;
    table_recognized(doc.id(), tc.start_line).then_some(tc)
}

/// [`table_at_cursor`], also refusing a cell that `table-unrecognize-cell` has
/// deactivated. Used by the cell-scoped commands.
fn table_cell_at_cursor(cx: &mut Context) -> Option<TableCtx> {
    let tc = table_at_cursor(cx)?;
    let doc = doc!(cx.editor).id();
    table_cell_active(doc, tc.start_line, tc.row, tc.col).then_some(tc)
}

/// The column widths to pin the table in `[start, end)` to, when
/// `table-fixed-width-mode` is on: the widths its grid *already has* in the
/// buffer. `None` when the mode is off (the columns are free to grow).
fn table_fixed_widths(cx: &Context, start: usize, end: usize) -> Option<Vec<usize>> {
    if !TABLE_FIXED_WIDTH.with(|f| f.get()) {
        return None;
    }
    let block: String = doc!(cx.editor).text().slice(start..end).chars().collect();
    zmax_core::table::grid_col_widths(&block)
}

/// Replace the buffer range `[start, end)` with `table`'s freshly rendered grid.
/// Honours `table-fixed-width-mode`: with it on, the columns keep the widths the
/// grid has in the buffer and any cell that outgrew its column is word-wrapped
/// instead (the row gets taller).
fn replace_table_region(
    cx: &mut Context,
    start: usize,
    end: usize,
    table: &zmax_core::table::Table,
) {
    let fitted = table_fixed_widths(cx, start, end).map(|widths| {
        let mut t = table.clone();
        t.fit_to_widths(&widths);
        t
    });
    replace_table_region_raw(cx, start, end, fitted.as_ref().unwrap_or(table));
}

/// [`replace_table_region`] without the fixed-width fit — for the commands that
/// change a column's width *on purpose* (`table-widen-cell` / `table-narrow-cell`),
/// which pass the table already fitted to the width they asked for.
fn replace_table_region_raw(
    cx: &mut Context,
    start: usize,
    end: usize,
    table: &zmax_core::table::Table,
) {
    let (view, doc) = current!(cx.editor);
    let rendered = table.render();
    let tx = Transaction::change(
        doc.text(),
        std::iter::once((start, end, Some(rendered.into()))),
    );
    doc.apply(&tx, view.id);
    doc.append_changes_to_history(view);
}

/// Shared refusal for the `table-*` at-point commands: point is not on a table at
/// all, or it is on one that `table-unrecognize`/`table-unrecognize-cell` has
/// deactivated.
fn not_on_table(cx: &mut Context) {
    let (view, doc) = current_ref!(cx.editor);
    let cursor = doc
        .selection(view.id)
        .primary()
        .cursor(doc.text().slice(..));
    let msg = match table_at_point(doc.text(), cursor) {
        Some(tc) if !table_recognized(doc.id(), tc.start_line) => {
            "the table at point is not recognized (M-x table-recognize)"
        }
        Some(_) => "the cell at point is not recognized (M-x table-recognize)",
        None => "point is not inside a text table (start a line with + or |)",
    };
    cx.editor.set_error(msg);
}

/// Emacs `table-recognize` / `table-recognize-table`: activate the ASCII table at
/// point — parse it into the internal model, take it (and its cells) back out of
/// the unrecognized set so the `table-*` commands operate on it again, and report
/// its dimensions.
fn table_recognize(cx: &mut Context) {
    let (view, doc) = current_ref!(cx.editor);
    let cursor = doc
        .selection(view.id)
        .primary()
        .cursor(doc.text().slice(..));
    let Some(tc) = table_at_point(doc.text(), cursor) else {
        not_on_table(cx);
        return;
    };
    let doc_id = doc.id();
    TABLE_UNRECOGNIZED.with(|s| s.borrow_mut().remove(&(doc_id, tc.start_line)));
    TABLE_UNRECOGNIZED_CELLS.with(|s| {
        s.borrow_mut()
            .retain(|&(d, l, _, _)| d != doc_id || l != tc.start_line)
    });
    cx.editor.set_status(format!(
        "Recognized table: {} row(s) x {} column(s)",
        tc.table.rows(),
        tc.table.cols()
    ));
}

fn table_recognize_table(cx: &mut Context) {
    table_recognize(cx);
}

/// Emacs `table-recognize-region`: recognize the table spanning the selection.
fn table_recognize_region(cx: &mut Context) {
    let block = {
        let (view, doc) = current_ref!(cx.editor);
        let range = doc.selection(view.id).primary();
        let slice = doc.text().slice(..);
        if range.from() == range.to() {
            None
        } else {
            Some(
                slice
                    .slice(range.from()..range.to())
                    .chars()
                    .collect::<String>(),
            )
        }
    };
    let parsed = block.as_deref().and_then(zmax_core::table::recognize);
    match parsed {
        Some(t) => cx.editor.set_status(format!(
            "Recognized region table: {} row(s) x {} column(s)",
            t.rows(),
            t.cols()
        )),
        None => cx
            .editor
            .set_error("no table grid found in the selected region"),
    }
}

/// Emacs `table-recognize-cell`: report the contents and size of the cell at
/// point within the table at point.
fn table_recognize_cell(cx: &mut Context) {
    match table_cell_at_cursor(cx) {
        Some(tc) => {
            let content = tc.table.get(tc.row, tc.col).unwrap_or("");
            cx.editor.set_status(format!(
                "Cell ({}, {}): {:?} — {}w x {}h",
                tc.row + 1,
                tc.col + 1,
                content,
                tc.table.col_width(tc.col),
                tc.table.row_height(tc.row)
            ));
        }
        None => not_on_table(cx),
    }
}

/// Emacs `table-query-dimension`: report the size of the current cell, the whole
/// table, its grid dimension and total cell count.
fn table_query_dimension(cx: &mut Context) {
    match table_at_cursor(cx) {
        Some(tc) => cx
            .editor
            .set_status(tc.table.query_dimension(tc.row, tc.col)),
        None => not_on_table(cx),
    }
}

thread_local! {
    /// Justification cycle phase for [`table_justify`] (left → center → right → full).
    static TABLE_JUSTIFY_CYCLE: std::cell::Cell<u8> = const { std::cell::Cell::new(0) };
}

/// Emacs `table-justify`: cycle the justification of the current column
/// (left → center → right → full) and re-render. A dense-grid table stores
/// justification only at render time, so only the most-recently-justified
/// column keeps its alignment across re-recognition.
fn table_justify(cx: &mut Context) {
    use zmax_core::table::Justify;
    let Some(mut tc) = table_cell_at_cursor(cx) else {
        not_on_table(cx);
        return;
    };
    let order = [
        Justify::Left,
        Justify::Center,
        Justify::Right,
        Justify::Full,
    ];
    let phase = TABLE_JUSTIFY_CYCLE.with(|p| {
        let v = p.get();
        p.set((v + 1) % order.len() as u8);
        v as usize
    });
    let j = order[phase];
    tc.table.justify_column(tc.col, j);
    replace_table_region(cx, tc.start, tc.end, &tc.table);
    cx.editor
        .set_status(format!("Column {} justified {:?}", tc.col + 1, j));
}

/// Emacs `table-widen-cell`: widen the current column by one character. This is an
/// explicit width change, so `table-fixed-width-mode` does not pin it — the column
/// moves to the new width and its cells re-wrap to it.
fn table_widen_cell(cx: &mut Context) {
    let Some(mut tc) = table_cell_at_cursor(cx) else {
        not_on_table(cx);
        return;
    };
    tc.table.widen_cell(tc.col, 1);
    table_refit_after_resize(cx, &mut tc, 1);
    replace_table_region_raw(cx, tc.start, tc.end, &tc.table);
    cx.editor
        .set_status(format!("Widened column {} by 1", tc.col + 1));
}

/// Emacs `table-narrow-cell`: narrow the current column by one character. In
/// fixed-width mode the cells re-wrap to the narrower column (the row grows
/// taller) rather than holding the column open.
fn table_narrow_cell(cx: &mut Context) {
    let Some(mut tc) = table_cell_at_cursor(cx) else {
        not_on_table(cx);
        return;
    };
    tc.table.narrow_cell(tc.col, 1);
    table_refit_after_resize(cx, &mut tc, -1);
    replace_table_region_raw(cx, tc.start, tc.end, &tc.table);
    cx.editor
        .set_status(format!("Narrowed column {} by 1", tc.col + 1));
}

/// In `table-fixed-width-mode`, re-fit `tc.table` to the buffer's grid widths with
/// the current column moved by `delta` — the width the widen/narrow command just
/// asked for. A no-op when the mode is off.
fn table_refit_after_resize(cx: &Context, tc: &mut TableCtx, delta: i64) {
    let Some(mut widths) = table_fixed_widths(cx, tc.start, tc.end) else {
        return;
    };
    if let Some(w) = widths.get_mut(tc.col) {
        *w = (*w as i64 + delta).max(1) as usize;
    }
    tc.table.fit_to_widths(&widths);
}

/// Emacs `table-heighten-cell`: make the current row one line taller.
fn table_heighten_cell(cx: &mut Context) {
    let Some(mut tc) = table_at_cursor(cx) else {
        not_on_table(cx);
        return;
    };
    tc.table.heighten_cell(tc.row, 1);
    replace_table_region(cx, tc.start, tc.end, &tc.table);
    cx.editor
        .set_status(format!("Heightened row {} by 1", tc.row + 1));
}

/// Emacs `table-shorten-cell`: make the current row one line shorter.
fn table_shorten_cell(cx: &mut Context) {
    let Some(mut tc) = table_at_cursor(cx) else {
        not_on_table(cx);
        return;
    };
    tc.table.shorten_cell(tc.row, 1);
    replace_table_region(cx, tc.start, tc.end, &tc.table);
    cx.editor
        .set_status(format!("Shortened row {} by 1", tc.row + 1));
}

/// Emacs `table-span-cell` (rightward): merge the current cell with its right
/// neighbour. On a dense grid only the text is merged — no true multi-column
/// spanned cell is drawn.
fn table_span_cell(cx: &mut Context) {
    let Some(mut tc) = table_cell_at_cursor(cx) else {
        not_on_table(cx);
        return;
    };
    if tc.col + 1 >= tc.table.cols() {
        cx.editor.set_error("no cell to the right to span into");
        return;
    }
    tc.table.span_cell_right(tc.row, tc.col);
    replace_table_region(cx, tc.start, tc.end, &tc.table);
    cx.editor
        .set_status("Merged cell with the one to its right");
}

/// Emacs `table-split-cell-horizontally`: split the current cell into two
/// columns at the middle of its content. Because the grid is dense the new
/// column is inserted across every row.
fn table_split_cell_horizontally(cx: &mut Context) {
    let Some(mut tc) = table_cell_at_cursor(cx) else {
        not_on_table(cx);
        return;
    };
    let mid = tc.table.get(tc.row, tc.col).unwrap_or("").chars().count() / 2;
    tc.table.split_cell_horizontally(tc.row, tc.col, mid);
    replace_table_region(cx, tc.start, tc.end, &tc.table);
    cx.editor.set_status("Split cell into two columns");
}

/// Emacs `table-split-cell-vertically`: split the current cell into two rows at
/// the middle of its content. The new row is inserted across every column.
fn table_split_cell_vertically(cx: &mut Context) {
    let Some(mut tc) = table_cell_at_cursor(cx) else {
        not_on_table(cx);
        return;
    };
    let mid = tc.table.get(tc.row, tc.col).unwrap_or("").chars().count() / 2;
    tc.table.split_cell_vertically(tc.row, tc.col, mid);
    replace_table_region(cx, tc.start, tc.end, &tc.table);
    cx.editor.set_status("Split cell into two rows");
}

/// Emacs `table-split-cell`: split the current cell (defaults to a vertical
/// split, as `table.el` does when no direction is chosen).
fn table_split_cell(cx: &mut Context) {
    table_split_cell_vertically(cx);
}

/// Emacs `table-insert-sequence`: fill cells, from the one at point to the end
/// of the table, with an incrementing sequence starting at 1.
fn table_insert_sequence(cx: &mut Context) {
    let Some(mut tc) = table_at_cursor(cx) else {
        not_on_table(cx);
        return;
    };
    let total = tc.table.rows() * tc.table.cols();
    let linear = tc.row * tc.table.cols() + tc.col;
    let count = total.saturating_sub(linear);
    tc.table.insert_sequence((tc.row, tc.col), "1", count, 1, 1);
    replace_table_region(cx, tc.start, tc.end, &tc.table);
    cx.editor
        .set_status(format!("Inserted sequence into {count} cell(s)"));
}

/// Emacs `table-generate-source`: emit HTML source for the table at point,
/// inserting it just below the table. (The pure API also produces LaTeX and
/// CALS via `Table::generate_source`.)
fn table_generate_source(cx: &mut Context) {
    use zmax_core::table::SourceLang;
    let Some(tc) = table_at_cursor(cx) else {
        not_on_table(cx);
        return;
    };
    let source = tc.table.generate_source(SourceLang::Html);
    let insert = format!("\n{source}");
    let (view, doc) = current!(cx.editor);
    let tx = Transaction::change(
        doc.text(),
        std::iter::once((tc.end, tc.end, Some(insert.into()))),
    );
    doc.apply(&tx, view.id);
    doc.append_changes_to_history(view);
    cx.editor
        .set_status("Generated HTML source below the table");
}

/// Emacs `table-capture`: turn the selected plain text into a table (rows split
/// on newlines, cells on whitespace) and replace the selection with the grid.
fn table_capture(cx: &mut Context) {
    let region = {
        let (view, doc) = current_ref!(cx.editor);
        let range = doc.selection(view.id).primary();
        if range.from() == range.to() {
            None
        } else {
            let slice = doc.text().slice(..);
            Some((
                range.from(),
                range.to(),
                slice
                    .slice(range.from()..range.to())
                    .chars()
                    .collect::<String>(),
            ))
        }
    };
    let Some((from, to, text)) = region else {
        cx.editor
            .set_error("select the text to capture into a table first");
        return;
    };
    let table = zmax_core::table::capture(&text, None, None);
    let rendered = table.render();
    let (view, doc) = current!(cx.editor);
    let tx = Transaction::change(
        doc.text(),
        std::iter::once((from, to, Some(rendered.into()))),
    );
    doc.apply(&tx, view.id);
    doc.append_changes_to_history(view);
    cx.editor.set_status(format!(
        "Captured {} row(s) x {} column(s) into a table",
        table.rows(),
        table.cols()
    ));
}

/// Emacs `table-release`: convert the table at point back into plain text
/// (space-joined cells, one row per line).
fn table_release(cx: &mut Context) {
    let Some(tc) = table_at_cursor(cx) else {
        not_on_table(cx);
        return;
    };
    let text = tc.table.release();
    let (view, doc) = current!(cx.editor);
    let tx = Transaction::change(
        doc.text(),
        std::iter::once((tc.start, tc.end, Some(text.into()))),
    );
    doc.apply(&tx, view.id);
    doc.append_changes_to_history(view);
    cx.editor
        .set_status("Released the table back to plain text");
}

thread_local! {
    /// `table-fixed-width-mode`: while on, a table re-render pins each column to
    /// the width it already has in the buffer instead of growing it to fit the
    /// content. Read by [`replace_table_region`].
    static TABLE_FIXED_WIDTH: std::cell::Cell<bool> = const { std::cell::Cell::new(false) };
    /// The tables that `table-unrecognize*` has deactivated, keyed by document
    /// and by the table's first line: an unrecognized table is inert text and the
    /// `table-*` at-point commands refuse to touch it until `table-recognize`
    /// takes it back. Read by [`table_at_cursor`].
    static TABLE_UNRECOGNIZED: std::cell::RefCell<HashSet<(DocumentId, usize)>> =
        std::cell::RefCell::new(HashSet::new());
    /// The cells `table-unrecognize-cell` has deactivated, keyed by document,
    /// table start line and `(row, col)`. Read by [`table_cell_active`].
    static TABLE_UNRECOGNIZED_CELLS: std::cell::RefCell<HashSet<(DocumentId, usize, usize, usize)>> =
        std::cell::RefCell::new(HashSet::new());
}

/// Is the table starting at buffer line `line` of `doc` recognized (active)?
fn table_recognized(doc: DocumentId, line: usize) -> bool {
    TABLE_UNRECOGNIZED.with(|s| !s.borrow().contains(&(doc, line)))
}

/// Is cell `(row, col)` of the table starting at `line` recognized (active)?
fn table_cell_active(doc: DocumentId, line: usize, row: usize, col: usize) -> bool {
    TABLE_UNRECOGNIZED_CELLS.with(|s| !s.borrow().contains(&(doc, line, row, col)))
}

/// Emacs `table-fixed-width-mode`: "in the fixed width mode, typing inside a cell
/// never changes the cell width, where in the normal mode the cell width expands
/// automatically in order to prevent a word being folded into multiple lines"
/// (`table.el`).
///
/// zmax's buffer tables are plain text that is re-laid-out by the `table-*`
/// commands, so the mode is read there: with it on, every re-render pins the
/// columns to the widths the grid already has in the buffer and word-wraps a cell
/// that outgrew its column (the row gets taller); with it off, the column widens
/// to fit. Turning it on immediately fits the table at point, so the effect is
/// visible at once.
fn table_fixed_width_mode(cx: &mut Context) {
    let on = TABLE_FIXED_WIDTH.with(|f| {
        let v = !f.get();
        f.set(v);
        v
    });
    let mut fitted = false;
    if on {
        if let Some(tc) = table_at_cursor(cx) {
            replace_table_region(cx, tc.start, tc.end, &tc.table);
            fitted = true;
        }
    }
    cx.editor.set_status(format!(
        "Table fixed-width mode {}{}",
        if on { "enabled" } else { "disabled" },
        if fitted {
            " (table at point fitted)"
        } else {
            ""
        }
    ));
}

/// Emacs `table-unrecognize` (`table-unrecognize-table` when point is in one):
/// deactivate the table at point. Its text stays exactly as it is, but it is no
/// longer a table as far as the `table-*` commands are concerned — they refuse to
/// operate on it until `table-recognize` activates it again.
fn table_unrecognize_table(cx: &mut Context) {
    let Some(tc) = table_at_cursor(cx) else {
        not_on_table(cx);
        return;
    };
    let doc = doc!(cx.editor).id();
    TABLE_UNRECOGNIZED.with(|s| s.borrow_mut().insert((doc, tc.start_line)));
    cx.editor.set_status(format!(
        "Unrecognized table at line {} ({} row(s) x {} column(s))",
        tc.start_line + 1,
        tc.table.rows(),
        tc.table.cols()
    ));
}

/// Emacs `table-unrecognize`: deactivate every table in the buffer.
fn table_unrecognize(cx: &mut Context) {
    let (doc_id, starts) = {
        let doc = doc!(cx.editor);
        (doc.id(), table_start_lines(doc.text(), 0, usize::MAX))
    };
    let n = starts.len();
    TABLE_UNRECOGNIZED.with(|s| {
        let mut s = s.borrow_mut();
        for line in starts {
            s.insert((doc_id, line));
        }
    });
    cx.editor
        .set_status(format!("Unrecognized {n} table(s) in this buffer"));
}

/// Emacs `table-unrecognize-region`: deactivate every table that starts inside
/// the selection.
fn table_unrecognize_region(cx: &mut Context) {
    let (doc_id, starts) = {
        let (view, doc) = current_ref!(cx.editor);
        let text = doc.text();
        let range = doc.selection(view.id).primary();
        let slice = text.slice(..);
        let first = slice.char_to_line(range.from());
        let last = slice.char_to_line(range.to().min(slice.len_chars()));
        (doc.id(), table_start_lines(text, first, last))
    };
    let n = starts.len();
    TABLE_UNRECOGNIZED.with(|s| {
        let mut s = s.borrow_mut();
        for line in starts {
            s.insert((doc_id, line));
        }
    });
    cx.editor
        .set_status(format!("Unrecognized {n} table(s) in the region"));
}

/// Emacs `table-unrecognize-cell`: deactivate just the cell at point. The rest of
/// the table stays live; the cell-scoped commands (justify, widen/narrow, split,
/// span, recognize-cell) refuse to touch this one.
fn table_unrecognize_cell(cx: &mut Context) {
    let Some(tc) = table_at_cursor(cx) else {
        not_on_table(cx);
        return;
    };
    let doc = doc!(cx.editor).id();
    TABLE_UNRECOGNIZED_CELLS.with(|s| s.borrow_mut().insert((doc, tc.start_line, tc.row, tc.col)));
    cx.editor.set_status(format!(
        "Unrecognized cell ({}, {})",
        tc.row + 1,
        tc.col + 1
    ));
}

/// The first line of every ASCII table whose first line falls in the inclusive
/// line range `[first, last]` — a table line being one whose trimmed text starts
/// with `+` or `|`, as in [`table_at_point`].
fn table_start_lines(text: &Rope, first: usize, last: usize) -> Vec<usize> {
    let slice = text.slice(..);
    let n = slice.len_lines();
    let is_tbl = |line: usize| -> bool {
        line < n && {
            let s: String = slice.line(line).chars().collect();
            let t = s.trim_start();
            t.starts_with('+') || t.starts_with('|')
        }
    };
    let mut out = Vec::new();
    let mut line = 0;
    while line < n {
        if is_tbl(line) {
            let start = line;
            while line < n && is_tbl(line) {
                line += 1;
            }
            if start >= first && start <= last {
                out.push(start);
            }
        } else {
            line += 1;
        }
    }
    out
}

/// Emacs `list-faces-display` / `facemenu`: browse faces and colors.
fn facemenu(cx: &mut Context) {
    open_overlay(cx, |_editor| {
        Ok(Box::new(crate::ui::facemenu::FaceMenu::new()) as Box<dyn Component>)
    });
}

// --- facemenu: face text properties on the region (emacs M-o) ---
//
// Emacs' face menu puts a `face` text property on the region; the property lives
// on the characters, survives editing, is what `enriched-mode` writes to disk,
// and is read by redisplay. zmax stores it on the `Document`
// (`Document::text_props`) and renders it in
// `ui::editor::EditorView::doc_text_prop_highlights`. Text properties are not
// part of the undo history (they are not text), so `u` will not take a face back
// off — `facemenu-remove-all` is how you undo one, as in Emacs.

/// The non-empty selection ranges the face commands operate on — Emacs' "the
/// region", generalised to every zmax selection.
fn region_char_ranges(editor: &Editor) -> Vec<std::ops::Range<usize>> {
    let (view, doc) = current_ref!(editor);
    doc.selection(view.id)
        .iter()
        .filter(|r| r.from() < r.to())
        .map(|r| r.from()..r.to())
        .collect()
}

/// Apply `face` to the region as a face text property (Emacs
/// `facemenu-add-face`). Reports the character count, or an error when there is
/// no region — every `facemenu-set-*` command lands here, and so does the
/// interactive face/colour picker.
pub(crate) fn facemenu_add_face(
    editor: &mut Editor,
    face: &zmax_core::text_props::Face,
    label: &str,
) {
    let ranges = region_char_ranges(editor);
    if ranges.is_empty() {
        editor.set_error(format!("{label}: the region is empty"));
        return;
    }
    let chars: usize = ranges.iter().map(|r| r.end - r.start).sum();
    let doc = doc_mut!(editor);
    doc.update_text_props(|props| {
        for range in &ranges {
            props.add_face(range.clone(), face);
        }
    });
    editor.set_status(format!("{label}: {chars} chars"));
}

/// Drop text properties from the region. `face_only` is Emacs
/// `facemenu-remove-face-props` (the `face` property and nothing else); the full
/// form is `facemenu-remove-all` (every property, so hidden text reappears too).
fn facemenu_remove(cx: &mut Context, face_only: bool) {
    let label = if face_only {
        "facemenu-remove-face-props"
    } else {
        "facemenu-remove-all"
    };
    let ranges = region_char_ranges(cx.editor);
    if ranges.is_empty() {
        cx.editor.set_error(format!("{label}: the region is empty"));
        return;
    }
    let chars: usize = ranges.iter().map(|r| r.end - r.start).sum();
    let doc = doc_mut!(cx.editor);
    doc.update_text_props(|props| {
        for range in &ranges {
            if face_only {
                props.remove_face(range.clone());
            } else {
                props.remove_all(range.clone());
            }
        }
    });
    cx.editor.set_status(format!("{label}: {chars} chars"));
}

/// Emacs `facemenu-set-bold` (M-o b).
fn facemenu_set_bold(cx: &mut Context) {
    facemenu_add_face(
        cx.editor,
        &zmax_core::text_props::Face::bold(),
        "facemenu-set-bold",
    );
}

/// Emacs `facemenu-set-italic` (M-o i).
fn facemenu_set_italic(cx: &mut Context) {
    facemenu_add_face(
        cx.editor,
        &zmax_core::text_props::Face::italic(),
        "facemenu-set-italic",
    );
}

/// Emacs `facemenu-set-bold-italic` (M-o l).
fn facemenu_set_bold_italic(cx: &mut Context) {
    facemenu_add_face(
        cx.editor,
        &zmax_core::text_props::Face::bold_italic(),
        "facemenu-set-bold-italic",
    );
}

/// Emacs `facemenu-set-underline` (M-o u).
fn facemenu_set_underline(cx: &mut Context) {
    facemenu_add_face(
        cx.editor,
        &zmax_core::text_props::Face::underline(),
        "facemenu-set-underline",
    );
}

/// Emacs `facemenu-set-default` (M-o d): put the *default* face on the region,
/// which is the same as taking every face attribute off it.
fn facemenu_set_default(cx: &mut Context) {
    facemenu_add_face(
        cx.editor,
        &zmax_core::text_props::Face::default(),
        "facemenu-set-default",
    );
}

/// Emacs `facemenu-set-face` (M-o o): pick a face from `list-faces-display` and
/// put it on the region.
fn facemenu_set_face(cx: &mut Context) {
    open_overlay(cx, |_editor| {
        Ok(Box::new(crate::ui::facemenu::FaceMenu::picker(
            crate::ui::facemenu::Target::Face,
        )) as Box<dyn Component>)
    });
}

/// Emacs `facemenu-set-foreground`: pick a colour and make it the region's
/// foreground.
fn facemenu_set_foreground(cx: &mut Context) {
    open_overlay(cx, |_editor| {
        Ok(Box::new(crate::ui::facemenu::FaceMenu::picker(
            crate::ui::facemenu::Target::Foreground,
        )) as Box<dyn Component>)
    });
}

/// Emacs `facemenu-set-background`: pick a colour and make it the region's
/// background.
fn facemenu_set_background(cx: &mut Context) {
    open_overlay(cx, |_editor| {
        Ok(Box::new(crate::ui::facemenu::FaceMenu::picker(
            crate::ui::facemenu::Target::Background,
        )) as Box<dyn Component>)
    });
}

/// Emacs `facemenu-remove-face-props`: remove only the `face` property from the
/// region. Text hidden by an `invisible` property stays hidden.
fn facemenu_remove_face_props(cx: &mut Context) {
    facemenu_remove(cx, true);
}

/// Emacs `facemenu-remove-all`: remove *every* text property from the region —
/// faces and `invisible` alike, so text hidden by `hide-ifdef-mode` or
/// `sgml-tags-invisible` comes back.
fn facemenu_remove_all(cx: &mut Context) {
    facemenu_remove(cx, false);
}

// --- text properties driven by a buffer scan (hide-ifdef, cpp-highlight, sgml) ---

/// The buffer's lines, borrowed for a `zmax_core::cmode` scan.
fn buffer_lines(doc: &Document) -> Vec<String> {
    doc.text()
        .lines()
        .map(|l| l.to_string().trim_end_matches('\n').to_string())
        .collect()
}

/// Char offset of the start of each line, for turning a line range into a char
/// range.
fn line_char_starts(doc: &Document) -> Vec<usize> {
    let text = doc.text();
    (0..text.len_lines())
        .map(|l| text.line_to_char(l))
        .collect()
}

/// Emacs `hide-ifdef-mode` (C-c @): hide the code the C preprocessor will skip.
///
/// Turning it on hides the body of every conditional branch that provably is not
/// compiled — `#if 0`, the `#else` of an `#if 1`, an `#ifdef` of a macro the file
/// never defines — as an `invisible` text property, so the lines disappear from
/// the display without touching the text. Turning it off reveals them.
///
/// Divergence, stated plainly: GNU Emacs evaluates the conditions against
/// `hide-ifdef-env`, which `hide-ifdef-define` populates, and hides every branch
/// that is not *true* — so with the default empty env it hides the body of every
/// `#ifdef`. zmax has no `hide-ifdef-define`, so it evaluates against the
/// file's own `#define`s and leaves a branch it cannot decide visible
/// (`zmax_core::cmode::dead_branches`); hiding on "cannot tell" with no way to
/// define a macro would blank out most of a real source file.
fn hide_ifdef_mode(cx: &mut Context) {
    let doc = doc_mut!(cx.editor);
    if doc.text_props().has_invisible() {
        doc.update_text_props(|props| props.clear_invisible());
        cx.editor.set_status("hide-ifdef-mode disabled");
        return;
    }
    let lines = buffer_lines(doc);
    let refs: Vec<&str> = lines.iter().map(String::as_str).collect();
    let dead = zmax_core::cmode::dead_branches(&refs);
    if dead.is_empty() {
        cx.editor
            .set_status("hide-ifdef-mode: no dead preprocessor branches");
        return;
    }
    let starts = line_char_starts(doc);
    let hidden: usize = dead.iter().map(|r| r.end - r.start).sum();
    doc.update_text_props(|props| {
        for range in &dead {
            let from = starts[range.start.min(starts.len() - 1)];
            let to = starts
                .get(range.end)
                .copied()
                .unwrap_or_else(|| starts[starts.len() - 1]);
            props.set_invisible(from..to, true);
        }
    });
    cx.editor
        .set_status(format!("hide-ifdef-mode: {hidden} line(s) hidden"));
}

/// Emacs `cpp-highlight-buffer`: show which preprocessor conditionals are live
/// and which are compiled out.
///
/// Shades the body of every provably-dead branch with the `shadow` face as a face
/// text property, so the code that will not compile is visibly dimmed and stays
/// dimmed while you edit around it. Running it again clears the shading.
///
/// Divergence: Emacs prompts for a face per distinct condition (its "cpp edit"
/// buffer); this shades all dead branches with one face and does not offer the
/// per-condition colour prompt.
fn cpp_highlight_buffer(cx: &mut Context) {
    let doc = doc_mut!(cx.editor);
    let lines = buffer_lines(doc);
    let refs: Vec<&str> = lines.iter().map(String::as_str).collect();
    let dead = zmax_core::cmode::dead_branches(&refs);
    if dead.is_empty() {
        cx.editor
            .set_status("cpp-highlight-buffer: no dead preprocessor branches");
        return;
    }
    let starts = line_char_starts(doc);
    let shadow = zmax_core::text_props::Face::named("shadow");
    // Toggle: a second run takes the shading back off.
    let first = starts[dead[0].start.min(starts.len() - 1)];
    let shaded = doc
        .text_props()
        .props_at(first)
        .is_some_and(|p| p.face == shadow);
    doc.update_text_props(|props| {
        for range in &dead {
            let from = starts[range.start.min(starts.len() - 1)];
            let to = starts
                .get(range.end)
                .copied()
                .unwrap_or_else(|| starts[starts.len() - 1]);
            if shaded {
                props.remove_face(from..to);
            } else {
                props.add_face(from..to, &shadow);
            }
        }
    });
    cx.editor.set_status(if shaded {
        format!("cpp-highlight-buffer: cleared {} region(s)", dead.len())
    } else {
        format!("cpp-highlight-buffer: {} dead region(s)", dead.len())
    });
}

/// Emacs `sgml-tags-invisible` (C-c C-t in HTML/SGML mode): hide the markup tags
/// and show only the text they mark up. Running it again brings the tags back.
///
/// The tags are hidden with an `invisible` text property, so the text is
/// untouched — the file on disk still has its markup, and editing inside the
/// visible text works normally.
fn sgml_tags_invisible(cx: &mut Context) {
    let doc = doc_mut!(cx.editor);
    if doc.text_props().has_invisible() {
        doc.update_text_props(|props| props.clear_invisible());
        cx.editor.set_status("sgml-tags-invisible: tags shown");
        return;
    }
    let text: String = doc.text().slice(..).chars().collect();
    let tags = zmax_core::sgml::parse_tags(&text);
    if tags.is_empty() {
        cx.editor
            .set_error("sgml-tags-invisible: no tags in buffer");
        return;
    }
    let count = tags.len();
    doc.update_text_props(|props| {
        for tag in &tags {
            props.set_invisible(tag.start..tag.end, true);
        }
    });
    cx.editor
        .set_status(format!("sgml-tags-invisible: {count} tag(s) hidden"));
}

// --- cwarn-mode: suspicious C constructs ---

/// The documents `cwarn-mode` is on for, plus the global flag
/// `global-cwarn-mode` sets. Read every frame by
/// `ui::editor::EditorView::doc_cwarn_highlights`, which is what actually paints
/// the warnings.
fn cwarn_docs() -> &'static std::sync::Mutex<std::collections::HashSet<DocumentId>> {
    static DOCS: std::sync::OnceLock<std::sync::Mutex<std::collections::HashSet<DocumentId>>> =
        std::sync::OnceLock::new();
    DOCS.get_or_init(Default::default)
}

fn cwarn_global_flag() -> &'static std::sync::atomic::AtomicBool {
    static F: std::sync::atomic::AtomicBool = std::sync::atomic::AtomicBool::new(false);
    &F
}

/// Whether `cwarn-mode` paints warnings in this document — either it was turned
/// on for the buffer, or `global-cwarn-mode` turned it on everywhere.
pub(crate) fn cwarn_enabled(doc: DocumentId) -> bool {
    cwarn_global_flag().load(std::sync::atomic::Ordering::Relaxed)
        || cwarn_docs()
            .lock()
            .map(|d| d.contains(&doc))
            .unwrap_or(false)
}

/// Emacs `cwarn-mode`: highlight C constructs that are legal but almost always a
/// mistake — an assignment where a comparison was meant (`if (a = b)`) and a
/// semicolon that silently empties the body (`if (x);`).
///
/// The scan is `zmax_core::cmode::cwarn_scan`; the highlight is painted from
/// the viewport every frame, like Hi-Lock, so it tracks the buffer as you type.
fn cwarn_mode(cx: &mut Context) {
    let id = doc!(cx.editor).id();
    let Ok(mut docs) = cwarn_docs().lock() else {
        cx.editor.set_error("cwarn-mode: state is poisoned");
        return;
    };
    if docs.remove(&id) {
        drop(docs);
        cx.editor.set_status("cwarn-mode disabled");
        return;
    }
    docs.insert(id);
    drop(docs);
    let lines = buffer_lines(doc!(cx.editor));
    let refs: Vec<&str> = lines.iter().map(String::as_str).collect();
    let found = zmax_core::cmode::cwarn_scan(&refs).len();
    cx.editor
        .set_status(format!("cwarn-mode enabled ({found} warning(s))"));
}

/// Emacs `global-cwarn-mode`: turn `cwarn-mode` on in every buffer.
fn global_cwarn_mode(cx: &mut Context) {
    let flag = cwarn_global_flag();
    let on = !flag.load(std::sync::atomic::Ordering::Relaxed);
    flag.store(on, std::sync::atomic::Ordering::Relaxed);
    cx.editor.set_status(if on {
        "global-cwarn-mode enabled"
    } else {
        "global-cwarn-mode disabled"
    });
}

// --- goto-address-mode: buttonize the URLs and e-mails in the buffer ---

/// The documents `goto-address-mode` is on for. Read every frame by
/// `ui::editor::EditorView::doc_goto_address_highlights`.
fn goto_address_docs() -> &'static std::sync::Mutex<std::collections::HashSet<DocumentId>> {
    static DOCS: std::sync::OnceLock<std::sync::Mutex<std::collections::HashSet<DocumentId>>> =
        std::sync::OnceLock::new();
    DOCS.get_or_init(Default::default)
}

/// Whether `goto-address-mode` is highlighting addresses in this document.
pub(crate) fn goto_address_enabled(doc: DocumentId) -> bool {
    goto_address_docs()
        .lock()
        .map(|d| d.contains(&doc))
        .unwrap_or(false)
}

/// Emacs `goto-address-mode`: highlight the URLs and e-mail addresses in the
/// buffer so they stand out as the links they are. `:open-url` (Emacs
/// `goto-address-at-point`) follows the one under the cursor.
///
/// The scan is `zmax_core::goto_address::addresses`, run over the visible lines
/// each frame, so it costs nothing on a large file and tracks edits immediately.
fn goto_address_mode(cx: &mut Context) {
    let id = doc!(cx.editor).id();
    let Ok(mut docs) = goto_address_docs().lock() else {
        cx.editor.set_error("goto-address-mode: state is poisoned");
        return;
    };
    if docs.remove(&id) {
        drop(docs);
        cx.editor.set_status("goto-address-mode disabled");
        return;
    }
    docs.insert(id);
    drop(docs);
    let doc = doc!(cx.editor);
    let found: usize = doc
        .text()
        .lines()
        .map(|line| zmax_core::goto_address::addresses(&line.to_string()).len())
        .sum();
    cx.editor.set_status(format!(
        "goto-address-mode enabled ({found} address(es); :open-url follows one)"
    ));
}

// --- transient-mark-mode ---

fn transient_mark_flag() -> &'static std::sync::atomic::AtomicBool {
    // On by default, as in Emacs 23 and later.
    static F: std::sync::atomic::AtomicBool = std::sync::atomic::AtomicBool::new(true);
    &F
}

/// Whether the region is highlighted. Read by
/// `ui::editor::EditorView::doc_selection_highlights` every frame.
pub(crate) fn transient_mark_enabled() -> bool {
    transient_mark_flag().load(std::sync::atomic::Ordering::Relaxed)
}

/// Emacs `transient-mark-mode`: whether the region between point and mark is
/// *highlighted*.
///
/// Turning it off does not remove the region — the selection is still there and
/// every region command still acts on it — it stops being shaded, which is
/// exactly the pre-23 Emacs behaviour the command restores. The cursor stays
/// drawn.
fn transient_mark_mode(cx: &mut Context) {
    let flag = transient_mark_flag();
    let on = !flag.load(std::sync::atomic::Ordering::Relaxed);
    flag.store(on, std::sync::atomic::Ordering::Relaxed);
    cx.editor.set_status(if on {
        "transient-mark-mode enabled (the region is highlighted)"
    } else {
        "transient-mark-mode disabled (the region still acts, but is not shaded)"
    });
}

// --- prettify-symbols-mode / glyphless-display-mode ---

/// Emacs `prettify-symbols-mode`: draw `->` as `→`, `<=` as `≤`, `lambda` as `λ`.
///
/// The buffer text does not change — point still walks every character and the
/// file on disk is byte-identical — only the glyphs drawn for them do, which is
/// what Emacs' `display` property does. The symbol table is per-language
/// (`zmax_core::prettify::symbols_for`); a language with no table is a no-op,
/// as it is in Emacs.
fn prettify_symbols_mode(cx: &mut Context) {
    let doc = doc_mut!(cx.editor);
    let on = !doc.prettify_symbols();
    let language = doc.language_name().map(str::to_string);
    if on
        && language
            .as_deref()
            .and_then(zmax_core::prettify::symbols_for)
            .is_none()
    {
        let what = language.unwrap_or_else(|| "this buffer".into());
        cx.editor
            .set_error(format!("prettify-symbols-mode: no symbol table for {what}"));
        return;
    }
    let count = doc.set_prettify_symbols(on);
    cx.editor.set_status(if on {
        format!("prettify-symbols-mode enabled ({count} symbol(s))")
    } else {
        "prettify-symbols-mode disabled".to_string()
    });
}

/// Emacs `glyphless-display-mode`: draw the characters a terminal shows as
/// nothing — control characters, C1 controls, zero-width spaces, bidi overrides —
/// as a visible glyph, so text that is hiding something stops hiding it.
fn glyphless_display_mode(cx: &mut Context) {
    let doc = doc_mut!(cx.editor);
    let on = !doc.glyphless_display();
    let count = doc.set_glyphless_display(on);
    cx.editor.set_status(if on {
        format!("glyphless-display-mode enabled ({count} glyphless char(s))")
    } else {
        "glyphless-display-mode disabled".to_string()
    });
}

