fn select_all_impl<F>(editor: &mut Editor, select_fn: F)
where
    F: Fn(&Syntax, RopeSlice, Selection) -> Selection,
{
    let (view, doc) = current!(editor);

    if let Some(syntax) = doc.syntax() {
        let text = doc.text().slice(..);
        let current_selection = doc.selection(view.id);
        let selection = select_fn(syntax, text, current_selection.clone());
        doc.set_selection(view.id, selection);
    }
}

fn select_all_siblings(cx: &mut Context) {
    let motion = |editor: &mut Editor| {
        select_all_impl(editor, object::select_all_siblings);
    };

    cx.editor.apply_motion(motion);
}

fn select_all_children(cx: &mut Context) {
    let motion = |editor: &mut Editor| {
        select_all_impl(editor, object::select_all_children);
    };

    cx.editor.apply_motion(motion);
}

// vim `%`: with no count, match the bracket under the cursor; with a count,
// `{count}%` jumps to {count} percent through the file, on the first non-blank.
fn match_brackets_or_goto_percent(cx: &mut Context) {
    let Some(count) = cx.count else {
        // vim `%` (match the bracket under the cursor) is itself a jump command.
        // The operator form `d%`/`y%` uses `match_brackets` directly, so recording
        // the jump here keeps standalone `%` correct without affecting operators.
        {
            let (view, doc) = current!(cx.editor);
            push_jump(view, doc);
        }
        match_brackets(cx);
        return;
    };
    let is_select = cx.editor.mode == Mode::Select;
    {
        let (view, doc) = current!(cx.editor);
        push_jump(view, doc);
        let text = doc.text().slice(..);
        // Effective line count excludes a phantom trailing empty line so the
        // percentage matches vim's "number-of-lines".
        let lines = if text.line(text.len_lines() - 1).len_chars() == 0 {
            text.len_lines().saturating_sub(1)
        } else {
            text.len_lines()
        };
        // vim formula: ({count} * number-of-lines + 99) / 100
        let line = (count.get().saturating_mul(lines).saturating_add(99) / 100)
            .saturating_sub(1)
            .min(lines.saturating_sub(1));
        let pos = text.line_to_char(line);
        let selection = doc
            .selection(view.id)
            .clone()
            .transform(|range| range.put_cursor(text, pos, is_select));
        doc.set_selection(view.id, selection);
    }
    goto_first_nonwhitespace(cx);
}

/// vim `matchpairs`: find the partner of a user-defined pair char (e.g. `<:>`)
/// under the cursor via a nesting scan. Returns None for chars not in the option
/// (the built-in bracket matcher handles the standard pairs).
fn matchpairs_match(text: RopeSlice, pos: usize) -> Option<usize> {
    let spec = typed::vim_opt_str("matchpairs")?;
    let ch = text.get_char(pos)?;
    for pair in spec.split(',') {
        let mut it = pair.chars();
        let (open, colon, close) = (it.next()?, it.next()?, it.next()?);
        if colon != ':' || open == close {
            continue;
        }
        let len = text.len_chars();
        if ch == open {
            let (mut depth, mut i) = (0i32, pos);
            while i + 1 < len {
                i += 1;
                let c = text.char(i);
                if c == open {
                    depth += 1;
                } else if c == close {
                    if depth == 0 {
                        return Some(i);
                    }
                    depth -= 1;
                }
            }
        } else if ch == close {
            let (mut depth, mut i) = (0i32, pos);
            while i > 0 {
                i -= 1;
                let c = text.char(i);
                if c == close {
                    depth += 1;
                } else if c == open {
                    if depth == 0 {
                        return Some(i);
                    }
                    depth -= 1;
                }
            }
        }
    }
    None
}

fn match_brackets(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    let is_select = cx.editor.mode == Mode::Select;
    let text = doc.text();
    let text_slice = text.slice(..);

    let selection = doc.selection(view.id).clone().transform(|range| {
        let pos = range.cursor(text_slice);
        let matched = doc
            .syntax()
            .map_or_else(
                || match_brackets::find_matching_bracket_plaintext(text.slice(..), pos),
                |syntax| match_brackets::find_matching_bracket_fuzzy(syntax, text.slice(..), pos),
            )
            .or_else(|| matchpairs_match(text_slice, pos));
        if let Some(matched_pos) = matched {
            range.put_cursor(text_slice, matched_pos, is_select)
        } else {
            range
        }
    });

    doc.set_selection(view.id, selection);
    // vim 'foldopen' contains `percent`: `%` onto a bracket inside a closed fold
    // opens it.
    foldopen_at(view, doc, "percent");
}

