/// vim 'formatlistpat' (default `^\s*\d\+[\]:.)}\t ]\s*`): the visual width of the
/// list marker starting `text`, or `None` when 'formatoptions' does not contain
/// `n` or the text is not a list item. The width is what the continuation lines
/// of a reflowed item are indented by.
fn list_item_hang(text: &str) -> Option<usize> {
    if !formatoptions_contains('n') {
        return None;
    }
    let pat =
        typed::vim_opt_str("formatlistpat").unwrap_or_else(|| r"^\s*\d+[\]:.)}\t ]\s*".to_string());
    // vim patterns spell the count as `\d\+`; the Rust regex engine wants `\d+`.
    let pat = pat.replace(r"\+", "+").replace(r"\|", "|");
    let re = Regex::new(&pat).ok()?;
    let first = text.lines().next()?;
    let m = re.find(first)?;
    (m.start() == 0).then(|| first[..m.end()].chars().count())
}

/// Filter the selection through the external program `prg` (vim 'formatprg' /
/// 'equalprg'), replacing it with what the program writes to stdout.
fn filter_selection_through(cx: &mut Context, prg: &str, option: &str) {
    let (from, to, input) = {
        let (view, doc) = current_ref!(cx.editor);
        let r = doc.selection(view.id).primary();
        let text = doc.text();
        // vim filters whole lines.
        let first = text.char_to_line(r.from());
        let last = text.char_to_line(r.to().saturating_sub(1).max(r.from()));
        let from = text.line_to_char(first);
        let to = text
            .line_to_char((last + 1).min(text.len_lines()))
            .min(text.len_chars());
        (from, to, text.slice(from..to).to_string())
    };
    let mut parts = prg.split_whitespace();
    let Some(cmd) = parts.next() else {
        cx.editor.set_error(format!("E518: empty '{option}'"));
        return;
    };
    let out = std::process::Command::new(cmd)
        .args(parts)
        .stdin(std::process::Stdio::piped())
        .stdout(std::process::Stdio::piped())
        .stderr(std::process::Stdio::null())
        .spawn()
        .and_then(|mut child| {
            use std::io::Write;
            if let Some(mut stdin) = child.stdin.take() {
                stdin.write_all(input.as_bytes())?;
            }
            child.wait_with_output()
        });
    let out = match out {
        Ok(o) if o.status.success() => String::from_utf8_lossy(&o.stdout).into_owned(),
        Ok(o) => {
            cx.editor
                .set_error(format!("'{option}': {cmd} exited with {}", o.status));
            return;
        }
        Err(e) => {
            cx.editor.set_error(format!("'{option}': {cmd}: {e}"));
            return;
        }
    };
    let (view, doc) = current!(cx.editor);
    let tx = Transaction::change(
        doc.text(),
        [(from, to, Some(out.as_str().into()))].into_iter(),
    );
    doc.apply(&tx, view.id);
    doc.append_changes_to_history(view);
    cx.editor
        .set_status(format!("filtered through '{option}' ({cmd})"));
}

/// vim 'foldopen': the events that automatically open the closed fold you land
/// in. `item` is the event's name (`search`, `quickfix`, `undo`, `percent`,
/// `jump`, …); the default list holds all of them but `insert`.
fn foldopen_at(view: &mut View, doc: &mut Document, item: &str) {
    const DEFAULT: &str = "block,hor,mark,percent,quickfix,search,tag,undo";
    let spec = typed::vim_opt_str("foldopen").unwrap_or_else(|| DEFAULT.to_string());
    if !spec
        .split(',')
        .map(str::trim)
        .any(|w| w == "all" || w == item)
    {
        return;
    }
    let line = doc
        .selection(view.id)
        .primary()
        .cursor_line(doc.text().slice(..));
    if doc.folds_mut().open_recursive(line) {
        fold_snap_cursor(view, doc);
    }
}

/// The files the current buffer includes, per vim's 'include' pattern. Each
/// include line's quoted/angled filename is resolved against the buffer's own
/// directory. With 'include' unset there are no included files, as in vim.
fn included_files(editor: &Editor) -> Vec<std::path::PathBuf> {
    let Some(pat) = typed::vim_opt_str("include").filter(|p| !p.trim().is_empty()) else {
        return Vec::new();
    };
    let Ok(re) = Regex::new(&pat) else {
        return Vec::new();
    };
    let (_view, doc) = current_ref!(editor);
    let Some(dir) = doc.path().and_then(|p| p.parent()).map(Path::to_path_buf) else {
        return Vec::new();
    };
    let text = doc.text().to_string();
    let mut out = Vec::new();
    for line in text.lines() {
        if re.find(line).is_none_or(|m| m.start() != 0) {
            continue;
        }
        // `#include "foo.h"` / `#include <foo.h>` / `require 'foo'`.
        let name = line
            .split_once('"')
            .and_then(|(_, rest)| rest.split_once('"'))
            .or_else(|| line.split_once('<').and_then(|(_, r)| r.split_once('>')))
            .or_else(|| line.split_once('\'').and_then(|(_, r)| r.split_once('\'')))
            .map(|(name, _)| name.to_string())
            .or_else(|| line.split_whitespace().last().map(str::to_string));
        let Some(name) = name.filter(|n| !n.is_empty()) else {
            continue;
        };
        let path = dir.join(&name);
        if path.is_file() && !out.contains(&path) {
            out.push(path);
        }
    }
    out
}

/// vim `i_CTRL-N` / `i_CTRL-P`: complete the keyword before the cursor from the
/// sources listed in 'complete' (default `.,w,b,u,t`):
///
/// | item | source |
/// |------|--------|
/// | `.`  | the current buffer |
/// | `w` `b` `u` | the other open buffers |
/// | `k`  | the files in 'dictionary' |
/// | `s`  | the files in 'thesaurus' |
/// | `i`  | the files this buffer includes ('include') |
/// | `d`  | the names this buffer `#define`s ('define') |
/// | `t` `]` | the visited tags table |
fn complete_keyword(cx: &mut Context) {
    let (start, prefix) = keyword_before_cursor(cx.editor);
    if prefix.is_empty() {
        return;
    }
    let spec = typed::vim_opt_str("complete").unwrap_or_else(|| ".,w,b,u,t".to_string());
    let items: Vec<String> = spec
        .split(',')
        .map(|s| s.trim().to_string())
        .filter(|s| !s.is_empty())
        .collect();
    let has = |item: &str| items.iter().any(|i| i == item);

    let mut words: HashSet<String> = HashSet::new();
    let add_text = |text: &str, words: &mut HashSet<String>| {
        for word in text.split(|c: char| !char_is_word(c)) {
            if word.len() > prefix.len() && word.starts_with(&prefix) {
                words.insert(word.to_string());
            }
        }
    };

    let current_id = doc!(cx.editor).id();
    if has(".") {
        let text = doc!(cx.editor).text().to_string();
        add_text(&text, &mut words);
    }
    if has("w") || has("b") || has("u") || has("U") {
        let others: Vec<String> = cx
            .editor
            .documents()
            .filter(|d| d.id() != current_id)
            .map(|d| d.text().to_string())
            .collect();
        for text in others {
            add_text(&text, &mut words);
        }
    }
    if has("k") {
        for text in option_word_files("dictionary") {
            add_text(&text, &mut words);
        }
    }
    if has("s") {
        for text in option_word_files("thesaurus") {
            add_text(&text, &mut words);
        }
    }
    if has("i") {
        for path in included_files(cx.editor) {
            if let Ok(text) = std::fs::read_to_string(path) {
                add_text(&text, &mut words);
            }
        }
    }
    if has("d") {
        let define = typed::vim_opt_str("define").unwrap_or_else(|| r"^\s*#\s*define".to_string());
        if let Ok(re) = Regex::new(&format!(r"(?:{define})\s+([A-Za-z_]\w*)")) {
            let text = doc!(cx.editor).text().to_string();
            for caps in text.lines().filter_map(|l| re.captures(l)) {
                if let Some(name) = caps.get(1).map(|m| m.as_str()) {
                    if name.len() > prefix.len() && name.starts_with(&prefix) {
                        words.insert(name.to_string());
                    }
                }
            }
        }
    }
    if has("t") || has("]") {
        if let Some((_, table)) = tags_table().read().unwrap().as_ref() {
            for name in zmax_core::etags::complete(table, &prefix) {
                if name.len() > prefix.len() {
                    words.insert(name);
                }
            }
        }
    }
    complete_from(cx, start, sorted(words.into_iter().collect()), "keyword");
}

/// The longest prefix every candidate shares — what 'completeopt' `longest`
/// inserts instead of a whole candidate.
fn longest_common_prefix(candidates: &[String]) -> String {
    let Some(first) = candidates.first() else {
        return String::new();
    };
    let mut len = first.chars().count();
    for c in &candidates[1..] {
        len = len.min(
            first
                .chars()
                .zip(c.chars())
                .take_while(|(a, b)| a == b)
                .count(),
        );
    }
    first.chars().take(len).collect()
}

// ===========================================================================
// Emacs minor modes whose state the renderer / insert path actually reads.
//
// Every flag below has exactly one reader, named in its doc comment. A toggle
// with no reader is a lie, so none are added here without wiring one.
// ===========================================================================

/// `show-paren-mode` (global) — read by `EditorView::highlight_focused_view_elements`.
/// On by default, as in Emacs since 25.1.
fn show_paren_global() -> &'static std::sync::atomic::AtomicBool {
    static F: std::sync::atomic::AtomicBool = std::sync::atomic::AtomicBool::new(true);
    &F
}

/// Buffers where `show-paren-local-mode` has overridden the global setting.
fn show_paren_local() -> &'static std::sync::RwLock<HashMap<DocumentId, bool>> {
    static F: std::sync::OnceLock<std::sync::RwLock<HashMap<DocumentId, bool>>> =
        std::sync::OnceLock::new();
    F.get_or_init(Default::default)
}

/// Whether the matching-paren overlay should be drawn in `doc`: the buffer's
/// `show-paren-local-mode` setting if it has one, else the global one.
pub(crate) fn show_paren_enabled(doc: DocumentId) -> bool {
    if let Some(&local) = show_paren_local().read().unwrap().get(&doc) {
        return local;
    }
    show_paren_global().load(std::sync::atomic::Ordering::Relaxed)
}

/// Emacs `show-paren-mode`: toggle highlighting of the parenthesis matching the
/// one at point, in every buffer.
fn show_paren_mode(cx: &mut Context) {
    let f = show_paren_global();
    let on = !f.load(std::sync::atomic::Ordering::Relaxed);
    f.store(on, std::sync::atomic::Ordering::Relaxed);
    cx.editor.set_status(if on {
        "Show-Paren mode enabled"
    } else {
        "Show-Paren mode disabled"
    });
}

/// Emacs `show-paren-local-mode`: toggle paren highlighting in this buffer only,
/// overriding `show-paren-mode` for it.
fn show_paren_local_mode(cx: &mut Context) {
    let id = doc!(cx.editor).id();
    let on = !show_paren_enabled(id);
    show_paren_local().write().unwrap().insert(id, on);
    cx.editor.set_status(if on {
        "Show-Paren mode enabled in this buffer"
    } else {
        "Show-Paren mode disabled in this buffer"
    });
}

/// `hi-lock-mode` — read by `EditorView::doc_hilock_highlights`. On by default so
/// `highlight-regexp` paints without an extra step; turning it off hides every
/// hi-lock overlay while keeping the pattern list intact.
fn hi_lock_enabled_flag() -> &'static std::sync::atomic::AtomicBool {
    static F: std::sync::atomic::AtomicBool = std::sync::atomic::AtomicBool::new(true);
    &F
}

/// Whether hi-lock overlays are drawn (read by the renderer).
pub(crate) fn hi_lock_enabled() -> bool {
    hi_lock_enabled_flag().load(std::sync::atomic::Ordering::Relaxed)
}

/// Emacs `hi-lock-mode`: toggle display of the interactive `highlight-regexp`
/// patterns. The patterns survive being switched off — `hi-lock-mode` again
/// brings them all back.
fn hi_lock_mode(cx: &mut Context) {
    let f = hi_lock_enabled_flag();
    let on = !f.load(std::sync::atomic::Ordering::Relaxed);
    f.store(on, std::sync::atomic::Ordering::Relaxed);
    let n = crate::hi_lock::sources().len();
    cx.editor.set_status(if on {
        format!("Hi-Lock mode enabled ({n} pattern(s) shown)")
    } else {
        format!("Hi-Lock mode disabled ({n} pattern(s) kept, not shown)")
    });
}

/// The electric / delete-selection insert-time modes, all read by
/// `insert::insert_char` or `insert::insert_newline`.
#[derive(Clone, Copy, PartialEq, Eq)]
pub(crate) enum InsertMode {
    /// `delete-selection-mode`: self-inserting replaces the active region.
    DeleteSelection,
    /// `electric-indent-mode`: a newline re-indents the line it opens (on by
    /// default, as in Emacs 24.4+).
    ElectricIndent,
    /// `electric-quote-mode`: `'` and `"` self-insert as curved quotes.
    ElectricQuote,
    /// `electric-layout-mode`: `;` `{` `}` open a fresh line after themselves.
    ElectricLayout,
}

fn insert_modes() -> &'static std::sync::RwLock<HashSet<u8>> {
    static F: std::sync::OnceLock<std::sync::RwLock<HashSet<u8>>> = std::sync::OnceLock::new();
    // electric-indent-mode is the one that ships enabled.
    F.get_or_init(|| std::sync::RwLock::new(HashSet::from([InsertMode::ElectricIndent as u8])))
}

/// Whether `mode` is enabled (read by the insert path).
pub(crate) fn insert_mode_on(mode: InsertMode) -> bool {
    insert_modes().read().unwrap().contains(&(mode as u8))
}

/// Flip `mode` and report the new state.
fn toggle_insert_mode(cx: &mut Context, mode: InsertMode, label: &str) {
    let on = {
        let mut m = insert_modes().write().unwrap();
        if m.remove(&(mode as u8)) {
            false
        } else {
            m.insert(mode as u8);
            true
        }
    };
    cx.editor.set_status(format!(
        "{label} {}",
        if on { "enabled" } else { "disabled" }
    ));
}

/// Emacs `delete-selection-mode`: typing (or yanking) with an active region
/// replaces the region instead of inserting beside it.
fn delete_selection_mode(cx: &mut Context) {
    toggle_insert_mode(cx, InsertMode::DeleteSelection, "Delete-Selection mode");
}

/// Delete every non-empty selection range, collapsing each to a point, so the
/// character about to be self-inserted lands in its place. No-op when nothing is
/// selected (the common case: an ordinary point insert).
fn delete_active_region(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    let sel = doc.selection(view.id);
    if !sel.ranges().iter().any(|r| r.from() != r.to()) {
        return;
    }
    let transaction =
        Transaction::change_by_selection(doc.text(), sel, |range| (range.from(), range.to(), None));
    doc.apply(&transaction, view.id);
}

/// Emacs `electric-indent-mode`: RET re-indents the new line. Enabled by default;
/// turning it off makes newlines keep the column you were at.
fn electric_indent_mode(cx: &mut Context) {
    toggle_insert_mode(cx, InsertMode::ElectricIndent, "Electric-Indent mode");
}

/// Emacs `electric-quote-mode`: `'` and `"` insert curved quotes (`‘’` / `“”`),
/// opening or closing according to what precedes them.
fn electric_quote_mode(cx: &mut Context) {
    toggle_insert_mode(cx, InsertMode::ElectricQuote, "Electric-Quote mode");
}

/// Emacs `electric-layout-mode`: typing `;`, `{` or `}` also opens a new line
/// after it, so statements and blocks lay themselves out as you type.
fn electric_layout_mode(cx: &mut Context) {
    toggle_insert_mode(cx, InsertMode::ElectricLayout, "Electric-Layout mode");
}

/// `which-function-mode` — read by `ui::statusline::render`, which appends the
/// enclosing function's name to the status line of the focused view.
fn which_function_flag() -> &'static std::sync::atomic::AtomicBool {
    static F: std::sync::atomic::AtomicBool = std::sync::atomic::AtomicBool::new(false);
    &F
}

/// Whether the status line should show the enclosing function.
pub(crate) fn which_function_enabled() -> bool {
    which_function_flag().load(std::sync::atomic::Ordering::Relaxed)
}

/// The name of the innermost function / class enclosing point, for
/// `which-function-mode`. `None` when point is not inside one (or the buffer has
/// no syntax tree). Reuses the same tree-sitter textobject scan as the JetBrains
/// navigation bar, so the two never disagree.
pub(crate) fn which_function(editor: &Editor) -> Option<String> {
    navigation_crumbs(editor).last().map(|c| c.label.clone())
}

/// Emacs `which-function-mode`: show the function point is in on the mode line.
fn which_function_mode(cx: &mut Context) {
    let f = which_function_flag();
    let on = !f.load(std::sync::atomic::Ordering::Relaxed);
    f.store(on, std::sync::atomic::Ordering::Relaxed);
    cx.editor.set_status(if on {
        "Which-Function mode enabled"
    } else {
        "Which-Function mode disabled"
    });
}

// ---------------------------------------------------------------------------
// Emacs Compilation mode. zmax's compilation buffer is the Run tool window:
// `compile` / `recompile` stream a build into it and every `file:line` in the
// output is a navigable error. These are the commands that walk that list.
// ---------------------------------------------------------------------------

/// Emacs `compilation-next-file` (`M-}`): skip the rest of this file's errors and
/// land on the first error of the next file in the compilation output.
fn compilation_next_file(cx: &mut Context) {
    cx.callback.push(Box::new(|compositor, cx| {
        if let Some(view) = compositor.find::<crate::ui::EditorView>() {
            view.goto_run_error_file(cx, true);
        }
    }));
}

/// Emacs `compilation-previous-file` (`M-{`): the same, backwards — and it lands
/// on that file's *first* error, not its last.
fn compilation_previous_file(cx: &mut Context) {
    cx.callback.push(Box::new(|compositor, cx| {
        if let Some(view) = compositor.find::<crate::ui::EditorView>() {
            view.goto_run_error_file(cx, false);
        }
    }));
}

/// Emacs `compile-goto-error` (`RET` in the compilation buffer): visit the error
/// the compilation output is parked on, without advancing to the next one.
fn compile_goto_error(cx: &mut Context) {
    cx.callback.push(Box::new(|compositor, cx| {
        if let Some(view) = compositor.find::<crate::ui::EditorView>() {
            view.goto_current_run_error(cx);
        }
    }));
}

/// Emacs `kill-compilation` (`C-c C-k`): kill the running compilation.
fn kill_compilation(cx: &mut Context) {
    cx.callback.push(Box::new(|compositor, cx| {
        if let Some(view) = compositor.find::<crate::ui::EditorView>() {
            view.kill_active_run(cx);
        }
    }));
}

// ---------------------------------------------------------------------------
// Emacs Grep. `grep`/`rgrep`/`lgrep` all run a search tool as a compilation, so
// the hits land in the compilation buffer and `next-error` walks them. zmax
// runs ripgrep into the Run console, where the same `file:line` navigation
// (`compilation-next-error`, `compilation-next-file`) applies.
// ---------------------------------------------------------------------------

/// Start `command` in the Run (compilation) console, rooted at `cwd`.
fn start_run(jobs: &mut job::Jobs, command: String, cwd: std::path::PathBuf) {
    let call = Callback::EditorCompositor(Box::new(
        move |editor: &mut Editor, compositor: &mut Compositor| match compositor
            .find::<crate::ui::EditorView>(
        ) {
            Some(view) => view.start_run_with_editor(editor, command, cwd),
            None => editor.set_error("no editor view"),
        },
    ));
    jobs.callback(async move { Ok(call) });
}

/// Shell-quote one argument for the run console's shell.
fn shell_quote(s: &str) -> String {
    format!("'{}'", s.replace('\'', r"'\''"))
}

/// The shared body of `rgrep` / `lgrep` / `grep-find`: read the regexp, then the
/// file glob, then (unless `dir` is already fixed) the directory, and run ripgrep
/// over them. `recursive` distinguishes `rgrep`/`grep-find` from `lgrep`.
fn grep_prompt(cx: &mut Context, label: &'static str, recursive: bool, fixed_dir: bool) {
    let root = zmax_loader::find_workspace().0;
    prompt_then(cx, label, move |cx, pattern| {
        let pattern = pattern.to_string();
        let root = root.clone();
        prompt_then_cx(cx, "files (glob, e.g. *.rs): ", move |cx, glob| {
            let glob = glob.to_string();
            let pattern = pattern.clone();
            let root = root.clone();
            let run = move |cx: &mut crate::compositor::Context, dir: String| {
                let mut cmd = String::from("rg --no-heading --line-number --color never");
                if !recursive {
                    // `lgrep` searches one directory, not the tree below it.
                    cmd.push_str(" --max-depth 1");
                }
                cmd.push_str(&format!(
                    " --glob {} -e {} -- {}",
                    shell_quote(&glob),
                    shell_quote(&pattern),
                    shell_quote(&dir)
                ));
                start_run(cx.jobs, cmd, std::path::PathBuf::from(&dir));
            };
            if fixed_dir {
                run(cx, root.to_string_lossy().into_owned());
            } else {
                let root = root.clone();
                prompt_then_cx(cx, "directory: ", move |cx, dir| {
                    let dir = if dir.is_empty() {
                        root.to_string_lossy().into_owned()
                    } else {
                        dir.to_string()
                    };
                    run(cx, dir);
                });
            }
        });
    });
}

/// Emacs `rgrep`: grep recursively under a directory you name, restricted to the
/// files matching a glob. Hits stream into the compilation (Run) console.
fn rgrep(cx: &mut Context) {
    grep_prompt(cx, "rgrep (regexp): ", true, false);
}

/// Emacs `lgrep`: grep the files of one directory *without* descending into its
/// subdirectories.
fn lgrep(cx: &mut Context) {
    grep_prompt(cx, "lgrep (regexp): ", false, false);
}

/// Emacs `grep-find` (alias `find-grep`): recursive grep, rooted at the project.
fn grep_find(cx: &mut Context) {
    grep_prompt(cx, "grep-find (regexp): ", true, true);
}

// ---------------------------------------------------------------------------
// Emacs Hideshow (`hs-minor-mode`'s commands), over the document's fold state.
// ---------------------------------------------------------------------------

/// The syntax-tree block nodes of `doc` at nesting depth `level` (1 = outermost),
/// as the `(first, last)` line ranges to fold. A "block" is any node spanning
/// more than one line — the same definition `hs-hide-level` uses via
/// `hs-block-start-regexp`.
fn hs_blocks_at_level(doc: &Document, level: usize) -> Vec<(usize, usize)> {
    let Some(syntax) = doc.syntax() else {
        return Vec::new();
    };
    let slice = doc.text().slice(..);
    let len = slice.len_bytes();
    let mut out = Vec::new();
    // Depth counts only the *multi-line* ancestors, so a block's level is its
    // nesting among blocks, not among all syntax nodes.
    let mut stack = vec![(syntax.tree().root_node(), 0usize)];
    while let Some((node, depth)) = stack.pop() {
        let br = node.byte_range();
        let start = slice.char_to_line(slice.byte_to_char((br.start as usize).min(len)));
        let end = slice.char_to_line(slice.byte_to_char((br.end as usize).min(len)));
        let is_block = end > start;
        let depth = if is_block { depth + 1 } else { depth };
        if is_block && depth == level {
            // Fold the body: the lines strictly inside the block.
            if end > start + 1 {
                out.push((start + 1, end - 1));
            }
            continue; // deeper blocks are inside this one; nothing more to do
        }
        for child in node.children() {
            stack.push((child, depth));
        }
    }
    out.sort_unstable();
    out.dedup();
    out
}

/// Emacs `hs-hide-level`: hide every block at the nesting depth you name (with a
/// prefix arg in Emacs; zmax prompts), leaving shallower blocks open.
fn hs_hide_level(cx: &mut Context) {
    let level = cx.count.map_or(0, |c| c.get());
    if level > 0 {
        return hs_hide_level_n(cx, level);
    }
    prompt_then(cx, "hs-hide-level (depth): ", |cx, input| {
        let Ok(level) = input.parse::<usize>() else {
            cx.editor.set_error("hs-hide-level: not a number");
            return;
        };
        if level == 0 {
            cx.editor.set_error("hs-hide-level: depth must be >= 1");
            return;
        }
        let mut ctx = Context {
            register: None,
            count: None,
            editor: cx.editor,
            callback: Vec::new(),
            on_next_key_callback: None,
            jobs: cx.jobs,
        };
        hs_hide_level_n(&mut ctx, level);
    });
}

/// Fold every block at depth `level`.
fn hs_hide_level_n(cx: &mut Context, level: usize) {
    let blocks = hs_blocks_at_level(doc!(cx.editor), level);
    if blocks.is_empty() {
        cx.editor
            .set_status(format!("hs-hide-level: no blocks at depth {level}"));
        return;
    }
    let n = blocks.len();
    let (view, doc) = current!(cx.editor);
    let total = doc.text().len_lines();
    for (first, last) in blocks {
        doc.folds_mut().create(first, last);
        doc.folds_mut().close(first);
    }
    doc.folds_mut().clamp(total.saturating_sub(1));
    fold_snap_cursor(view, doc);
    cx.editor.set_status(format!(
        "hs-hide-level: folded {n} block(s) at depth {level}"
    ));
}

/// Emacs `hs-show-region`: reveal everything inside the selection — every fold
/// that overlaps it is opened.
fn hs_show_region(cx: &mut Context) {
    let (view, doc) = current!(cx.editor);
    let text = doc.text();
    let range = doc.selection(view.id).primary();
    let (l0, l1) = (
        text.char_to_line(range.from()),
        text.char_to_line(range.to().min(text.len_chars())),
    );
    let opened: Vec<usize> = doc
        .folds()
        .closed_ranges()
        .into_iter()
        .filter(|&(start, end)| start <= l1 && end >= l0)
        .map(|(start, _)| start)
        .collect();
    if opened.is_empty() {
        cx.editor
            .set_status("hs-show-region: no folds in the selection");
        return;
    }
    let n = opened.len();
    for start in opened {
        doc.folds_mut().open(start);
    }
    cx.editor
        .set_status(format!("hs-show-region: opened {n} fold(s)"));
}

// ---------------------------------------------------------------------------
// Emacs Rectangles: the pieces of `C-x r` not already covered by the RectOp
// family (kill / delete / clear / yank / open / copy).
// ---------------------------------------------------------------------------

/// Emacs `string-rectangle` (`C-x r t`): replace the rectangle's contents on each
/// line with a string you type. Shorter lines are padded out to the rectangle's
/// left column first, so the string still lands in the right column.
fn string_rectangle(cx: &mut Context) {
    prompt_then(cx, "string rectangle: ", |cx, s| {
        let s = s.to_string();
        let (view, doc) = current!(cx.editor);
        let text = doc.text().clone();
        let sel = doc.selection(view.id).primary();
        let (p0, p1) = (sel.from(), sel.to());
        let l0 = text.char_to_line(p0);
        let l1 = text.char_to_line(p1.max(p0).saturating_sub(1).max(p0));
        let col_of = |pos: usize| pos - text.line_to_char(text.char_to_line(pos));
        let (c0, c1) = (col_of(p0), col_of(p1));
        let left = c0.min(c1);

        // Delete the rectangle's columns (which consumes its right edge), then
        // splice the string in at its left edge on every line it spans.
        let lines = doc_lines(&text);
        let mut new_lines = crate::emacs_rect::delete(&lines, l0, l1, c0, c1);
        for line in new_lines.iter_mut().take(l1 + 1).skip(l0) {
            let mut chars: Vec<char> = line.chars().collect();
            // Pad short lines out to the rectangle's left column so the string
            // still lands in the right column.
            while chars.len() < left {
                chars.push(' ');
            }
            let at = left.min(chars.len());
            let tail: String = chars[at..].iter().collect();
            let head: String = chars[..at].iter().collect();
            *line = format!("{head}{s}{tail}");
        }

        let le = doc.line_ending.as_str();
        let new_text = new_lines.join(le);
        let old_len = text.len_chars();
        let transaction = Transaction::change(
            &text,
            std::iter::once((0, old_len, Some(Tendril::from(new_text.as_str())))),
        );
        let (view, doc) = current!(cx.editor);
        doc.apply(&transaction, view.id);
        cx.editor.set_status(format!(
            "string-rectangle: inserted \"{s}\" on {} line(s)",
            l1 + 1 - l0
        ));
    });
}

/// Emacs `rectangle-mark-mode` (`C-x SPC`): make the region rectangular, so the
/// rectangle commands act on the block between point and mark. zmax's
/// rectangular region is vim's visual-block selection.
fn rectangle_mark_mode(cx: &mut Context) {
    visual_block_mode(cx);
}

/// Emacs `rectangle-exchange-point-and-mark` (`C-x C-x` inside
/// `rectangle-mark-mode`): move point to the opposite corner of the rectangle.
fn rectangle_exchange_point_and_mark(cx: &mut Context) {
    if cx.editor.block.is_none() {
        cx.editor
            .set_error("rectangle-exchange-point-and-mark: not in rectangle-mark-mode");
        return;
    }
    block_swap_corners(cx);
}

// ---------------------------------------------------------------------------
// Emacs Customize. zmax's customization data is its TOML config, so the
// Customize commands are views on it: the settings tree, a search over it, and
// the diff against the built-in defaults.
// ---------------------------------------------------------------------------

/// One configuration setting, flattened to a dotted path.
struct CustomSetting {
    path: String,
    value: String,
    default: String,
}

/// Flatten a TOML value into dotted `path = value` leaves.
fn flatten_toml(v: &toml::Value, prefix: &str, out: &mut Vec<(String, String)>) {
    match v {
        toml::Value::Table(t) => {
            let mut keys: Vec<&String> = t.keys().collect();
            keys.sort();
            for k in keys {
                let p = if prefix.is_empty() {
                    k.clone()
                } else {
                    format!("{prefix}.{k}")
                };
                flatten_toml(&t[k], &p, out);
            }
        }
        other => out.push((prefix.to_string(), other.to_string())),
    }
}

/// Every setting the editor is running with, paired with its built-in default so
/// the Customize commands can tell "changed" from "untouched".
fn custom_settings(editor: &Editor) -> Vec<CustomSetting> {
    let empty = || toml::Value::Table(toml::map::Map::new());
    let live = toml::Value::try_from(&*editor.config()).unwrap_or_else(|_| empty());
    let base =
        toml::Value::try_from(zmax_view::editor::Config::default()).unwrap_or_else(|_| empty());
    let (mut live_leaves, mut base_leaves) = (Vec::new(), Vec::new());
    flatten_toml(&live, "", &mut live_leaves);
    flatten_toml(&base, "", &mut base_leaves);
    let defaults: HashMap<String, String> = base_leaves.into_iter().collect();
    live_leaves
        .into_iter()
        .map(|(path, value)| {
            let default = defaults.get(&path).cloned().unwrap_or_default();
            CustomSetting {
                path,
                value,
                default,
            }
        })
        .collect()
}

/// The Customize picker: setting / value / default, selecting one copies its
/// dotted path (the affordance `config-variable-search` gives) so it can be
/// pasted straight into a config file. Every Customize command builds this same
/// picker — there is exactly one construction of it.
fn build_customize_picker(settings: Vec<CustomSetting>) -> Box<dyn Component> {
    let columns = [
        ui::PickerColumn::new("setting", |s: &CustomSetting, _: &()| {
            s.path.as_str().into()
        }),
        ui::PickerColumn::new("value", |s: &CustomSetting, _: &()| s.value.as_str().into()),
        ui::PickerColumn::new("default", |s: &CustomSetting, _: &()| {
            s.default.as_str().into()
        }),
    ];
    let picker = Picker::new(
        columns,
        0,
        settings,
        (),
        |cx, s: &CustomSetting, _action| {
            let path = s.path.clone();
            match cx.editor.registers.write('+', vec![path.clone()]) {
                Ok(()) => cx.editor.set_status(format!("Copied: {path}")),
                Err(e) => cx.editor.set_error(e.to_string()),
            }
        },
    );
    Box::new(overlaid(picker))
}

/// Show `settings` in the Customize picker now.
fn customize_picker(cx: &mut Context, title: &'static str, settings: Vec<CustomSetting>) {
    if settings.is_empty() {
        cx.editor.set_status(format!("{title}: nothing to show"));
        return;
    }
    cx.push_layer(build_customize_picker(settings));
}

/// Show `settings` in the Customize picker from inside another picker's / prompt's
/// callback (which cannot push a layer directly), reporting `empty` when there is
/// nothing to show.
fn customize_picker_deferred(
    cx: &mut crate::compositor::Context,
    settings: Vec<CustomSetting>,
    empty: &'static str,
) {
    let call: job::Callback = Callback::EditorCompositor(Box::new(
        move |editor: &mut Editor, compositor: &mut Compositor| {
            if settings.is_empty() {
                editor.set_status(empty);
                return;
            }
            compositor.push(build_customize_picker(settings));
        },
    ));
    cx.jobs.callback(async move { Ok(call) });
}

/// Emacs `customize-group`: customize the settings of one group. zmax's groups
/// are the top-level config sections (`editor`, `keys`, `theme`, …) — pick one and
/// its settings are shown.
fn customize_group(cx: &mut Context) {
    let groups: Vec<String> = {
        let mut g: Vec<String> = custom_settings(cx.editor)
            .iter()
            .filter_map(|s| s.path.split('.').next().map(str::to_string))
            .collect();
        g.sort();
        g.dedup();
        g
    };
    if groups.is_empty() {
        cx.editor.set_error("customize-group: no settings");
        return;
    }
    let columns = [ui::PickerColumn::new("group", |g: &String, _: &()| {
        g.as_str().into()
    })];
    let picker = Picker::new(columns, 0, groups, (), |cx, group, _action| {
        let group = group.clone();
        let settings: Vec<CustomSetting> = custom_settings(cx.editor)
            .into_iter()
            .filter(|s| s.path.split('.').next() == Some(group.as_str()))
            .collect();
        customize_picker_deferred(cx, settings, "customize-group: no settings in that group");
    });
    cx.push_layer(Box::new(overlaid(picker)));
}

/// Emacs `customize-apropos`: customize every setting whose name or value matches
/// a regexp you type.
fn customize_apropos(cx: &mut Context) {
    prompt_then(cx, "customize-apropos (regexp): ", |cx, pattern| {
        let re = match regex::Regex::new(pattern) {
            Ok(re) => re,
            Err(e) => {
                cx.editor.set_error(format!("customize-apropos: {e}"));
                return;
            }
        };
        let hits: Vec<CustomSetting> = custom_settings(cx.editor)
            .into_iter()
            .filter(|s| re.is_match(&s.path) || re.is_match(&s.value))
            .collect();
        customize_picker_deferred(cx, hits, "customize-apropos: no matching settings");
    });
}

/// Emacs `customize-changed`: the settings whose current value differs from the
/// built-in default — i.e. everything this configuration actually changes.
fn customize_changed(cx: &mut Context) {
    let changed: Vec<CustomSetting> = custom_settings(cx.editor)
        .into_iter()
        .filter(|s| s.value != s.default)
        .collect();
    customize_picker(cx, "customize-changed", changed);
}

/// Emacs `customize-saved`: the settings written down in the config file (the
/// ones that will come back on the next start).
fn customize_saved(cx: &mut Context) {
    let saved: Vec<(String, String)> = {
        let path = zmax_loader::config_file();
        let mut leaves = Vec::new();
        if let Ok(text) = std::fs::read_to_string(&path) {
            if let Ok(v) = text.parse::<toml::Value>() {
                flatten_toml(&v, "", &mut leaves);
            }
        }
        leaves
    };
    if saved.is_empty() {
        cx.editor
            .set_status("customize-saved: the config file sets nothing (all defaults)");
        return;
    }
    let live: HashMap<String, String> = custom_settings(cx.editor)
        .into_iter()
        .map(|s| (s.path, s.default))
        .collect();
    let settings: Vec<CustomSetting> = saved
        .into_iter()
        .map(|(path, value)| {
            let default = live.get(&path).cloned().unwrap_or_default();
            CustomSetting {
                path,
                value,
                default,
            }
        })
        .collect();
    customize_picker(cx, "customize-saved", settings);
}

/// Emacs `customize-unsaved`: the settings changed for this session but *not*
/// written to the config file — they are lost on exit unless saved.
fn customize_unsaved(cx: &mut Context) {
    let saved: HashMap<String, String> = {
        let mut leaves = Vec::new();
        if let Ok(text) = std::fs::read_to_string(zmax_loader::config_file()) {
            if let Ok(v) = text.parse::<toml::Value>() {
                flatten_toml(&v, "", &mut leaves);
            }
        }
        leaves.into_iter().collect()
    };
    // Changed from the default, but the config file does not say so.
    let unsaved: Vec<CustomSetting> = custom_settings(cx.editor)
        .into_iter()
        .filter(|s| s.value != s.default && saved.get(&s.path) != Some(&s.value))
        .collect();
    if unsaved.is_empty() {
        cx.editor
            .set_status("customize-unsaved: every changed setting is saved");
        return;
    }
    customize_picker(cx, "customize-unsaved", unsaved);
}

/// Emacs `customize-dirlocals`: edit the directory-local settings of this project
/// (Emacs's `.dir-locals.el`; zmax's `.zmax/config.toml`).
fn customize_dirlocals(cx: &mut Context) {
    edit_project_config(cx);
}

// ---------------------------------------------------------------------------
// Emacs Org structure editing (the `M-<arrow>` / `S-TAB` family), over the same
// heading engine the outline commands use.
// ---------------------------------------------------------------------------

/// Emacs `org-metaleft` (`M-<left>`): promote the heading at point.
fn org_metaleft(cx: &mut Context) {
    org_promote(cx);
}

/// Emacs `org-metaright` (`M-<right>`): demote the heading at point.
fn org_metaright(cx: &mut Context) {
    org_demote(cx);
}

/// Emacs `org-metaup` (`M-<up>`): move the subtree at point above its previous
/// sibling, children and all.
fn org_metaup(cx: &mut Context) {
    org_move_subtree(cx, true);
}

/// Emacs `org-metadown` (`M-<down>`): move the subtree at point below its next
/// sibling.
fn org_metadown(cx: &mut Context) {
    org_move_subtree(cx, false);
}

/// Exchange the subtree at point with its previous (`up`) or next sibling.
fn org_move_subtree(cx: &mut Context, up: bool) {
    let (view, doc) = current!(cx.editor);
    let text = doc.text().clone();
    let cursor = doc.selection(view.id).primary().cursor(text.slice(..));
    let cursor_line = text.char_to_line(cursor);
    let cursor_col = cursor - text.line_to_char(cursor_line);

    // Work on the real lines: a trailing newline would otherwise make an empty
    // last "line" travel with the final subtree.
    let body: String = text.slice(..).chars().collect();
    let trimmed = body.trim_end_matches('\n');
    let lines: Vec<&str> = trimmed.split('\n').collect();

    let hs = zmax_core::outline::headings(trimmed);
    let Some(swap) = zmax_core::outline::sibling_swap(&hs, cursor_line, lines.len(), up) else {
        cx.editor.set_status(if up {
            "org-metaup: no previous sibling at this level"
        } else {
            "org-metadown: no next sibling at this level"
        });
        return;
    };
    let mut new_text = zmax_core::outline::apply_sibling_swap(&lines, swap).join("\n");
    new_text.push_str(&body[trimmed.len()..]); // the trailing newline(s), if any

    let old_len = text.len_chars();
    let transaction = Transaction::change(
        &text,
        std::iter::once((0, old_len, Some(Tendril::from(new_text.as_str())))),
    );
    doc.apply(&transaction, view.id);

    // Follow the subtree to its new home, keeping the column.
    let (view, doc) = current!(cx.editor);
    let text = doc.text();
    let new_line = (cursor_line as isize + swap.cursor_delta)
        .clamp(0, text.len_lines().saturating_sub(1) as isize) as usize;
    let line_start = text.line_to_char(new_line);
    let line_len = text.line(new_line).len_chars();
    let pos = (line_start + cursor_col.min(line_len.saturating_sub(1))).min(text.len_chars());
    doc.set_selection(view.id, Selection::point(pos));
}

/// Emacs `org-shifttab` (`S-TAB`): cycle the whole buffer's visibility —
/// overview (headings only) -> contents -> show all.
fn org_shifttab(cx: &mut Context) {
    outline_cycle_buffer(cx);
}

/// Emacs `c-ts-mode-set-style`: the tree-sitter C mode's style command. zmax
/// derives the style from the buffer's actual indentation, so it reports the same
/// style `c-set-style` does.
fn c_ts_mode_set_style(cx: &mut Context) {
    c_set_style(cx);
}

// ===========================================================================
// Emacs commands: non-incremental word search, fill, rigid indent, quoting,
// foldout, related files, windows/buffers, abbrev files, whitespace options.
// ===========================================================================

/// Shared body of `word-search-forward` / `word-search-backward`: read a search
/// string and jump to the next match of it as a *word* search — the words must
/// appear in order, but any punctuation or whitespace may separate them, and the
/// ends must fall on word boundaries. The regexp is built by
/// `zmax_core::search::word_search_regexp` (the port of emacs's
/// `word-search-regexp`).
fn word_search_impl(cx: &mut Context, direction: Direction, label: &'static str) {
    let scrolloff = cx.editor.config().scrolloff;
    let wrap_around = cx.editor.config().search.wrap_around;
    prompt_then(cx, label, move |cx, input| {
        if input.is_empty() {
            return;
        }
        let pattern = zmax_core::search::word_search_regexp(input, false);
        let ci = cx.editor.config().search.smart_case && !input.chars().any(char::is_uppercase);
        match rope::RegexBuilder::new()
            .syntax(rope::Config::new().case_insensitive(ci).multi_line(true))
            .build(&pattern)
        {
            Ok(regex) => search_impl(
                cx.editor,
                &regex,
                Movement::Move,
                direction,
                scrolloff,
                wrap_around,
                true,
            ),
            Err(err) => cx.editor.set_error(format!("word-search: {err}")),
        }
    });
}

/// Emacs `word-search-forward` (`M-s w`): search forward for a sequence of words,
/// ignoring the punctuation and whitespace between them.
fn word_search_forward(cx: &mut Context) {
    word_search_impl(cx, Direction::Forward, "Word search: ");
}

/// Emacs `word-search-backward`: [`word_search_forward`] the other way.
fn word_search_backward(cx: &mut Context) {
    word_search_impl(cx, Direction::Backward, "Word search backward: ");
}

/// Emacs `fill-region-as-paragraph` (`M-x`): fill the region as ONE paragraph —
/// the line breaks *and blank lines* inside it are folded away and the whole
/// region is re-wrapped to the fill column. (`fill-region` would instead keep the
/// blank lines and fill each paragraph separately.)
fn fill_region_as_paragraph(cx: &mut Context) {
    let width = cx.editor.config().text_width;
    let (view, doc) = current!(cx.editor);
    let range = doc.selection(view.id).primary();
    if range.from() == range.to() {
        cx.editor
            .set_error("fill-region-as-paragraph: the region is empty");
        return;
    }
    let (from, to) = (range.from(), range.to());
    let src: String = doc.text().slice(from..to).chars().collect();
    let filled = zmax_core::wrap::fill_as_paragraph(&src, width);
    let tx = Transaction::change(
        doc.text(),
        std::iter::once((from, to, Some(Tendril::from(filled.as_str())))),
    );
    doc.apply(&tx, view.id);
    doc.append_changes_to_history(view);
    let end = (from + filled.chars().count()).min(doc.text().len_chars());
    doc.set_selection(view.id, Selection::single(from, end));
}

/// Emacs `indent-rigidly` (`C-x TAB`): shift every line of the region by a number
/// of *columns* (negative shifts left). Emacs takes the count as a prefix
/// argument; zmax reads it from a prompt so a left shift can be typed as well.
fn indent_rigidly(cx: &mut Context) {
    prompt_then(cx, "Indent rigidly (columns): ", |cx, input| {
        let Ok(cols) = input.trim().parse::<i64>() else {
            cx.editor
                .set_error("indent-rigidly: give a (possibly negative) column count");
            return;
        };
        let (view, doc) = current!(cx.editor);
        let tab_width = doc.tab_width();
        let text = doc.text();
        let slice = text.slice(..);
        let range = doc.selection(view.id).primary();
        let first = slice.char_to_line(range.from());
        let last = slice.char_to_line(range.to().saturating_sub(1).max(range.from()));
        let from = slice.line_to_char(first);
        let to = slice.line_to_char((last + 1).min(slice.len_lines()));
        let block: String = slice.slice(from..to).chars().collect();
        // Keep the block's trailing newline out of the shift, then put it back.
        let (body, tail) = match block.strip_suffix('\n') {
            Some(body) => (body, "\n"),
            None => (block.as_str(), ""),
        };
        let shifted = format!(
            "{}{tail}",
            zmax_core::indent::indent_rigidly(body, cols, tab_width)
        );
        let tx = Transaction::change(
            text,
            std::iter::once((from, to, Some(Tendril::from(shifted.as_str())))),
        );
        doc.apply(&tx, view.id);
        doc.append_changes_to_history(view);
        cx.editor.set_status(format!(
            "Indented {} line(s) by {cols} column(s)",
            last - first + 1
        ));
    });
}

/// Emacs `quoted-insert` (`C-q`): insert the next character literally — including
/// a control character, which is otherwise a command. `C-q TAB` inserts a tab,
/// `C-q C-l` a form feed, `C-q RET` a newline.
fn quoted_insert(cx: &mut Context) {
    cx.editor.set_status("C-q-");
    cx.on_next_key(move |cx, event| {
        use zmax_view::input::KeyModifiers;
        let literal = match event.code {
            KeyCode::Enter => Some('\n'),
            KeyCode::Tab => Some('\t'),
            KeyCode::Char(c) if event.modifiers.contains(KeyModifiers::CONTROL) => {
                // The ASCII control character the key stands for: C-a..C-z and
                // C-@ C-[ C-\ C-] C-^ C-_ are `key & 0x1f`; C-? is DEL.
                let byte = if c == '?' {
                    0x7f
                } else {
                    (c.to_ascii_uppercase() as u8).wrapping_sub(0x40)
                };
                Some(if byte <= 0x1f || byte == 0x7f {
                    byte as char
                } else {
                    c
                })
            }
            KeyCode::Char(c) => Some(c),
            _ => None,
        };
        match literal {
            Some(c) => {
                insert_at_cursors(cx.editor, &c.to_string());
                cx.editor.set_status(format!("Inserted {:?}", c));
            }
            None => cx.editor.set_error("quoted-insert: not a character"),
        }
    });
}

/// Narrow the buffer (and fold everything outside) to the inclusive line range
/// `[first, last]` — the line-addressed form of [`narrow_to_region`], used by
/// foldout to zoom into an outline subtree.
fn narrow_to_lines(cx: &mut Context, first: usize, last: usize) {
    let (view, doc) = current!(cx.editor);
    let text = doc.text().slice(..);
    let last_line = doc.text().len_lines().saturating_sub(1);
    let lo = text.line_to_char(first);
    let hi = text.line_to_char((last + 1).min(text.len_lines()));
    for (s, e) in narrow_outside_ranges(first, last, last_line) {
        doc.folds_mut().create(s, e);
    }
    doc.folds_mut().clamp(last_line);
    doc.narrow_to(lo, hi);
    fold_goto_line(view, doc, first);
}

/// Emacs `foldout-zoom-subtree` (`C-c C-z`): zoom into the outline subtree at
/// point — narrow the buffer to the heading and its body so nothing outside it is
/// visible or reachable. `foldout-exit-fold` zooms back out.
fn foldout_zoom_subtree(cx: &mut Context) {
    let (line, text) = outline_context(cx);
    let hs = zmax_core::outline::headings(&text);
    let total = doc!(cx.editor).text().len_lines();
    match zmax_core::outline::subtree_bounds(&hs, line, total) {
        Some((first, last)) => {
            narrow_to_lines(cx, first, last);
            cx.editor.set_status(format!(
                "Zoomed into the subtree at line {} ({} line(s))",
                first + 1,
                last - first + 1
            ));
        }
        None => cx
            .editor
            .set_error("foldout-zoom-subtree: point is not in an outline subtree"),
    }
}

/// Emacs `foldout-exit-fold` (`C-c C-x`): leave the zoomed subtree — widen back to
/// the whole buffer and put point back on the heading that was zoomed into.
fn foldout_exit_fold(cx: &mut Context) {
    let was_narrowed = {
        let (view, doc) = current_ref!(cx.editor);
        doc.is_narrowed() || doc.view_narrow(view.id).is_some()
    };
    if !was_narrowed {
        cx.editor.set_error("foldout-exit-fold: not inside a fold");
        return;
    }
    widen(cx);
    let (line, text) = outline_context(cx);
    let hs = zmax_core::outline::headings(&text);
    let head = zmax_core::outline::headings(&text)
        .iter()
        .rev()
        .find(|h| h.line <= line)
        .copied()
        .or_else(|| zmax_core::outline::up_heading(&hs, line));
    outline_goto(cx, head);
    cx.editor.set_status("Exited the fold");
}

/// Emacs `ff-find-related-file` (`find-file.el`): visit the file related to this
/// one — the header of a source file, the source of a header. The candidates and
/// their order are emacs's `cc-other-file-alist`
/// (`zmax_core::cmode::related_file_names`); they are looked for beside the
/// file and in the usual `include`/`inc`/`src`/`lib` siblings of its directory.
fn ff_find_related_file(cx: &mut Context) {
    let Some(path) = doc!(cx.editor).path().map(|p| p.to_path_buf()) else {
        cx.editor
            .set_error("ff-find-related-file: buffer is not visiting a file");
        return;
    };
    let Some(name) = path.file_name().and_then(|n| n.to_str()) else {
        return;
    };
    let candidates = zmax_core::cmode::related_file_names(name);
    if candidates.is_empty() {
        cx.editor
            .set_error(format!("ff-find-related-file: no related file for {name}"));
        return;
    }
    let dir = path.parent().unwrap_or(std::path::Path::new("."));
    let mut dirs = vec![dir.to_path_buf()];
    if let Some(parent) = dir.parent() {
        for alt in ["include", "inc", "src", "lib"] {
            let d = parent.join(alt);
            if d.is_dir() && d != dir {
                dirs.push(d);
            }
        }
    }
    for cand in &candidates {
        for d in &dirs {
            let target = d.join(cand);
            if target.is_file() {
                if let Err(err) = cx.editor.open(&target, Action::Replace) {
                    cx.editor.set_error(format!("ff-find-related-file: {err}"));
                }
                return;
            }
        }
    }
    cx.editor.set_error(format!(
        "ff-find-related-file: none of {} exists",
        candidates.join(", ")
    ));
}

/// Emacs `revert-buffer-quick` (`C-x x g`): revert the buffer from its file with
/// no confirmation prompt (the "quick" of the name).
fn revert_buffer_quick(cx: &mut Context) {
    if doc!(cx.editor).path().is_none() {
        cx.editor
            .set_error("revert-buffer-quick: buffer is not visiting a file");
        return;
    }
    let scrolloff = cx.editor.config().scrolloff;
    let trust_full = reload_trust_full(cx.editor);
    let (view, doc) = current!(cx.editor);
    match doc.reload(view, &cx.editor.diff_providers, trust_full) {
        Ok(()) => {
            view.ensure_cursor_in_view(doc, scrolloff);
            cx.editor.set_status("Reverted buffer from file");
        }
        Err(err) => cx.editor.set_error(format!("revert-buffer-quick: {err}")),
    }
}

/// Emacs `delete-file`: delete a file from disk. The prompt defaults to the file
/// this buffer is visiting; the buffer itself is left alone (as in emacs, which
/// leaves it visiting a now-missing file).
fn delete_file(cx: &mut Context) {
    let current = doc!(cx.editor)
        .path()
        .map(|p| p.display().to_string())
        .unwrap_or_default();
    prompt_then(cx, "Delete file: ", move |cx, input| {
        let raw = if input.is_empty() {
            current.as_str()
        } else {
            input
        };
        if raw.is_empty() {
            cx.editor.set_error("delete-file: no file");
            return;
        }
        let path = zmax_stdx::path::expand_tilde(std::path::Path::new(raw)).into_owned();
        match std::fs::remove_file(&path) {
            Ok(()) => cx.editor.set_status(format!("Deleted {}", path.display())),
            Err(err) => cx
                .editor
                .set_error(format!("delete-file: {}: {err}", path.display())),
        }
    });
}

/// Spacemacs `] f` / `[ f` (vim-unimpaired `]f`/`[f`): open the next/previous
/// file in the current file's directory, in name-sorted order, wrapping at the
/// ends. Hidden files and subdirectories are skipped.
fn cycle_file_in_dir(cx: &mut Context, forward: bool) {
    let cur = {
        let (_, doc) = current!(cx.editor);
        match doc.path() {
            Some(p) => p.to_path_buf(),
            None => {
                cx.editor.set_error("no file in this buffer");
                return;
            }
        }
    };
    let Some(dir) = cur.parent().map(|d| d.to_path_buf()) else {
        cx.editor.set_error("file has no parent directory");
        return;
    };
    let mut files: Vec<std::path::PathBuf> = match std::fs::read_dir(&dir) {
        Ok(rd) => rd
            .filter_map(|e| e.ok())
            .map(|e| e.path())
            .filter(|p| p.is_file())
            .filter(|p| {
                !p.file_name()
                    .and_then(|n| n.to_str())
                    .is_some_and(|n| n.starts_with('.'))
            })
            .collect(),
        Err(e) => {
            cx.editor.set_error(format!("{}: {e}", dir.display()));
            return;
        }
    };
    files.sort();
    if files.is_empty() {
        cx.editor.set_error("no files in this directory");
        return;
    }
    // Locate the current file by full path, falling back to file name (the open
    // path may differ from read_dir's join only by canonicalization).
    let idx = files
        .iter()
        .position(|p| p == &cur)
        .or_else(|| files.iter().position(|p| p.file_name() == cur.file_name()))
        .unwrap_or(0);
    let n = files.len();
    let next = if forward {
        (idx + 1) % n
    } else {
        (idx + n - 1) % n
    };
    let target = files[next].clone();
    if let Err(e) = cx.editor.open(&target, Action::Replace) {
        cx.editor
            .set_error(format!("open {}: {e}", target.display()));
    }
}

/// Spacemacs `SPC t z`: toggle 0-based vs 1-based column indexing in the
/// statusline position readout.
fn toggle_column_indexing(cx: &mut Context) {
    use std::sync::atomic::Ordering;
    let now = !crate::ui::statusline::COLUMN_ZERO_BASED.load(Ordering::Relaxed);
    crate::ui::statusline::COLUMN_ZERO_BASED.store(now, Ordering::Relaxed);
    cx.editor.set_status(if now {
        "column indexing: 0-based"
    } else {
        "column indexing: 1-based"
    });
}

/// Emacs `bury-buffer` (Spacemacs `SPC b . C-d`): stop showing the current
/// buffer in this window without killing it — display the previously-visited
/// file instead. The buffer stays open and reachable from the buffer list.
fn bury_buffer(cx: &mut Context) {
    goto_last_accessed_file(cx);
}

/// Spacemacs `] f`: open the next file in the current file's directory.
fn next_file_in_dir(cx: &mut Context) {
    cycle_file_in_dir(cx, true);
}

/// Spacemacs `[ f`: open the previous file in the current file's directory.
fn prev_file_in_dir(cx: &mut Context) {
    cycle_file_in_dir(cx, false);
}

/// Emacs `quit-window` (`q` in a special buffer): quit the window showing this
/// buffer — close the window when it is one of several, and when it is the only
/// one, bury the buffer by switching the window to the previously visited file.
fn quit_window(cx: &mut Context) {
    if cx.editor.tree.views().count() > 1 {
        wclose(cx);
    } else {
        goto_last_accessed_file(cx);
    }
}

/// Emacs `switch-to-buffer-other-window` (`C-x 4 b`): pick a buffer and show it in
/// another window, splitting the current one.
fn switch_to_buffer_other_window(cx: &mut Context) {
    buffer_picker_impl(cx, Some(Action::HorizontalSplit), false);
}

/// Emacs `shrink-window-if-larger-than-buffer` (`C-x -`): shrink the window's
/// height to just fit its buffer's text, never below the minimum height and never
/// when the buffer is taller than the window.
fn shrink_window_if_larger_than_buffer(cx: &mut Context) {
    let view = cx.editor.tree.focus;
    let (height, lines) = {
        let view = cx.editor.tree.get(view);
        let doc = &cx.editor.documents[&view.doc];
        (view.inner_height(), doc.text().len_lines())
    };
    if height <= lines {
        cx.editor
            .set_status("shrink-window-if-larger-than-buffer: the buffer fills the window");
        return;
    }
    let delta = (height - lines) as i16;
    cx.editor.tree.resize_vertical(view, -delta);
    cx.editor.set_status(format!(
        "Shrank the window by {delta} line(s) to fit the buffer"
    ));
}

/// Emacs `edit-abbrevs` (`C-x a e` in `*Abbrevs*`): show every abbrev definition
/// in a buffer, in the same `abbrev-file` syntax `write-abbrev-file` produces.
/// Editing it and running `define-abbrevs` redefines them from the text — the
/// round trip emacs does with `edit-abbrevs-redefine`.
fn edit_abbrevs(cx: &mut Context) {
    let body = crate::emacs_abbrev::serialize();
    if body.is_empty() {
        cx.editor.set_status("No abbrevs defined");
        return;
    }
    show_text_in_scratch(cx.editor, &format!("{body}\n"));
    cx.editor
        .set_status("Edit the definitions, then M-x define-abbrevs to redefine them");
}

/// Emacs `quietly-read-abbrev-file`: read abbrev definitions from a file without
/// saying anything about it (the startup form of `read-abbrev-file`). The prompt
/// defaults to `~/.zmax/abbrev_defs`, where `write-abbrev-file` puts them.
fn quietly_read_abbrev_file(cx: &mut Context) {
    prompt_then(cx, "Read abbrev file: ", |cx, input| {
        let raw = if input.is_empty() {
            "~/.zmax/abbrev_defs"
        } else {
            input
        };
        let path = zmax_stdx::path::expand_tilde(std::path::Path::new(raw)).into_owned();
        match crate::emacs_abbrev::read_from(&path) {
            // Quietly: emacs prints nothing on success here.
            Ok(_) => {}
            Err(err) => cx.editor.set_error(format!(
                "quietly-read-abbrev-file: {}: {err}",
                path.display()
            )),
        }
    });
}

/// Emacs `whitespace-toggle-options` (`C-c w t`): toggle one of the whitespace
/// visualizations, chosen by the next key — `s` spaces, `t` tabs, `n` newlines,
/// `b` no-break spaces, `a` all of them. The renderer reads the resulting
/// `whitespace.render` config, so the buffer redraws at once.
fn whitespace_toggle_options(cx: &mut Context) {
    use zmax_view::editor::{WhitespaceRender, WhitespaceRenderValue};
    cx.editor
        .set_status("whitespace options: s=spaces t=tabs n=newlines b=nbsp a=all");
    cx.on_next_key(move |cx, event| {
        let Some(key) = event.char() else {
            cx.editor
                .set_error("whitespace-toggle-options: unknown option");
            return;
        };
        let mut label = String::new();
        edit_live_config(cx, |c| {
            // Read the current per-kind values, then flip the chosen one.
            let (mut space, mut tab, mut newline, mut nbsp) = (
                c.whitespace.render.space(),
                c.whitespace.render.tab(),
                c.whitespace.render.newline(),
                c.whitespace.render.nbsp(),
            );
            let flip = |v: &mut WhitespaceRenderValue| {
                *v = match *v {
                    WhitespaceRenderValue::None => WhitespaceRenderValue::All,
                    WhitespaceRenderValue::All => WhitespaceRenderValue::None,
                };
            };
            match key {
                's' => {
                    flip(&mut space);
                    label = format!("spaces {:?}", space);
                }
                't' => {
                    flip(&mut tab);
                    label = format!("tabs {:?}", tab);
                }
                'n' => {
                    flip(&mut newline);
                    label = format!("newlines {:?}", newline);
                }
                'b' => {
                    flip(&mut nbsp);
                    label = format!("nbsp {:?}", nbsp);
                }
                'a' => {
                    let on = matches!(space, WhitespaceRenderValue::None);
                    let v = if on {
                        WhitespaceRenderValue::All
                    } else {
                        WhitespaceRenderValue::None
                    };
                    space = v;
                    tab = v;
                    newline = v;
                    nbsp = v;
                    label = format!("all {:?}", v);
                }
                _ => return,
            }
            c.whitespace.render = WhitespaceRender::Specific {
                default: None,
                space: Some(space),
                nbsp: Some(nbsp),
                nnbsp: Some(nbsp),
                tab: Some(tab),
                newline: Some(newline),
            };
        });
        if label.is_empty() {
            cx.editor
                .set_error("whitespace-toggle-options: unknown option");
        } else {
            cx.editor.set_status(format!("whitespace: {label}"));
        }
    });
}

/// Emacs `xref-find-apropos` (`C-M-.`): list every identifier in the project whose
/// name matches a pattern, in the xref results buffer.
fn xref_find_apropos(cx: &mut Context) {
    prompt_then(cx, "Search for pattern: ", |cx, input| {
        if input.is_empty() {
            return;
        }
        let pattern = input.to_string();
        let root = std::env::current_dir().unwrap_or_else(|_| std::path::PathBuf::from("."));
        let call: job::Callback = Callback::EditorCompositor(Box::new(
            move |editor: &mut Editor, compositor: &mut Compositor| match crate::ui::xref::Xref::new(
                root, pattern,
            ) {
                Ok(x) => compositor.push(Box::new(x) as Box<dyn Component>),
                Err(e) => editor.set_error(format!("xref-find-apropos: {e}")),
            },
        ));
        cx.jobs.callback(async move { Ok(call) });
    });
}

/// Emacs `keyboard-escape-quit` (`ESC ESC ESC`): the universal "get out" — drop
/// any extra cursors, deactivate the region and leave select mode, leaving one
/// cursor where point is.
fn keyboard_escape_quit(cx: &mut Context) {
    keep_primary_selection(cx);
    collapse_selection(cx);
    if cx.editor.mode() == Mode::Select {
        exit_select_mode(cx);
    }
    cx.editor.autoinfo = None;
}

thread_local! {
    /// `kill-ring-deindent-mode`: read by [`deindent_killed`] on every text that
    /// goes to the kill ring.
    static KILL_RING_DEINDENT: std::cell::Cell<bool> = const { std::cell::Cell::new(false) };
}

/// Emacs `kill-ring-deindent-mode`: "text saved to the kill-ring will have its
/// indentation decreased by the amount of indentation of the first saved line"
/// (Emacs manual, *Kill Options*) — so a block lifted out of a nested context
/// pastes back at column zero. Read by [`deindent_killed`], which every kill and
/// copy passes its text through.
fn kill_ring_deindent_mode(cx: &mut Context) {
    let on = KILL_RING_DEINDENT.with(|f| {
        let v = !f.get();
        f.set(v);
        v
    });
    cx.editor.set_status(format!(
        "kill-ring-deindent mode {}",
        if on { "enabled" } else { "disabled" }
    ));
}

/// Deindent text on its way to the kill ring when `kill-ring-deindent-mode` is on.
/// A no-op otherwise.
fn deindent_killed(tab_width: usize, values: Vec<String>) -> Vec<String> {
    if !KILL_RING_DEINDENT.with(|f| f.get()) {
        return values;
    }
    values
        .into_iter()
        .map(|v| zmax_core::indent::deindent_by_first_line(&v, tab_width))
        .collect()
}

/// Emacs `async-shell-command` (`M-&`): run a shell command *without* blocking the
/// editor, and show its output in a buffer when it finishes. (`shell-command`,
/// `M-!`, waits for it.)
fn async_shell_command(cx: &mut Context) {
    prompt_then(cx, "Async shell command: ", |cx, input| {
        if input.is_empty() {
            return;
        }
        let cmd = input.to_string();
        let shell = cx.editor.config().shell.clone();
        if shell.is_empty() {
            cx.editor
                .set_error("async-shell-command: no shell configured");
            return;
        }
        cx.editor.set_status(format!("Started (async): {cmd}"));
        cx.jobs.callback(async move {
            let result = shell_impl_async(&shell, &cmd, None).await;
            let call: job::Callback = Callback::EditorCompositor(Box::new(
                move |editor: &mut Editor, _compositor: &mut Compositor| match result {
                    Ok(output) => {
                        show_text_in_scratch(editor, output.as_ref());
                        editor.set_status(format!("Finished: {cmd}"));
                    }
                    Err(err) => editor.set_error(format!("async-shell-command: {err}")),
                },
            ));
            Ok(call)
        });
    });
}

/// Emacs `xref-quit-and-pop-marker-stack` (`M-,` in the xref buffer): close the
/// xref results and jump back to where the search started.
fn xref_quit_and_pop_marker_stack(cx: &mut Context) {
    cx.callback.push(Box::new(|compositor, _cx| {
        compositor.pop();
    }));
    jump_backward(cx);
}

/// Emacs `display-fill-column-indicator-mode`: draw a rule at the fill column, so
/// the column text is filled at is visible. zmax's rulers are the same feature,
/// so the mode toggles a ruler at `text_width` (emacs's `fill-column`).
fn display_fill_column_indicator_mode(cx: &mut Context) {
    let col = cx.editor.config().text_width as u16;
    let mut on = false;
    edit_live_config(cx, |c| {
        if c.rulers.contains(&col) {
            c.rulers.retain(|&r| r != col);
        } else {
            c.rulers.push(col);
            on = true;
        }
    });
    cx.editor.set_status(format!(
        "fill-column indicator (col {col}): {}",
        if on { "on" } else { "off" }
    ));
}

/// Emacs `kill-some-buffers`: offer to kill each buffer in turn — `y` kills it,
/// `n` keeps it, `q` (or any other key) stops asking.
fn kill_some_buffers(cx: &mut Context) {
    let ids: Vec<DocumentId> = cx.editor.documents().map(|d| d.id()).collect();
    kill_some_buffers_step(cx, ids);
}

/// One step of [`kill_some_buffers`]: ask about `ids`' first buffer, then recurse
/// on the rest.
fn kill_some_buffers_step(cx: &mut Context, mut ids: Vec<DocumentId>) {
    let Some(id) = ids.pop() else {
        cx.editor.set_status("kill-some-buffers: done");
        return;
    };
    let Some(doc) = cx.editor.documents.get(&id) else {
        kill_some_buffers_step(cx, ids);
        return;
    };
    let name = doc
        .path()
        .map(|p| p.display().to_string())
        .unwrap_or_else(|| "[scratch]".to_string());
    let modified = doc.is_modified();
    cx.editor.set_status(format!(
        "Kill buffer {name}{}? (y/n/q)",
        if modified { " (modified)" } else { "" }
    ));
    cx.on_next_key(move |cx, event| {
        match event.char() {
            Some('y') | Some('Y') => {
                // Emacs asks again before killing a modified buffer; zmax's
                // close refuses it instead, which is the same protection.
                if cx.editor.close_document(id, false).is_err() {
                    cx.editor.set_error(format!(
                        "kill-some-buffers: {name} is modified — save it first"
                    ));
                    return;
                }
            }
            Some('n') | Some('N') => {}
            _ => {
                cx.editor.set_status("kill-some-buffers: stopped");
                return;
            }
        }
        kill_some_buffers_step(cx, ids);
    });
}

// ---------------------------------------------------------------------------
// Auto-save (emacs `do-auto-save` / `auto-save-mode` / `recover-session`).
// zmax's auto-save file is the vim swap file `crate::vim_swap` writes: it is
// re-written every few changes while `swapfile` is on, removed on a clean save,
// and read back by `:recover` — exactly the role of Emacs's `#file#`.
// ---------------------------------------------------------------------------

/// Emacs `do-auto-save` (M-x): write every modified buffer to its auto-save file
/// now, rather than waiting for the periodic write.
fn do_auto_save(cx: &mut Context) {
    let mut saved = 0;
    let mut skipped = 0;
    for doc in cx.editor.documents() {
        if !doc.is_modified() {
            continue;
        }
        if doc.path().is_none() {
            skipped += 1;
            continue;
        }
        crate::vim_swap::preserve(doc);
        saved += 1;
    }
    cx.editor.set_status(format!(
        "Auto-saving...done ({saved} buffer{}{})",
        if saved == 1 { "" } else { "s" },
        if skipped > 0 {
            format!(", {skipped} unnamed skipped")
        } else {
            String::new()
        }
    ));
}

/// Emacs `auto-save-mode`: turn auto-saving on or off. zmax auto-saves through
/// the vim `swapfile` option, so this flips that — the change hook in
/// `crate::vim_swap` starts (or stops) writing the recovery file.
fn auto_save_mode(cx: &mut Context) {
    let on = !cx.editor.config().swapfile;
    cx.callback.push(Box::new(move |_compositor, cx| {
        match crate::commands::typed::apply_config_value(cx, "swapfile", serde_json::json!(on)) {
            Ok(()) => cx.editor.set_status(format!(
                "Auto-Save mode {}",
                if on { "enabled" } else { "disabled" }
            )),
            Err(e) => cx.editor.set_error(format!("auto-save-mode: {e}")),
        }
    }));
}

/// Every auto-save (swap) file that can be found for the current session: the one
/// beside each open document, plus any other swap file sitting in a directory an
/// open document lives in (a file the crashed session had open but this one has
/// not re-opened). Returns `(original file, swap file)` pairs.
///
/// The `.<name>.swp` layout is the one `crate::vim_swap::swap_path` writes; when
/// a swap `directory` is configured the name is the full path with `/` replaced
/// by `%`, and that is decoded back here.
fn recoverable_files(cx: &Context) -> Vec<(std::path::PathBuf, std::path::PathBuf)> {
    let mut out: Vec<(std::path::PathBuf, std::path::PathBuf)> = Vec::new();
    let mut push = |file: std::path::PathBuf, swap: std::path::PathBuf| {
        if swap.is_file() && !out.iter().any(|(f, _)| *f == file) {
            out.push((file, swap));
        }
    };

    let swap_dir = cx.editor.config().swap_directory.clone();
    if swap_dir.is_empty() {
        // Swap files live beside the file they belong to: scan the directories the
        // open documents are in.
        let mut dirs: Vec<std::path::PathBuf> = cx
            .editor
            .documents()
            .filter_map(|d| d.path()?.parent().map(std::path::Path::to_path_buf))
            .collect();
        if let Ok(cwd) = std::env::current_dir() {
            dirs.push(cwd);
        }
        dirs.sort();
        dirs.dedup();
        for dir in dirs {
            let Ok(entries) = std::fs::read_dir(&dir) else {
                continue;
            };
            for e in entries.flatten() {
                let name = e.file_name().to_string_lossy().into_owned();
                let Some(inner) = name
                    .strip_prefix('.')
                    .and_then(|n| n.strip_suffix(".swp"))
                    .filter(|n| !n.is_empty())
                else {
                    continue;
                };
                push(dir.join(inner), e.path());
            }
        }
    } else {
        let dir = match swap_dir.strip_prefix("~/") {
            Some(rest) => match std::env::var_os("HOME") {
                Some(home) => std::path::PathBuf::from(home).join(rest),
                None => std::path::PathBuf::from(&swap_dir),
            },
            None => std::path::PathBuf::from(&swap_dir),
        };
        let Ok(entries) = std::fs::read_dir(&dir) else {
            return out;
        };
        for e in entries.flatten() {
            let name = e.file_name().to_string_lossy().into_owned();
            let Some(flat) = name
                .strip_prefix('.')
                .and_then(|n| n.strip_suffix(".swp"))
                .filter(|n| !n.is_empty())
            else {
                continue;
            };
            push(std::path::PathBuf::from(flat.replace('%', "/")), e.path());
        }
    }
    out
}

/// Emacs `recover-session`: list the files an interrupted session left auto-save
/// data for, and recover the one chosen — the buffer is opened and its text
/// replaced by the auto-saved text (the recovered buffer is modified, so it is
/// saved only if you save it).
fn recover_session(cx: &mut Context) {
    let files = recoverable_files(cx);
    if files.is_empty() {
        cx.editor
            .set_status("recover-session: no auto-save files to recover from");
        return;
    }
    let columns = [
        PickerColumn::new(
            "file",
            |(f, _): &(std::path::PathBuf, std::path::PathBuf), _: &()| {
                f.display().to_string().into()
            },
        ),
        PickerColumn::new(
            "auto-save",
            |(_, s): &(std::path::PathBuf, std::path::PathBuf), _: &()| {
                s.display().to_string().into()
            },
        ),
    ];
    let picker = Picker::new(columns, 0, files, (), move |cx, (file, swap), _action| {
        let Ok(text) = std::fs::read_to_string(swap) else {
            cx.editor
                .set_error(format!("recover-session: cannot read {}", swap.display()));
            return;
        };
        if let Err(e) = cx.editor.open(file, Action::Replace) {
            cx.editor.set_error(format!("recover-session: {e}"));
            return;
        }
        replace_buffer_text(cx.editor, &text);
        cx.editor.set_status(format!(
            "Recovered {} from its auto-save file — save it to keep the recovery",
            file.display()
        ));
    });
    cx.push_layer(Box::new(overlaid(picker)));
}

/// Replace the whole of the current buffer with `text`, as one undoable change.
fn replace_buffer_text(editor: &mut Editor, text: &str) {
    let (view, doc) = current!(editor);
    let transaction = Transaction::change(
        doc.text(),
        std::iter::once((0, doc.text().len_chars(), Some(text.into()))),
    );
    doc.apply(&transaction, view.id);
    doc.append_changes_to_history(view);
}

// ---------------------------------------------------------------------------
// Optional mode-line constructs (emacs `line-number-mode`, `size-indication-mode`,
// `display-time`, `display-battery-mode`). Each is a flag read by
// `ui::statusline::render` — the same wiring `which-function-mode` uses — so
// toggling one changes what the status line draws on the next frame.
// ---------------------------------------------------------------------------

/// `line-number-mode`: whether the cursor position is shown. On by default, as
/// in Emacs.
fn line_number_flag() -> &'static std::sync::atomic::AtomicBool {
    static F: std::sync::atomic::AtomicBool = std::sync::atomic::AtomicBool::new(true);
    &F
}

/// Whether the status line should draw the `Position` element (line:column).
pub(crate) fn line_number_mode_enabled() -> bool {
    line_number_flag().load(std::sync::atomic::Ordering::Relaxed)
}

/// Emacs `line-number-mode`: toggle display of the line number (zmax's status
/// line draws the line and column together, so the whole position indicator
/// comes and goes).
fn line_number_mode(cx: &mut Context) {
    let on = !line_number_flag().fetch_xor(true, std::sync::atomic::Ordering::Relaxed);
    cx.editor.set_status(format!(
        "Line-Number mode {}",
        if on { "enabled" } else { "disabled" }
    ));
}

/// `size-indication-mode`: whether the buffer's size is shown.
fn size_indication_flag() -> &'static std::sync::atomic::AtomicBool {
    static F: std::sync::atomic::AtomicBool = std::sync::atomic::AtomicBool::new(false);
    &F
}

/// Whether the status line should draw the buffer size.
pub(crate) fn size_indication_enabled() -> bool {
    size_indication_flag().load(std::sync::atomic::Ordering::Relaxed)
}

/// Emacs `size-indication-mode`: toggle display of the buffer's size in the mode
/// line (`of 12k`, as Emacs writes it).
fn size_indication_mode(cx: &mut Context) {
    let on = !size_indication_flag().fetch_xor(true, std::sync::atomic::Ordering::Relaxed);
    cx.editor.set_status(format!(
        "Size-Indication mode {}",
        if on { "enabled" } else { "disabled" }
    ));
}

/// Emacs's `size-indication-mode` text for a buffer of `bytes` bytes: Emacs
/// prints the size the way `ls -h` does — `of 913`, `of 12k`, `of 3.4M`.
pub(crate) fn buffer_size_text(bytes: usize) -> String {
    const K: usize = 1024;
    if bytes < K {
        format!("of {bytes}")
    } else if bytes < K * K {
        format!("of {}k", bytes / K)
    } else {
        format!("of {:.1}M", bytes as f64 / (K * K) as f64)
    }
}

/// `display-time-mode`: whether the clock is shown.
fn display_time_flag() -> &'static std::sync::atomic::AtomicBool {
    static F: std::sync::atomic::AtomicBool = std::sync::atomic::AtomicBool::new(false);
    &F
}

/// The clock text for the mode line (`HH:MM`, local time), or `None` when
/// `display-time` is off.
pub(crate) fn display_time_text() -> Option<String> {
    if !display_time_flag().load(std::sync::atomic::Ordering::Relaxed) {
        return None;
    }
    let now = time::OffsetDateTime::now_local().unwrap_or_else(|_| time::OffsetDateTime::now_utc());
    Some(format!("{:02}:{:02}", now.hour(), now.minute()))
}

/// Emacs `display-time`: show the time of day in the mode line.
fn display_time(cx: &mut Context) {
    let on = !display_time_flag().fetch_xor(true, std::sync::atomic::Ordering::Relaxed);
    cx.editor.set_status(format!(
        "Display-Time mode {}",
        if on { "enabled" } else { "disabled" }
    ));
}

/// `display-battery-mode`: the last battery percentage the poller read (-1 =
/// unknown / not polled yet).
fn battery_level() -> &'static std::sync::atomic::AtomicI32 {
    static L: std::sync::atomic::AtomicI32 = std::sync::atomic::AtomicI32::new(-1);
    &L
}

/// Whether the battery poller thread is running (and so whether the mode is on).
fn battery_flag() -> &'static std::sync::atomic::AtomicBool {
    static F: std::sync::atomic::AtomicBool = std::sync::atomic::AtomicBool::new(false);
    &F
}

/// Read the battery charge percentage from the OS: `pmset -g batt` on macOS,
/// `/sys/class/power_supply/BAT*/capacity` on Linux. `None` when there is no
/// battery (a desktop, a VM) or the reading cannot be parsed.
fn read_battery_percent() -> Option<u8> {
    #[cfg(target_os = "macos")]
    {
        let out = std::process::Command::new("pmset")
            .args(["-g", "batt"])
            .output()
            .ok()?;
        let text = String::from_utf8_lossy(&out.stdout);
        // "...InternalBattery-0 (id=…)\t85%; discharging; 3:41 remaining present: true"
        let pct = text
            .split('\t')
            .nth(1)?
            .split('%')
            .next()?
            .trim()
            .to_string();
        pct.parse::<u8>().ok()
    }
    #[cfg(target_os = "linux")]
    {
        let dir = std::fs::read_dir("/sys/class/power_supply").ok()?;
        for entry in dir.flatten() {
            let name = entry.file_name();
            if !name.to_string_lossy().starts_with("BAT") {
                continue;
            }
            if let Ok(s) = std::fs::read_to_string(entry.path().join("capacity")) {
                if let Ok(n) = s.trim().parse::<u8>() {
                    return Some(n);
                }
            }
        }
        None
    }
    #[cfg(not(any(target_os = "macos", target_os = "linux")))]
    {
        None
    }
}

/// The battery text for the mode line (`85%`), or `None` when the mode is off or
/// the machine has no battery.
pub(crate) fn display_battery_text() -> Option<String> {
    if !battery_flag().load(std::sync::atomic::Ordering::Relaxed) {
        return None;
    }
    match battery_level().load(std::sync::atomic::Ordering::Relaxed) {
        n if n >= 0 => Some(format!("{n}%")),
        _ => None,
    }
}

/// Emacs `display-battery-mode`: show the battery charge in the mode line. A
/// background thread re-reads the OS every 60 seconds (and asks for a redraw)
/// while the mode is on, so the status line render never blocks on `pmset`.
fn display_battery_mode(cx: &mut Context) {
    use std::sync::atomic::Ordering;
    let on = !battery_flag().fetch_xor(true, Ordering::Relaxed);
    if !on {
        cx.editor.set_status("Display-Battery mode disabled");
        return;
    }
    // One poller at a time: a thread that is still in its sleep when the mode is
    // turned off and on again keeps serving, instead of a second one starting.
    static POLLING: std::sync::atomic::AtomicBool = std::sync::atomic::AtomicBool::new(false);
    if !POLLING.swap(true, Ordering::Relaxed) {
        std::thread::spawn(|| {
            while battery_flag().load(Ordering::Relaxed) {
                let level = read_battery_percent().map(i32::from).unwrap_or(-1);
                battery_level().store(level, Ordering::Relaxed);
                zmax_event::request_redraw();
                std::thread::sleep(std::time::Duration::from_secs(60));
            }
            POLLING.store(false, Ordering::Relaxed);
        });
    }
    cx.editor.set_status("Display-Battery mode enabled");
}

// ── frames (emacs C-x 5) ────────────────────────────────────────────────────
//
// A frame on a *text terminal* — which is what zmax is — is a whole window
// layout that owns the terminal while it is displayed; emacs creates them with
// `make-frame`, shows one at a time, and swaps between them with `C-x 5 o`.
// zmax_view::Editor keeps the parked ones in `frames` (each a tab-set with its
// own splits), and switching rebuilds the live tree from the target. The
// commands below are the `C-x 5` map.

/// emacs `make-frame-command` (`C-x 5 2`): a new frame showing this buffer.
fn make_frame_command(cx: &mut Context) {
    let doc = doc!(cx.editor).id();
    cx.editor.new_frame(doc, None);
}

/// emacs `clone-frame` (`C-x 5 c`): a new frame with a copy of this frame's
/// whole layout — every tab, every split, the same buffers.
fn clone_frame(cx: &mut Context) {
    cx.editor.clone_frame();
}

/// emacs `delete-frame` (`C-x 5 0`): close the displayed frame and show another.
fn delete_frame(cx: &mut Context) {
    cx.editor.delete_frame();
}

/// emacs `delete-other-frames` (`C-x 5 1`): close every frame but this one.
fn delete_other_frames(cx: &mut Context) {
    let n = cx.editor.delete_other_frames();
    cx.editor.set_status(format!("deleted {n} other frame(s)"));
}

/// emacs `other-frame` (`C-x 5 o`): display the next frame (wraps).
fn other_frame(cx: &mut Context) {
    let n = cx.editor.frame_count();
    if n < 2 {
        cx.editor.set_status("only one frame");
        return;
    }
    let next = (cx.editor.current_frame() + cx.count()) % n;
    cx.editor.switch_frame(next);
}

/// emacs `undelete-frame`: bring back the frame most recently deleted while
/// `undelete-frame-mode` was on. With the mode off, emacs records nothing and
/// there is nothing to bring back — same here.
fn undelete_frame(cx: &mut Context) {
    if !cx.editor.undelete_frame_mode {
        cx.editor
            .set_error("undelete-frame: undelete-frame-mode is not enabled");
        return;
    }
    if !cx.editor.undelete_frame() {
        cx.editor.set_error("undelete-frame: no deleted frame");
    }
}

/// emacs `undelete-frame-mode`: start (or stop) recording deleted frames, which
/// is what makes `undelete-frame` able to bring one back.
fn undelete_frame_mode(cx: &mut Context) {
    let on = !cx.editor.undelete_frame_mode;
    cx.editor.undelete_frame_mode = on;
    if !on {
        cx.editor.closed_frames.clear();
    }
    cx.editor.set_status(if on {
        "Undelete-Frame mode enabled"
    } else {
        "Undelete-Frame mode disabled"
    });
}

/// emacs `set-frame-name`: rename the displayed frame (the name
/// `select-frame-by-name` looks up).
fn set_frame_name(cx: &mut Context) {
    prompt_then(cx, "Frame name: ", |cx, input| {
        if input.is_empty() {
            cx.editor.set_error("set-frame-name: empty name");
            return;
        }
        cx.editor.rename_current_frame(input.to_string());
        cx.editor.set_status(format!("frame renamed to {input}"));
    });
}

/// emacs `select-frame-by-name`: pick a frame by name and display it.
fn select_frame_by_name(cx: &mut Context) {
    let docs = cx.editor.frame_focused_docs();
    let names = cx.editor.frame_names();
    let current = cx.editor.current_frame();
    struct FrameMeta {
        index: usize,
        name: String,
        buffer: String,
        is_current: bool,
    }
    let items: Vec<FrameMeta> = names
        .into_iter()
        .map(|(index, name)| FrameMeta {
            index,
            name,
            buffer: docs
                .get(index)
                .and_then(|id| cx.editor.documents.get(id))
                .map(|d| d.display_name().into_owned())
                .unwrap_or_default(),
            is_current: index == current,
        })
        .collect();
    let columns = [
        PickerColumn::new("frame", |m: &FrameMeta, _: &()| m.name.clone().into()),
        PickerColumn::new("buffer", |m: &FrameMeta, _: &()| m.buffer.clone().into()),
        PickerColumn::new("", |m: &FrameMeta, _: &()| {
            if m.is_current { "*" } else { "" }.into()
        }),
    ];
    let picker = Picker::new(columns, 0, items, (), |cx, meta, _action| {
        cx.editor.switch_frame(meta.index);
    });
    cx.push_layer(Box::new(overlaid(picker)));
}

/// emacs `find-file-other-frame` (`C-x 5 f`): pick a file; it opens in a new
/// frame. Arming `pending_display` is exactly emacs's own mechanism — the frame
/// is created by the buffer display, not by the file picker.
fn find_file_other_frame(cx: &mut Context) {
    cx.editor.pending_display = Some(zmax_view::editor::DisplayTarget::Frame);
    file_picker(cx);
}

/// emacs `find-file-read-only-other-frame` (`C-x 5 r`): the same, and the buffer
/// arrives read-only.
fn find_file_read_only_other_frame(cx: &mut Context) {
    let prompt = crate::ui::prompt::Prompt::new(
        "Find file read-only other frame: ".into(),
        None,
        ui::completers::filename,
        move |cx: &mut crate::compositor::Context, input: &str, ev: PromptEvent| {
            if ev != PromptEvent::Validate {
                return;
            }
            let path = zmax_stdx::path::expand_tilde(Path::new(input.trim()));
            cx.editor.pending_display = Some(zmax_view::editor::DisplayTarget::Frame);
            match cx.editor.open(&path, Action::Replace) {
                Ok(_) => {
                    doc_mut!(cx.editor).readonly = true;
                    cx.editor
                        .set_status(format!("{} (read-only, new frame)", path.display()));
                }
                Err(e) => {
                    cx.editor.pending_display = None;
                    cx.editor.set_error(format!("{}: {e}", path.display()));
                }
            }
        },
    );
    cx.push_layer(Box::new(prompt));
}

/// emacs `switch-to-buffer-other-frame` (`C-x 5 b`): pick a buffer; it is
/// displayed in a new frame.
fn switch_to_buffer_other_frame(cx: &mut Context) {
    cx.editor.pending_display = Some(zmax_view::editor::DisplayTarget::Frame);
    buffer_picker(cx);
}

/// emacs `dired-other-frame` (`C-x 5 d`): a new frame, with Dired over it.
fn dired_other_frame(cx: &mut Context) {
    let doc = doc!(cx.editor).id();
    cx.editor.new_frame(doc, None);
    dired(cx);
}

/// emacs `other-frame-prefix` (`C-x 5 5`): the buffer the *next* command
/// displays goes into a new frame.
fn other_frame_prefix(cx: &mut Context) {
    cx.editor.pending_display = Some(zmax_view::editor::DisplayTarget::Frame);
    cx.editor
        .set_status("the next buffer display will make a new frame");
}

/// emacs `other-window-prefix` (`C-x 4 4`): the buffer the *next* command
/// displays goes into another window (a split) instead of this one.
fn other_window_prefix(cx: &mut Context) {
    cx.editor.pending_display = Some(zmax_view::editor::DisplayTarget::Window);
    cx.editor
        .set_status("the next buffer display will use another window");
}

/// emacs `other-tab-prefix` (`C-x t t`): the buffer the *next* command displays
/// goes into a new tab.
fn other_tab_prefix(cx: &mut Context) {
    cx.editor.pending_display = Some(zmax_view::editor::DisplayTarget::Tab);
    cx.editor
        .set_status("the next buffer display will make a new tab");
}

/// emacs `display-buffer`: show a buffer in *another* window without selecting
/// it — the window you are typing in does not change, which is the whole point
/// (`switch-to-buffer` is the one that moves you). A `C-u` prefix (any count > 1)
/// makes it a new frame instead, the way emacs's display-buffer action alist
/// can be told to pop up a frame.
fn display_buffer(cx: &mut Context) {
    let other_frame = cx.count() > 1;
    let prompt = crate::ui::prompt::Prompt::new(
        "Display buffer: ".into(),
        None,
        ui::completers::buffer,
        move |cx: &mut crate::compositor::Context, input: &str, ev: PromptEvent| {
            if ev != PromptEvent::Validate {
                return;
            }
            let input = input.trim();
            let Some(id) = cx
                .editor
                .documents()
                .find(|d| d.display_name().as_ref() == input)
                .map(|d| d.id())
            else {
                cx.editor
                    .set_error(format!("display-buffer: no open buffer named {input}"));
                return;
            };
            if other_frame {
                let selected = cx.editor.tree.focus;
                cx.editor.new_frame(id, None);
                // A frame is its own terminal-sized window; emacs selects the
                // new frame's window here only with `select-frame-set-input-focus`,
                // so stay where the user was by going back to the old frame.
                let _ = selected;
                return;
            }
            let selected = cx.editor.tree.focus;
            cx.editor.switch(id, Action::VerticalSplit);
            cx.editor.focus(selected);
            cx.editor
                .set_status(format!("displaying {input} in another window"));
        },
    );
    cx.push_layer(Box::new(prompt));
}

// ── the zmax server (emacs `server-start` / `emacsclient`) ─────────────────
//
// `server-start` opens a Unix socket; a client connects, sends a request, and —
// for a file — *blocks* until the user says "done with this one" with
// `server-edit` (`C-x #`). That blocking handshake is the whole reason the
// server exists, so it is what is implemented: the socket lives in the terminal
// event loop (application.rs, which is what can `accept()`), and the waiting
// clients live on the Editor, where these commands can release them.
//
// Wire protocol (one request, `\n`-separated, terminated by a blank line):
//
//     -auth <key>          (required iff the server has an auth key)
//     -dir <directory>     (optional; relative -file paths resolve against it)
//     -file <path>[:LINE[:COL]]
//     -eval <expression>   (elisp, evaluated in this editor)
//     -nowait              (do not block; reply "done" at once)
//     <blank line>
//
// Replies: `done`, `abort`, `ok <value>` (for -eval) or `error <reason>`.

/// The directory the server socket lives in: `$XDG_RUNTIME_DIR/zmax/`, else
/// `$TMPDIR/zmax<uid>/` — the same shape as emacs's `server-socket-dir`.
#[cfg(unix)]
pub(crate) fn server_socket_dir() -> PathBuf {
    if let Some(run) = std::env::var_os("XDG_RUNTIME_DIR") {
        return PathBuf::from(run).join("zmax");
    }
    let uid = unsafe { libc::getuid() };
    std::env::temp_dir().join(format!("zmax{uid}"))
}

/// emacs `server-start` (and `server-force-delete` when it finds a dead socket):
/// listen on `$XDG_RUNTIME_DIR/zmax/<server-name>` so clients can hand files
/// to this editor. Called again while running, it stops the server, as emacs's
/// `C-u M-x server-start` does.
#[cfg(unix)]
fn server_start(cx: &mut Context) {
    if cx.editor.server.is_some() {
        server_stop(cx);
        return;
    }
    let name = "server".to_string();
    let dir = server_socket_dir();
    if let Err(e) = std::fs::create_dir_all(&dir) {
        cx.editor
            .set_error(format!("server-start: {}: {e}", dir.display()));
        return;
    }
    let socket = dir.join(&name);
    // A socket left behind by a crashed editor: if nothing is listening on it,
    // it is stale and emacs deletes it (`server-force-delete`).
    if socket.exists() && std::os::unix::net::UnixStream::connect(&socket).is_err() {
        let _ = std::fs::remove_file(&socket);
    }
    let listener = match std::os::unix::net::UnixListener::bind(&socket) {
        Ok(l) => l,
        Err(e) => {
            cx.editor
                .set_error(format!("server-start: {}: {e}", socket.display()));
            return;
        }
    };
    if let Err(e) = listener.set_nonblocking(true) {
        cx.editor.set_error(format!("server-start: {e}"));
        return;
    }
    cx.editor.server = Some(zmax_view::editor::ServerState {
        name,
        socket: socket.clone(),
        auth_key: None,
        clients: Vec::new(),
        next_client_id: 1,
    });
    // Hand the listening socket to the event loop, which owns the `select!`.
    crate::application::set_pending_server_listener(listener);
    cx.editor
        .set_status(format!("server started on {}", socket.display()));
}

#[cfg(not(unix))]
fn server_start(cx: &mut Context) {
    cx.editor
        .set_error("server-start: the zmax server needs a Unix socket");
}

/// Stop the server: release every blocked client and unlink the socket.
#[cfg(unix)]
fn server_stop(cx: &mut Context) {
    let Some(mut server) = cx.editor.server.take() else {
        return;
    };
    server.release_all(true);
    let _ = std::fs::remove_file(&server.socket);
    crate::application::stop_server_listener();
    cx.editor.set_status("server stopped");
}

/// emacs `server-edit` (`C-x #`): "I am done with this buffer" — save it and let
/// the `emacsclient` that is blocked on it return. With no client waiting on it,
/// emacs just saves and says so.
#[cfg(unix)]
fn server_edit(cx: &mut Context) {
    server_finish(cx, false);
}

#[cfg(not(unix))]
fn server_edit(cx: &mut Context) {
    cx.editor.set_error("server-edit: no server");
}

/// emacs `server-edit-abort`: give up on the buffer — the client is told the
/// edit was abandoned, and nothing is saved.
#[cfg(unix)]
fn server_edit_abort(cx: &mut Context) {
    server_finish(cx, true);
}

#[cfg(not(unix))]
fn server_edit_abort(cx: &mut Context) {
    cx.editor.set_error("server-edit-abort: no server");
}

#[cfg(unix)]
fn server_finish(cx: &mut Context, abort: bool) {
    if cx.editor.server.is_none() {
        cx.editor.set_error("server-edit: no server running");
        return;
    }
    let doc = doc!(cx.editor).id();
    if !abort {
        // emacs saves the buffer before releasing the client — the client's whole
        // reason to wait is to read the file back.
        if doc!(cx.editor).is_modified() {
            if let Err(e) = write_document_blocking(cx, doc) {
                cx.editor.set_error(format!("server-edit: {e}"));
                return;
            }
        }
    }
    let released = cx
        .editor
        .server
        .as_mut()
        .map(|s| s.finish_doc(doc, abort))
        .unwrap_or(0);
    if released == 0 {
        cx.editor
            .set_status("no client is waiting for this buffer (saved)");
        return;
    }
    // The client has the file back; the buffer it was given goes away, like
    // emacs's `server-buffer-done` killing the buffer it created.
    cx.editor.close_document(doc, true).ok();
    cx.editor.set_status(format!(
        "{released} client(s) released{}",
        if abort { " (aborted)" } else { "" }
    ));
}

/// Save `doc` now, synchronously — `server-edit` must not release the client
/// before the bytes are on disk, because the client reads the file immediately.
#[cfg(unix)]
fn write_document_blocking(cx: &mut Context, doc: DocumentId) -> anyhow::Result<()> {
    cx.editor.save::<PathBuf>(doc, None, false)?;
    cx.block_try_flush_writes()
}

/// emacs `server-generate-key`: mint the shared secret a client must present.
/// A client that does not send `-auth <key>` is refused from then on, and the
/// key is written to the server file next to the socket so a client can read it.
#[cfg(unix)]
fn server_generate_key(cx: &mut Context) {
    let Some(server) = cx.editor.server.as_mut() else {
        cx.editor
            .set_error("server-generate-key: no server running (M-x server-start)");
        return;
    };
    // 64 characters of real entropy, as emacs's `server-generate-key` produces
    // (it reads from a secure source, not from the pid/clock — and so do we).
    let mut bytes = [0u8; 64];
    match std::fs::File::open("/dev/urandom").and_then(|mut f| {
        use std::io::Read as _;
        f.read_exact(&mut bytes)
    }) {
        Ok(()) => {}
        Err(e) => {
            cx.editor
                .set_error(format!("server-generate-key: /dev/urandom: {e}"));
            return;
        }
    }
    const ALPHABET: &[u8; 64] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-_";
    let key: String = bytes
        .iter()
        .map(|b| ALPHABET[(*b & 0x3f) as usize] as char)
        .collect();
    let key_file = server.socket.with_extension("key");
    server.auth_key = Some(key.clone());
    let written = std::fs::write(&key_file, format!("{}\n{key}\n", server.socket.display()));
    match written {
        Ok(()) => {
            let _ = std::fs::set_permissions(
                &key_file,
                <std::fs::Permissions as std::os::unix::fs::PermissionsExt>::from_mode(0o600),
            );
            cx.editor.set_status(format!(
                "server key written to {} — clients must send -auth",
                key_file.display()
            ));
        }
        Err(e) => cx
            .editor
            .set_error(format!("server-generate-key: {}: {e}", key_file.display())),
    }
}

#[cfg(not(unix))]
fn server_generate_key(cx: &mut Context) {
    cx.editor
        .set_error("server-generate-key: the zmax server needs a Unix socket");
}

/// emacs `server-eval-at`: evaluate an expression in *another* editor — connect
/// to that server's socket as a client, send `-eval`, and report what it says.
#[cfg(unix)]
fn server_eval_at(cx: &mut Context) {
    prompt_then(cx, "server-eval-at (SERVER FORM): ", |cx, input| {
        let (server, form) = split_first_word(input);
        if server.is_empty() || form.is_empty() {
            cx.editor
                .set_error("server-eval-at: give a server name and an expression");
            return;
        }
        let socket = server_socket_dir().join(server);
        match server_eval_request(&socket, form) {
            Ok(reply) => cx.editor.set_status(reply),
            Err(e) => cx.editor.set_error(format!("server-eval-at: {e}")),
        }
    });
}

#[cfg(not(unix))]
fn server_eval_at(cx: &mut Context) {
    cx.editor
        .set_error("server-eval-at: the zmax server needs a Unix socket");
}

/// Connect to a zmax server socket, send an `-eval` request, and return its
/// one-line reply. The key file written by `server-generate-key` is read (if it
/// is there) so an authenticated server can be talked to.
#[cfg(unix)]
fn server_eval_request(socket: &Path, form: &str) -> anyhow::Result<String> {
    use std::io::{BufRead, BufReader, Write};
    let mut stream = std::os::unix::net::UnixStream::connect(socket)
        .with_context(|| format!("{}", socket.display()))?;
    stream.set_read_timeout(Some(std::time::Duration::from_secs(10)))?;
    let mut req = String::new();
    if let Ok(key_file) = std::fs::read_to_string(socket.with_extension("key")) {
        if let Some(key) = key_file.lines().nth(1) {
            req.push_str(&format!("-auth {key}\n"));
        }
    }
    req.push_str(&format!("-eval {form}\n\n"));
    stream.write_all(req.as_bytes())?;
    stream.flush()?;
    let mut reply = String::new();
    BufReader::new(&stream).read_line(&mut reply)?;
    let reply = reply.trim().to_string();
    if reply.is_empty() {
        anyhow::bail!("no reply");
    }
    Ok(reply)
}

// ── mouse commands (emacs `mouse-*`) ────────────────────────────────────────
//
// Every emacs mouse command reads the click out of the event it was invoked
// with (`(interactive "e")`). zmax records the last mouse position that landed
// on text (`Editor::last_mouse_pos`, set in ui::editor's mouse handler, which
// then *dispatches through these commands*) — so these are the real handlers for
// the mouse, not a re-implementation beside it, and they can also be run from a
// key or `M-x`, acting on the last click.

/// The last click's position in the current document, or point when the mouse
/// has not been used (or was last used in another buffer).
fn click_pos(editor: &Editor) -> usize {
    let (view, doc) = current_ref!(editor);
    match editor.last_mouse_pos {
        Some((id, pos)) if id == doc.id() => pos.min(doc.text().len_chars()),
        _ => doc
            .selection(view.id)
            .primary()
            .cursor(doc.text().slice(..)),
    }
}

/// emacs `mouse-set-point` (mouse-1): move point to the click.
pub(crate) fn mouse_set_point(cx: &mut Context) {
    let pos = click_pos(cx.editor);
    let (view, doc) = current!(cx.editor);
    doc.set_selection(view.id, Selection::point(pos));
    let id = view.id;
    cx.editor.ensure_cursor_in_view(id);
}

/// vim `<C-LeftMouse>` / `g<LeftMouse>`: jump to the tag (definition) of the
/// symbol at the last click — move point to the click, then go to definition.
pub(crate) fn mouse_goto_tag(cx: &mut Context) {
    mouse_set_point(cx);
    goto_definition(cx);
}

/// vim `<C-RightMouse>` / `g<RightMouse>` (CTRL-T): pop the tag/jump stack back
/// to where the last jump started.
pub(crate) fn mouse_pop_tag(cx: &mut Context) {
    jump_backward(cx);
}

/// vim `<S-LeftMouse>`: `*` at the click — search forward for the word there.
/// `search_selection_impl` expands the bare cursor the click leaves to the whole
/// word, which is what makes this `*` and not a single-character search.
pub(crate) fn mouse_search_word_forward(cx: &mut Context) {
    mouse_set_point(cx);
    search_selection_detect_word_boundaries(cx);
    search_next(cx);
}

/// vim `<S-RightMouse>`: `#` at the click — search backward for the word there.
pub(crate) fn mouse_search_word_backward(cx: &mut Context) {
    mouse_set_point(cx);
    search_selection_detect_word_boundaries(cx);
    search_prev(cx);
}

/// vim `[<MiddleMouse>`: `[p` at the click — paste before it.
pub(crate) fn mouse_paste_before(cx: &mut Context) {
    mouse_set_point(cx);
    paste_before(cx);
}

/// vim `]<MiddleMouse>`: `]p` at the click — paste after it.
pub(crate) fn mouse_paste_after(cx: &mut Context) {
    mouse_set_point(cx);
    paste_after(cx);
}

/// vim `mousescroll=hor:N`: how many columns one horizontal wheel tick moves the
/// window. Pure — unit tested.
fn mousescroll_cols(spec: &str) -> Option<usize> {
    spec.split(',').find_map(|part| {
        let (axis, n) = part.trim().split_once(':')?;
        (axis.trim() == "hor").then(|| n.trim().parse().ok())?
    })
}

/// The configured horizontal tick, falling back to vim's `hor:6` default.
fn mousescroll_cols_opt() -> usize {
    vim_opt_str("mousescroll")
        .and_then(|spec| mousescroll_cols(&spec))
        .unwrap_or(6)
}

/// Shift the focused view sideways. Moves the viewport only — the cursor stays
/// put, which is why no caller runs `ensure_cursor_in_view` afterwards (it would
/// snap the offset straight back).
fn scroll_view_horizontally(cx: &mut Context, cols: usize, right: bool) {
    let view_id = cx.editor.tree.focus;
    let doc_id = cx.editor.tree.get(view_id).doc;
    let doc = doc_mut!(cx.editor, &doc_id);
    let mut offset = doc.view_offset(view_id);
    offset.horizontal_offset = if right {
        offset.horizontal_offset.saturating_add(cols)
    } else {
        offset.horizontal_offset.saturating_sub(cols)
    };
    doc.set_view_offset(view_id, offset);
}

/// vim `<ScrollWheelLeft>`: move the window `mousescroll=hor:N` columns left.
pub(crate) fn mouse_scroll_left(cx: &mut Context) {
    scroll_view_horizontally(cx, mousescroll_cols_opt(), false);
}

/// vim `<ScrollWheelRight>`: move the window `mousescroll=hor:N` columns right.
pub(crate) fn mouse_scroll_right(cx: &mut Context) {
    scroll_view_horizontally(cx, mousescroll_cols_opt(), true);
}

/// vim `<S-ScrollWheelLeft>`: move the window one page left.
pub(crate) fn mouse_scroll_page_left(cx: &mut Context) {
    let cols = page_width(cx);
    scroll_view_horizontally(cx, cols, false);
}

/// vim `<S-ScrollWheelRight>`: move the window one page right.
pub(crate) fn mouse_scroll_page_right(cx: &mut Context) {
    let cols = page_width(cx);
    scroll_view_horizontally(cx, cols, true);
}

fn page_width(cx: &mut Context) -> usize {
    let (view, doc) = current_ref!(cx.editor);
    view.inner_width(doc) as usize
}

/// vim `<S-ScrollWheelUp>`: move the window one page up.
pub(crate) fn mouse_scroll_page_up(cx: &mut Context) {
    let offset = view!(cx.editor).inner_height();
    scroll(cx, offset, Direction::Backward, false);
}

/// vim `<S-ScrollWheelDown>`: move the window one page down.
pub(crate) fn mouse_scroll_page_down(cx: &mut Context) {
    let offset = view!(cx.editor).inner_height();
    scroll(cx, offset, Direction::Forward, false);
}

/// emacs `mouse-set-region` (drag mouse-1): the region runs from where the drag
/// started to the click.
pub(crate) fn mouse_set_region(cx: &mut Context) {
    let pos = click_pos(cx.editor);
    let (view, doc) = current!(cx.editor);
    let text = doc.text().slice(..);
    let anchor = doc
        .selection(view.id)
        .primary()
        .anchor
        .min(text.len_chars());
    doc.set_selection(view.id, Selection::single(anchor, pos));
    let id = view.id;
    cx.editor.mode = Mode::Select;
    cx.editor.ensure_cursor_in_view(id);
}

/// emacs `mouse-save-then-kill` (mouse-3): the first press extends the region to
/// the click and copies it; a second press at the same place kills it.
pub(crate) fn mouse_save_then_kill(cx: &mut Context) {
    let pos = click_pos(cx.editor);
    let register = cx.editor.config().mouse_yank_register;
    let (view, doc) = current!(cx.editor);
    let primary = doc.selection(view.id).primary();
    let already_there = primary.head == pos && primary.from() != primary.to();
    if already_there {
        // Second press at the same spot: kill the region it saved.
        delete_selection(cx);
        cx.editor.set_status("mouse-save-then-kill: region killed");
        return;
    }
    let text = doc.text().slice(..);
    let extended = primary.put_cursor(text, pos, true);
    doc.set_selection(view.id, Selection::single(extended.anchor, extended.head));
    let id = view.id;
    cx.editor.mode = Mode::Select;
    cx.editor.ensure_cursor_in_view(id);
    yank_main_selection_to_register(cx.editor, register);
}

/// emacs `mouse-yank-at-click` (mouse-2): point moves to the click and the kill
/// ring's top is inserted there.
pub(crate) fn mouse_yank_at_click(cx: &mut Context) {
    mouse_set_point(cx);
    let register = cx.editor.config().mouse_yank_register;
    let count = cx.count();
    paste(cx.editor, register, Paste::Before, count);
}

/// emacs `mouse-yank-primary`: insert the *primary selection* (the X selection a
/// drag leaves behind — zmax's mouse yank register) at point, without moving
/// point to the click.
pub(crate) fn mouse_yank_primary(cx: &mut Context) {
    let register = cx.editor.config().mouse_yank_register;
    let count = cx.count();
    paste(cx.editor, register, Paste::Before, count);
}

/// emacs `mouse-wheel-mode`: turn wheel scrolling on or off. Read by the mouse
/// handler in `ui::editor`, so turning it off really does stop the wheel.
fn mouse_wheel_mode(cx: &mut Context) {
    let on = !cx.editor.mouse_wheel_mode;
    cx.editor.mouse_wheel_mode = on;
    cx.editor.set_status(if on {
        "Mouse-Wheel mode enabled"
    } else {
        "Mouse-Wheel mode disabled"
    });
}

/// emacs `mouse-buffer-menu` (C-mouse-1): the buffer menu, from the mouse.
fn mouse_buffer_menu(cx: &mut Context) {
    buffer_picker(cx);
}

/// emacs `browse-url-at-mouse`: open the URL under the last click in the
/// external browser (`goto-address` finds the URL under a position).
fn browse_url_at_mouse(cx: &mut Context) {
    let pos = click_pos(cx.editor);
    let doc = doc!(cx.editor);
    let text = doc.text();
    let line_idx = text.char_to_line(pos.min(text.len_chars()));
    let line_start = text.line_to_char(line_idx);
    let line = text.line(line_idx).to_string();
    // The click's byte offset within the line, matched against the byte ranges
    // `goto_address::addresses` reports.
    let byte = line
        .char_indices()
        .nth(pos.saturating_sub(line_start))
        .map(|(b, _)| b)
        .unwrap_or(line.len());
    let found = zmax_core::goto_address::addresses(&line)
        .into_iter()
        .find(|a| a.range.contains(&byte))
        .map(|a| a.target(&line));
    let Some(url) = found else {
        cx.editor
            .set_error("browse-url-at-mouse: no URL under the mouse");
        return;
    };
    match open::that(&url) {
        Ok(()) => cx.editor.set_status(format!("browsing {url}")),
        Err(e) => cx.editor.set_error(format!("browse-url-at-mouse: {e}")),
    }
}

// ── the secondary selection (emacs `mouse-*-secondary`) ──────────────────────
//
// Emacs's secondary selection is a *second* region that does not move when point
// does, is shown in its own face, and is yanked with `mouse-yank-secondary`.
// zmax keeps the range on the Editor and paints it with the
// `secondary-selection` face text property, so it is visible and it tracks edits
// (the text-property layer maps its boundaries through every ChangeSet).

/// The face the secondary selection is painted with.
fn secondary_face() -> zmax_core::text_props::Face {
    zmax_core::text_props::Face::named("secondary-selection")
}

/// Drop whatever the secondary selection was painted over.
fn clear_secondary(editor: &mut Editor) {
    let Some((doc_id, range)) = editor.secondary_selection.take() else {
        return;
    };
    if let Some(doc) = editor.documents.get_mut(&doc_id) {
        let (from, to) = (range.from(), range.to());
        doc.update_text_props(|props| props.remove_face(from..to));
    }
}

/// emacs `mouse-start-secondary` (M-mouse-1 down): anchor the secondary
/// selection at the click.
pub(crate) fn mouse_start_secondary(cx: &mut Context) {
    clear_secondary(cx.editor);
    let pos = click_pos(cx.editor);
    let id = doc!(cx.editor).id();
    cx.editor.secondary_anchor = Some((id, pos));
    cx.editor.set_status("secondary selection started");
}

/// emacs `mouse-set-secondary` (M-drag-mouse-1): the secondary selection runs
/// from the anchor to the click.
pub(crate) fn mouse_set_secondary(cx: &mut Context) {
    let pos = click_pos(cx.editor);
    let id = doc!(cx.editor).id();
    let anchor = match cx.editor.secondary_anchor {
        Some((doc_id, anchor)) if doc_id == id => anchor,
        _ => {
            cx.editor
                .set_error("mouse-set-secondary: no secondary selection started");
            return;
        }
    };
    clear_secondary(cx.editor);
    let range = Range::new(anchor, pos);
    if range.from() == range.to() {
        cx.editor.set_status("secondary selection is empty");
        return;
    }
    let (from, to) = (range.from(), range.to());
    let face = secondary_face();
    let doc = doc_mut!(cx.editor);
    doc.update_text_props(|props| props.add_face(from..to, &face));
    cx.editor.secondary_selection = Some((id, range));
    cx.editor
        .set_status(format!("secondary selection: {} chars", to - from));
}

/// The secondary selection's text, if it is still there.
fn secondary_text(editor: &Editor) -> Option<String> {
    let (doc_id, range) = editor.secondary_selection?;
    let doc = editor.documents.get(&doc_id)?;
    let len = doc.text().len_chars();
    let (from, to) = (range.from().min(len), range.to().min(len));
    (from < to).then(|| doc.text().slice(from..to).to_string())
}

/// emacs `mouse-yank-secondary` (M-mouse-2): insert the secondary selection at
/// the click, leaving the secondary selection itself alone.
pub(crate) fn mouse_yank_secondary(cx: &mut Context) {
    let Some(text) = secondary_text(cx.editor) else {
        cx.editor
            .set_error("mouse-yank-secondary: no secondary selection");
        return;
    };
    let pos = click_pos(cx.editor);
    let (view, doc) = current!(cx.editor);
    let tx = Transaction::change(
        doc.text(),
        std::iter::once((pos, pos, Some(text.as_str().into()))),
    );
    doc.apply(&tx, view.id);
    doc.append_changes_to_history(view);
    cx.editor.set_status(format!(
        "yanked {} chars from the secondary selection",
        text.len()
    ));
}

/// emacs `mouse-secondary-save-then-kill` (M-mouse-3): copy the secondary
/// selection to the kill ring; run again, it deletes it.
pub(crate) fn mouse_secondary_save_then_kill(cx: &mut Context) {
    let Some(text) = secondary_text(cx.editor) else {
        cx.editor
            .set_error("mouse-secondary-save-then-kill: no secondary selection");
        return;
    };
    let register = cx.editor.config().mouse_yank_register;
    let saved = cx
        .editor
        .registers
        .read(register, cx.editor)
        .and_then(|mut v| v.next().map(|s| s.into_owned()))
        .map(|s| s == text)
        .unwrap_or(false);
    if saved {
        // Already saved once: this press kills it.
        let Some((doc_id, range)) = cx.editor.secondary_selection else {
            return;
        };
        clear_secondary(cx.editor);
        let view_id = cx.editor.tree.focus;
        let Some(doc) = cx.editor.documents.get_mut(&doc_id) else {
            return;
        };
        let tx = Transaction::change(
            doc.text(),
            std::iter::once((range.from(), range.to(), None)),
        );
        doc.apply(&tx, view_id);
        cx.editor.set_status("secondary selection killed");
        return;
    }
    if let Err(e) = cx.editor.registers.write(register, vec![text.clone()]) {
        cx.editor.set_error(e.to_string());
        return;
    }
    cx.editor.set_status(format!(
        "saved {} chars from the secondary selection",
        text.len()
    ));
}

// ── overwrite (emacs `overwrite-mode`) ───────────────────────────────────────

/// emacs `overwrite-mode`: a persistent minor mode in which a self-inserted
/// character *replaces* the one under point instead of pushing it right. Unlike
/// zmax's modal `R` (replace_mode), it stays on across insert sessions — it is
/// a property of the buffer's editing, not a mode you are in. Read by
/// `insert::insert_char`.
fn overwrite_mode(cx: &mut Context) {
    let on = !cx.editor.overwrite_mode;
    cx.editor.overwrite_mode = on;
    cx.editor.overwrite_binary = false;
    cx.editor.set_status(if on {
        "Overwrite mode enabled"
    } else {
        "Overwrite mode disabled"
    });
}

/// emacs `binary-overwrite-mode`: overwrite mode that does not spare newlines —
/// typing a character over a newline replaces the newline too, so the file's
/// byte layout is preserved. (In plain overwrite-mode a newline is never
/// overwritten; the character is inserted before it.)
fn binary_overwrite_mode(cx: &mut Context) {
    let on = !(cx.editor.overwrite_mode && cx.editor.overwrite_binary);
    cx.editor.overwrite_mode = on;
    cx.editor.overwrite_binary = on;
    cx.editor.set_status(if on {
        "Binary-Overwrite mode enabled"
    } else {
        "Binary-Overwrite mode disabled"
    });
}

/// emacs `compose-mail-other-frame` (`C-x 5 m`): a new frame, with a mail draft
/// in it. The draft is the same one `:compose-mail` opens.
fn compose_mail_other_frame(cx: &mut Context) {
    let doc = doc!(cx.editor).id();
    cx.editor.new_frame(doc, None);
    let mut cx = crate::compositor::Context {
        editor: cx.editor,
        jobs: cx.jobs,
        scroll: None,
    };
    typed::run_command_line(&mut cx, "compose-mail");
}

/// emacs `context-menu-mode`: turn the right-button popup menu on or off. Read
/// by the mouse handler, so with the mode off the right button really does not
/// pop up a menu.
fn context_menu_mode(cx: &mut Context) {
    let on = !cx.editor.context_menu_mode;
    cx.editor.context_menu_mode = on;
    cx.editor.set_status(if on {
        "Context-Menu mode enabled"
    } else {
        "Context-Menu mode disabled"
    });
}

/// emacs `reveal-mode`: text hidden by an `invisible` text property (what
/// `hide-ifdef-mode`, `outline` folding and `selective-display` put there) is
/// temporarily revealed while point is inside it, and hidden again the moment
/// point leaves. The check runs every frame in `ui::editor`'s render, which is
/// the only place that can see where point ended up.
fn reveal_mode(cx: &mut Context) {
    let on = !cx.editor.reveal_mode;
    cx.editor.reveal_mode = on;
    if !on {
        // Re-hide anything reveal-mode was holding open.
        if let Some((doc_id, range)) = cx.editor.revealed.take() {
            if let Some(doc) = cx.editor.documents.get_mut(&doc_id) {
                doc.update_text_props(|props| props.set_invisible(range, true));
            }
        }
    }
    cx.editor.set_status(if on {
        "Reveal mode enabled"
    } else {
        "Reveal mode disabled"
    });
}

/// emacs `desktop-save-mode`: save the desktop — every file-visiting buffer and
/// its point — on exit, without being asked. The event loop runs `:desktop-save`
/// on quit when this is on.
fn desktop_save_mode(cx: &mut Context) {
    let on = !cx.editor.desktop_save_mode;
    cx.editor.desktop_save_mode = on;
    cx.editor.set_status(if on {
        "Desktop-Save mode enabled — the desktop is saved on exit"
    } else {
        "Desktop-Save mode disabled"
    });
}

/// emacs `visual-wrap-prefix-mode`: a soft-wrapped line's continuation is
/// indented to line up under the line it wrapped from, instead of starting at
/// column 0. Toggles the `break_indent` the document formatter reads.
///
/// Divergence: emacs continues the whole *prefix* of the line (its indentation
/// **and** any comment marker or list bullet); zmax carries the indentation
/// only, because that is what the text formatter's wrap-indent understands.
fn visual_wrap_prefix_mode(cx: &mut Context) {
    let mut on = false;
    edit_live_config(cx, |c| {
        c.break_indent = !c.break_indent;
        on = c.break_indent;
    });
    cx.editor.set_status(if on {
        "Visual-Wrap-Prefix mode enabled"
    } else {
        "Visual-Wrap-Prefix mode disabled"
    });
}

/// The open dribble file (emacs `open-dribble-file`): every key the editor reads
/// is appended to it, which is how you produce a keystroke log for a bug report.
static DRIBBLE: std::sync::Mutex<Option<std::fs::File>> = std::sync::Mutex::new(None);

/// Append a key to the dribble file, if one is open. Called for every key event
/// by `ui::editor`.
pub(crate) fn dribble_key(event: &KeyEvent) {
    let Ok(mut file) = DRIBBLE.lock() else {
        return;
    };
    if let Some(file) = file.as_mut() {
        use std::io::Write;
        let _ = writeln!(file, "{event}");
        let _ = file.flush();
    }
}

/// emacs `open-dribble-file`: start recording every key into a file (an empty
/// name closes the one that is open). Emacs's own definition — "all keyboard
/// input is written to the file" — is what this does; it is how a keystroke log
/// for a bug report is made.
fn open_dribble_file(cx: &mut Context) {
    prompt_then(cx, "Open dribble file: ", |cx, input| {
        let input = input.trim();
        let Ok(mut slot) = DRIBBLE.lock() else {
            cx.editor.set_error("open-dribble-file: state is poisoned");
            return;
        };
        if input.is_empty() {
            *slot = None;
            cx.editor.set_status("dribble file closed");
            return;
        }
        let path = path::expand_tilde(Path::new(input));
        match std::fs::OpenOptions::new()
            .create(true)
            .append(true)
            .open(&path)
        {
            Ok(file) => {
                *slot = Some(file);
                cx.editor
                    .set_status(format!("dribbling keys to {}", path.display()));
            }
            Err(e) => cx
                .editor
                .set_error(format!("open-dribble-file: {}: {e}", path.display())),
        }
    });
}

#[cfg(test)]
mod gap_command_tests {
    use super::*;

    /// vim 'keymodel' is a comma list, and its default is empty — so the shifted
    /// keys must keep their word/page meaning unless the user opts in. A prefix
    /// match would wrongly fire `startsel` for a value of `stopsel`.
    #[test]
    fn keymodel_reads_whole_comma_separated_flags() {
        assert!(keymodel_has(Some("startsel"), "startsel"));
        assert!(keymodel_has(Some("startsel,stopsel"), "stopsel"));
        assert!(keymodel_has(Some(" startsel , stopsel "), "startsel"));
        // Default: empty / unset means both flags are off.
        assert!(!keymodel_has(Some(""), "startsel"));
        assert!(!keymodel_has(None, "startsel"));
        // `stopsel` alone must not enable `startsel`, and neither is a substring hit.
        assert!(!keymodel_has(Some("stopsel"), "startsel"));
        assert!(!keymodel_has(Some("startselx"), "startsel"));
    }

    /// vim's default `mousescroll` is `ver:3,hor:6` — the horizontal tick must read
    /// `hor`, not the `ver` that precedes it, or `<ScrollWheelLeft>` would move 3
    /// columns instead of 6.
    #[test]
    fn mousescroll_cols_reads_the_hor_axis() {
        assert_eq!(mousescroll_cols("ver:3,hor:6"), Some(6));
        assert_eq!(mousescroll_cols("hor:6,ver:3"), Some(6));
        assert_eq!(mousescroll_cols(" ver:3 , hor:12 "), Some(12));
        // No `hor` axis: the caller falls back to vim's default rather than
        // silently borrowing `ver`.
        assert_eq!(mousescroll_cols("ver:3"), None);
        assert_eq!(mousescroll_cols(""), None);
        assert_eq!(mousescroll_cols("hor:notanumber"), None);
    }

    /// `table-unrecognize` has to find every table in the buffer, and
    /// `table-unrecognize-region` only the ones that start inside the region.
    /// Both are keyed on the table's first line, which is what the recognized/
    /// unrecognized sets store.
    #[test]
    fn table_start_lines_finds_each_grid() {
        let text = Rope::from_str(
            "intro\n\
             +---+\n\
             | a |\n\
             +---+\n\
             between\n\
             +---+---+\n\
             | b | c |\n\
             +---+---+\n",
        );
        // Whole buffer: both tables, identified by their first line.
        assert_eq!(table_start_lines(&text, 0, usize::MAX), vec![1, 5]);
        // A region covering only the second table's lines.
        assert_eq!(table_start_lines(&text, 4, 7), vec![5]);
        // A region that ends before either table starts.
        assert!(table_start_lines(&text, 0, 0).is_empty());
        // Prose only: no grids at all.
        assert!(table_start_lines(&Rope::from_str("no grid here\n"), 0, usize::MAX).is_empty());
    }

    /// `rgrep`/`lgrep`/`grep-find` build a shell command line out of a regexp, a
    /// glob and a directory the user typed, and hand it to the Run console's
    /// shell. Everything user-typed goes through `shell_quote`, so the property
    /// that matters is that a real shell parses each one back as exactly one
    /// argument with exactly the original bytes — no command injection, no
    /// mangling of a regexp that happens to contain shell metacharacters.
    #[test]
    fn grep_arguments_round_trip_through_a_real_shell() {
        for input in [
            "foo",
            "it's",              // the case naive quoting gets wrong
            "a; rm -rf /",       // command separator
            "$(whoami)",         // command substitution
            "`id`",              // backtick substitution
            "'; touch pwned; '", // closing-quote injection attempt
            r"\bfn\s+\w+\(",     // a regexp with backslashes
            "*.rs",              // a glob, which must not be expanded
            "a\nb",              // an embedded newline
        ] {
            let out = std::process::Command::new("sh")
                .arg("-c")
                .arg(format!("printf %s {}", shell_quote(input)))
                .output()
                .expect("sh is available on every supported platform");
            assert!(out.status.success(), "sh rejected quoting of {input:?}");
            assert_eq!(
                String::from_utf8_lossy(&out.stdout),
                input,
                "shell_quote({input:?}) did not round-trip through the shell"
            );
            // Nothing may have run besides `printf` -- an injected command would
            // have written to stderr or produced extra output.
            assert!(
                out.stderr.is_empty(),
                "quoting of {input:?} leaked to stderr"
            );
        }
    }

    /// dabbrev's candidate order is the whole feature: Emacs searches backward
    /// from point first, so the nearest word behind you is what M-/ gives you.
    #[test]
    fn dabbrev_orders_backward_matches_before_forward_ones() {
        //            0         1         2         3         4
        //            0123456789012345678901234567890123456789012345
        let text = "value_one value_two value_th value_three value_four";
        // Cursor sits at the end of the `value_th` prefix (offset 28).
        let cursor = text.find("value_th").unwrap() + "value_th".len();
        let got = dabbrev_candidates(text, "value_th", cursor);
        assert_eq!(got, vec!["value_three"]);

        // A shorter prefix matches everything else, backward-nearest first.
        let got = dabbrev_candidates(text, "value_", cursor);
        assert_eq!(
            got,
            vec!["value_two", "value_one", "value_three", "value_four"],
            "backward matches (nearest first), then forward matches"
        );
    }

    /// The word being typed must never suggest itself, or M-/ would appear to do
    /// nothing; a repeated word elsewhere in the buffer is still a candidate.
    #[test]
    fn dabbrev_skips_the_word_under_the_cursor_but_not_its_twins() {
        let text = "total total_count tot";
        let cursor = text.len();
        assert_eq!(
            dabbrev_candidates(text, "tot", cursor),
            vec!["total_count", "total"],
            "nearest-first backward, and the prefix itself is not a candidate"
        );

        // Prefix equal to an existing word: that word is not offered verbatim.
        let text = "alpha alph";
        let cursor = text.len();
        assert_eq!(dabbrev_candidates(text, "alph", cursor), vec!["alpha"]);
        assert!(dabbrev_candidates("alpha alpha", "alpha", 11).is_empty());
    }

    /// Unwrapping keys off the innermost enclosing braces, which is what decides
    /// *which* block gets lifted.
    #[test]
    fn enclosing_brace_block_finds_the_innermost_pair() {
        let text = Rope::from_str("if (a) {\n    while (b) {\n        x();\n    }\n}\n");
        let slice = text.slice(..);
        let inner_x = text.line_to_char(2) + 8; // on `x()`
        let (open, close) = enclosing_brace_block(slice, inner_x).expect("inside the while block");
        assert_eq!(slice.char(open), '{');
        assert_eq!(slice.char(close), '}');
        // The innermost `{` is the `while`'s, on line 1 — not the `if`'s on line 0.
        assert_eq!(slice.char_to_line(open), 1);
        assert_eq!(slice.char_to_line(close), 3);

        // Between the two closing braces, the enclosing block is the outer `if`.
        let between = text.line_to_char(4);
        let (open, _close) = enclosing_brace_block(slice, between).expect("inside the if block");
        assert_eq!(slice.char_to_line(open), 0);

        // Outside every block there is nothing to unwrap.
        assert!(enclosing_brace_block(slice, text.len_chars() - 1).is_none());
    }

    /// The `\begin{env}` detector must not fire on a `}` that closes something
    /// else, or typing any brace in a LaTeX file would spray `\end{}` lines.
    #[test]
    fn begin_env_is_recognised_only_when_it_closes_a_begin() {
        assert_eq!(
            begin_env_before("\\begin{itemize}").as_deref(),
            Some("itemize")
        );
        assert_eq!(
            begin_env_before("  \\begin{align*}").as_deref(),
            Some("align*")
        );
        assert_eq!(begin_env_before("\\end{itemize}"), None);
        assert_eq!(begin_env_before("\\textbf{bold}"), None);
        assert_eq!(begin_env_before("\\begin{}"), None);
        assert_eq!(begin_env_before("x = {1}"), None);
        // Not yet closed: the `}` has not been typed.
        assert_eq!(begin_env_before("\\begin{itemize"), None);
    }

    /// A C header and its source are siblings of each other; unrelated files are
    /// not. Uses real files in a temp dir, because the rule is "the file exists".
    #[test]
    fn sibling_files_pairs_header_and_source() {
        let dir = std::env::temp_dir().join(format!("zmax-sib-{}", std::process::id()));
        let _ = std::fs::remove_dir_all(&dir);
        std::fs::create_dir_all(&dir).unwrap();
        for f in ["thing.c", "thing.h", "other.c"] {
            std::fs::write(dir.join(f), "").unwrap();
        }
        let from_c = sibling_files(&dir.join("thing.c"));
        assert_eq!(from_c, vec![dir.join("thing.h")]);

        let from_h = sibling_files(&dir.join("thing.h"));
        assert_eq!(from_h, vec![dir.join("thing.c")], "and back again");

        // No pair on disk -> no sibling (a .cpp partner that does not exist).
        std::fs::write(dir.join("lonely.cpp"), "").unwrap();
        assert!(sibling_files(&dir.join("lonely.cpp")).is_empty());

        let _ = std::fs::remove_dir_all(&dir);
    }
}

// ===========================================================================
// The package subsystem — the zmax port of GNU Emacs `package.el`.
//
// A zmax package is an Emacs package: a directory of Emacs Lisp, fetched from a
// real ELPA archive, unpacked under `~/.zmax/elpa/<name>-<version>/`, put on the
// elisp load path, and *activated* by evaluating its autoload file in the embedded
// `elisprs` interpreter. That is the whole contract, and it is the same one Emacs
// has — see `zmax_core::package` for the two honest divergences (no byte
// compiler; a package whose value is a GUI widget or a C module is inert here).
// ===========================================================================

use zmax_core::package::{
    self as pkg, Installed, Mark as PkgMark, PackageDesc, PackageKind, PackageMenu,
};

/// Where installed packages live: `~/.zmax/elpa/`, a sibling of `init.el` and
/// `lisp/` — the same layout Emacs uses under `~/.emacs.d/`.
pub(crate) fn elpa_dir() -> std::path::PathBuf {
    zmax_loader::config_dir().join("elpa")
}

/// The archives `package-refresh-contents` reads, in priority order. These are the
/// real ELPA archives; each serves an `archive-contents` listing and one
/// `<name>-<version>.tar` (or `.el`) per package.
const PACKAGE_ARCHIVES: &[(&str, &str)] = &[
    ("gnu", "https://elpa.gnu.org/packages/"),
    ("nongnu", "https://elpa.nongnu.org/nongnu/"),
    ("melpa", "https://melpa.org/packages/"),
];

/// Every package currently installed on disk.
pub(crate) fn installed_packages() -> Vec<Installed> {
    pkg::installed_packages(&elpa_dir())
}

/// Fetch and parse every archive's `archive-contents`. Blocking (ureq is), so it
/// is always called on a `spawn_blocking` task. A failing archive is reported and
/// skipped rather than failing the refresh — one archive being down must not stop
/// you installing from the others.
fn fetch_archives_blocking() -> (Vec<PackageDesc>, Vec<String>) {
    let agent = ureq::AgentBuilder::new()
        .timeout_connect(std::time::Duration::from_secs(10))
        .timeout_read(std::time::Duration::from_secs(60))
        .build();
    let mut all = Vec::new();
    let mut errors = Vec::new();
    for (name, url) in PACKAGE_ARCHIVES {
        let contents = agent
            .get(&format!("{url}archive-contents"))
            .set("User-Agent", "zmax-package")
            .call()
            .map_err(|e| format!("{name}: {e}"))
            .and_then(|resp| resp.into_string().map_err(|e| format!("{name}: {e}")));
        match contents.and_then(|src| pkg::parse_archive_contents(&src, name)) {
            Ok(mut packages) => all.append(&mut packages),
            Err(e) => errors.push(e),
        }
    }
    (all, errors)
}

/// Emacs `package-refresh-contents`: re-read every archive's listing, and rebuild
/// the package menu from it plus what is installed on disk.
pub(crate) fn package_refresh_impl(cx: &mut compositor::Context) {
    cx.editor.set_status("Refreshing package archives…");
    cx.jobs.callback(async move {
        let (available, errors) = tokio::task::spawn_blocking(fetch_archives_blocking)
            .await
            .unwrap_or_else(|e| (Vec::new(), vec![format!("join error: {e}")]));
        let call: job::Callback = Callback::EditorCompositor(Box::new(
            move |editor: &mut Editor, _compositor: &mut Compositor| {
                if available.is_empty() {
                    editor.set_error(format!(
                        "package-refresh-contents: no archive could be read ({})",
                        errors.join("; ")
                    ));
                    return;
                }
                let count = available.len();
                let installed = installed_packages();
                crate::ui::package_menu::set_menu(PackageMenu::new(available, &installed));
                if errors.is_empty() {
                    editor.set_status(format!("Package refresh: {count} packages available"));
                } else {
                    editor.set_status(format!(
                        "Package refresh: {count} packages available ({} archive(s) failed: {})",
                        errors.len(),
                        errors.join("; ")
                    ));
                }
            },
        ));
        Ok(call)
    });
}

/// Download and unpack one package into the elpa dir. Blocking.
///
/// A `tar` package holds a `<name>-<version>/` directory, which is unpacked
/// straight into the elpa dir; the `tar` crate refuses entries whose path escapes
/// the destination, which is what makes unpacking a downloaded archive safe. A
/// `single` package is one `.el` file, which is written into a directory of the
/// same name so that both kinds live under `<name>-<version>/` and can be found,
/// listed and deleted the same way.
fn install_package_blocking(desc: &PackageDesc) -> Result<std::path::PathBuf, String> {
    let base = PACKAGE_ARCHIVES
        .iter()
        .find(|(name, _)| *name == desc.archive)
        .map(|(_, url)| *url)
        .ok_or_else(|| format!("{}: unknown archive `{}`", desc.name, desc.archive))?;
    let url = format!("{base}{}", desc.file_name());

    let agent = ureq::AgentBuilder::new()
        .timeout_connect(std::time::Duration::from_secs(10))
        .timeout_read(std::time::Duration::from_secs(120))
        .build();
    let resp = agent
        .get(&url)
        .set("User-Agent", "zmax-package")
        .call()
        .map_err(|e| format!("{}: {e}", desc.name))?;
    let mut bytes = Vec::new();
    std::io::Read::read_to_end(&mut resp.into_reader(), &mut bytes)
        .map_err(|e| format!("{}: {e}", desc.name))?;

    let elpa = elpa_dir();
    std::fs::create_dir_all(&elpa).map_err(|e| format!("{}: {e}", elpa.display()))?;
    let dir = elpa.join(desc.dir_name());
    // A half-written previous attempt would shadow the new one.
    let _ = std::fs::remove_dir_all(&dir);

    match desc.kind {
        PackageKind::Single => {
            std::fs::create_dir_all(&dir).map_err(|e| format!("{}: {e}", dir.display()))?;
            let file = dir.join(format!("{}.el", desc.name));
            std::fs::write(&file, &bytes).map_err(|e| format!("{}: {e}", file.display()))?;
        }
        PackageKind::Tar => unpack_tar(&bytes, &elpa).map_err(|e| format!("{}: {e}", desc.name))?,
    }
    if !dir.is_dir() {
        return Err(format!(
            "{}: the archive did not contain {}/",
            desc.name,
            desc.dir_name()
        ));
    }
    Ok(dir)
}

/// Unpack a package tar into `dest`. ELPA serves plain tars; a locally built
/// package may be gzipped, so the gzip magic is sniffed and the stream decompressed
/// when it is there.
fn unpack_tar(bytes: &[u8], dest: &std::path::Path) -> std::io::Result<()> {
    let gzipped = bytes.starts_with(&[0x1f, 0x8b]);
    if gzipped {
        let decoder = flate2::read::GzDecoder::new(bytes);
        tar::Archive::new(decoder).unpack(dest)
    } else {
        tar::Archive::new(bytes).unpack(dest)
    }
}

/// Evaluate a package's entry file, which is what *activating* it means: its
/// autoload file if it has one (that is what Emacs loads), else the library named
/// after the package. Reports what it did; a package with neither is installed but
/// has nothing to run.
fn activate_package(cx: &mut compositor::Context, name: &str, dir: &std::path::Path) {
    let autoloads = dir.join(format!("{name}-autoloads.el"));
    let main = dir.join(format!("{name}.el"));
    let entry = if autoloads.is_file() {
        autoloads
    } else if main.is_file() {
        main
    } else {
        log::info!("package {name}: nothing to activate in {}", dir.display());
        return;
    };
    match std::fs::read_to_string(&entry) {
        Ok(src) => match crate::commands::scripting::eval_elisp(cx, &src) {
            Ok(_) => log::info!("package {name}: activated {}", entry.display()),
            Err(e) => cx
                .editor
                .set_error(format!("package {name}: {} — {e}", entry.display())),
        },
        Err(e) => cx
            .editor
            .set_error(format!("package {name}: {} — {e}", entry.display())),
    }
}

/// Emacs `package-activate-all`: put every installed package on the load path and
/// evaluate its autoload file. This is what `package-initialize` does at startup,
/// and it is called from `Application` on launch so that packages are live before
/// `init.el` runs.
pub(crate) fn package_activate_all_impl(cx: &mut compositor::Context) -> usize {
    let installed = installed_packages();
    // Only the newest version of each package is activated, as in Emacs.
    let mut newest: Vec<&Installed> = Vec::new();
    for inst in &installed {
        match newest.iter_mut().find(|n| n.name == inst.name) {
            Some(existing) => {
                if pkg::version_cmp(&inst.version, &existing.version) == std::cmp::Ordering::Greater
                {
                    *existing = inst;
                }
            }
            None => newest.push(inst),
        }
    }
    for inst in &newest {
        activate_package(cx, &inst.name, &inst.dir);
    }
    newest.len()
}

/// Install `desc` and everything it needs, then activate each. Runs the download on
/// a blocking task and comes back to the editor to activate (the elisp interpreter
/// is not `Send`, and activation must happen on the editor thread).
fn install_packages(cx: &mut compositor::Context, order: Vec<PackageDesc>) {
    if order.is_empty() {
        cx.editor.set_status("package-install: nothing to do");
        return;
    }
    let names: Vec<String> = order.iter().map(|d| d.name.clone()).collect();
    cx.editor
        .set_status(format!("Installing {}…", names.join(", ")));
    cx.jobs.callback(async move {
        let results = tokio::task::spawn_blocking(move || {
            order
                .into_iter()
                .map(|desc| {
                    let outcome = install_package_blocking(&desc);
                    (desc.name, outcome)
                })
                .collect::<Vec<_>>()
        })
        .await
        .unwrap_or_default();

        let call: job::Callback = Callback::EditorCompositor(Box::new(
            move |editor: &mut Editor, compositor: &mut Compositor| {
                let mut installed = Vec::new();
                let mut failed = Vec::new();
                let mut activate: Vec<(String, std::path::PathBuf)> = Vec::new();
                for (name, outcome) in results {
                    match outcome {
                        Ok(dir) => {
                            installed.push(name.clone());
                            activate.push((name, dir));
                        }
                        Err(e) => failed.push(e),
                    }
                }
                // Activation evaluates elisp, which needs the full context.
                let mut cx = compositor::Context {
                    editor,
                    jobs: &mut Jobs::new(),
                    scroll: None,
                };
                for (name, dir) in &activate {
                    activate_package(&mut cx, name, dir);
                }
                refresh_package_menu_rows();
                let _ = compositor;
                if failed.is_empty() {
                    editor.set_status(format!("Installed {}", installed.join(", ")));
                } else if installed.is_empty() {
                    editor.set_error(format!("package-install: {}", failed.join("; ")));
                } else {
                    editor.set_error(format!(
                        "Installed {}; failed: {}",
                        installed.join(", "),
                        failed.join("; ")
                    ));
                }
            },
        ));
        Ok(call)
    });
}

/// Rebuild the menu's rows against what is now on disk, keeping the archive
/// listing — so an install flips a row from `available` to `installed` without a
/// network round trip.
fn refresh_package_menu_rows() {
    let installed = installed_packages();
    crate::ui::package_menu::with_menu(|menu| {
        let available: Vec<PackageDesc> = menu
            .rows()
            .iter()
            .filter(|r| !r.desc.archive.is_empty())
            .map(|r| r.desc.clone())
            .collect();
        let mut rebuilt = PackageMenu::new(available, &installed);
        rebuilt.selected = menu.selected;
        rebuilt.filters = menu.filters.clone();
        rebuilt.hiding = menu.hiding;
        *menu = rebuilt;
    });
}

/// Delete an installed package's directory (Emacs `package-delete`).
fn delete_package(name: &str) -> Result<(), String> {
    let installed = installed_packages();
    let mut found = false;
    for inst in installed.iter().filter(|i| i.name == name) {
        std::fs::remove_dir_all(&inst.dir).map_err(|e| format!("{name}: {e}"))?;
        found = true;
    }
    if found {
        Ok(())
    } else {
        Err(format!("{name} is not installed"))
    }
}

/// The archive listing, loading it first if it has not been fetched. Every command
/// that needs the listing goes through here, so `M-x package-install` works from a
/// cold start instead of complaining that nothing is loaded.
fn with_archive_listing(
    cx: &mut Context,
    f: impl FnOnce(&mut compositor::Context) + Send + 'static,
) {
    if crate::ui::package_menu::is_loaded() {
        let mut cx = compositor::Context {
            editor: cx.editor,
            jobs: cx.jobs,
            scroll: None,
        };
        f(&mut cx);
        return;
    }
    cx.editor
        .set_status("Refreshing package archives (first use)…");
    cx.jobs.callback(async move {
        let (available, errors) = tokio::task::spawn_blocking(fetch_archives_blocking)
            .await
            .unwrap_or_else(|e| (Vec::new(), vec![format!("join error: {e}")]));
        let call: job::Callback = Callback::EditorCompositor(Box::new(
            move |editor: &mut Editor, _compositor: &mut Compositor| {
                if available.is_empty() {
                    editor.set_error(format!(
                        "package: no archive could be read ({})",
                        errors.join("; ")
                    ));
                    return;
                }
                let installed = installed_packages();
                crate::ui::package_menu::set_menu(PackageMenu::new(available, &installed));
                let mut cx = compositor::Context {
                    editor,
                    jobs: &mut Jobs::new(),
                    scroll: None,
                };
                f(&mut cx);
            },
        ));
        Ok(call)
    });
}

/// Emacs `list-packages` (`M-x list-packages`): open the package menu, fetching the
/// archive listing first if it has not been read yet.
fn list_packages(cx: &mut Context) {
    if crate::ui::package_menu::is_loaded() {
        open_overlay(cx, |_editor| {
            Ok(Box::new(crate::ui::package_menu::PackageMenuView::new()) as Box<dyn Component>)
        });
        return;
    }
    let mut ccx = compositor::Context {
        editor: cx.editor,
        jobs: cx.jobs,
        scroll: None,
    };
    package_refresh_impl(&mut ccx);
    // The refresh lands through the job queue; queue the menu behind it so it opens
    // with the listing already in it.
    cx.jobs.callback(async move {
        let call: job::Callback = Callback::EditorCompositor(Box::new(
            move |_editor: &mut Editor, compositor: &mut Compositor| {
                compositor.push(Box::new(crate::ui::package_menu::PackageMenuView::new()));
            },
        ));
        Ok(call)
    });
}

/// Emacs `package-refresh-contents`, by name.
fn package_refresh_contents(cx: &mut Context) {
    let mut cx = compositor::Context {
        editor: cx.editor,
        jobs: cx.jobs,
        scroll: None,
    };
    package_refresh_impl(&mut cx);
}

/// Emacs `package-install`: read a package name and install it, with its
/// dependencies, from the archives.
fn package_install(cx: &mut Context) {
    with_archive_listing(cx, |cx| {
        prompt_then_cx(cx, "Install package: ", |cx, input| {
            let name = input.trim().to_string();
            let listing = crate::ui::package_menu::with_menu(|m| {
                m.rows()
                    .iter()
                    .filter(|r| !r.desc.archive.is_empty())
                    .map(|r| r.desc.clone())
                    .collect::<Vec<_>>()
            });
            let Some(desc) = listing.iter().find(|d| d.name == name).cloned() else {
                cx.editor
                    .set_error(format!("package-install: no package named `{name}`"));
                return;
            };
            let order = pkg::install_order(&desc, &listing, &installed_packages());
            install_packages(cx, order);
        });
    });
}

/// Emacs `package-install-file`: install a package from a `.el` or `.tar` file on
/// disk, rather than from an archive — the way you install something you built
/// yourself.
fn package_install_file(cx: &mut Context) {
    ui::prompt(
        cx,
        "Install package file: ".into(),
        Some('f'),
        ui::completers::filename,
        |cx, input, event| {
            if event != PromptEvent::Validate {
                return;
            }
            let path = path::expand_tilde(std::path::Path::new(input.trim())).into_owned();
            match install_file(&path) {
                Ok((name, dir)) => {
                    activate_package(cx, &name, &dir);
                    refresh_package_menu_rows();
                    cx.editor
                        .set_status(format!("Installed {name} from {}", path.display()));
                }
                Err(e) => cx.editor.set_error(format!("package-install-file: {e}")),
            }
        },
    );
}

/// Install one local package file. A `.tar` is unpacked as it stands (it carries
/// its own `<name>-<version>/` directory); a bare `.el` becomes a package of that
/// name, versioned `0.0` since a lone file carries no version the archive format
/// would give it.
fn install_file(path: &std::path::Path) -> Result<(String, std::path::PathBuf), String> {
    let elpa = elpa_dir();
    std::fs::create_dir_all(&elpa).map_err(|e| format!("{}: {e}", elpa.display()))?;
    let stem = path
        .file_stem()
        .and_then(|s| s.to_str())
        .ok_or_else(|| format!("{}: not a package file name", path.display()))?;

    match path.extension().and_then(|e| e.to_str()) {
        Some("el") => {
            let dir = elpa.join(format!("{stem}-0.0"));
            let _ = std::fs::remove_dir_all(&dir);
            std::fs::create_dir_all(&dir).map_err(|e| format!("{}: {e}", dir.display()))?;
            std::fs::copy(path, dir.join(format!("{stem}.el")))
                .map_err(|e| format!("{}: {e}", path.display()))?;
            Ok((stem.to_string(), dir))
        }
        Some("tar") | Some("gz") | Some("tgz") => {
            let bytes = std::fs::read(path).map_err(|e| format!("{}: {e}", path.display()))?;
            unpack_tar(&bytes, &elpa).map_err(|e| format!("{}: {e}", path.display()))?;
            // The tar's own top directory names the package.
            let (name, version) = pkg::split_dir_name(stem)
                .ok_or_else(|| format!("{stem}: not a <name>-<version> package archive"))?;
            let dir = elpa.join(format!("{name}-{}", pkg::version_string(&version)));
            Ok((name, dir))
        }
        _ => Err(format!(
            "{}: a package file is a .el or a .tar",
            path.display()
        )),
    }
}

/// Emacs `package-delete`: remove an installed package from disk.
fn package_delete(cx: &mut Context) {
    prompt_then(cx, "Delete package: ", |cx, input| {
        match delete_package(input.trim()) {
            Ok(()) => {
                refresh_package_menu_rows();
                cx.editor.set_status(format!("Deleted {}", input.trim()));
            }
            Err(e) => cx.editor.set_error(format!("package-delete: {e}")),
        }
    });
}

/// Emacs `package-upgrade`: install the archive's newer version of one package.
fn package_upgrade(cx: &mut Context) {
    with_archive_listing(cx, |cx| {
        prompt_then_cx(cx, "Upgrade package: ", |cx, input| {
            let name = input.trim().to_string();
            let upgrade = crate::ui::package_menu::with_menu(|m| {
                m.find(&name)
                    .filter(|r| r.status == pkg::Status::Obsolete)
                    .map(|r| r.desc.clone())
            });
            match upgrade {
                Some(desc) => install_packages(cx, vec![desc]),
                None => cx
                    .editor
                    .set_error(format!("package-upgrade: {name} has no newer version")),
            }
        });
    });
}

/// Emacs `package-upgrade-all`: install a newer version of every package that has
/// one.
fn package_upgrade_all(cx: &mut Context) {
    with_archive_listing(cx, |cx| {
        let upgrades = crate::ui::package_menu::with_menu(|m| {
            m.rows()
                .iter()
                .filter(|r| r.status == pkg::Status::Obsolete)
                .map(|r| r.desc.clone())
                .collect::<Vec<_>>()
        });
        if upgrades.is_empty() {
            cx.editor.set_status("No packages to upgrade");
            return;
        }
        install_packages(cx, upgrades);
    });
}

/// Emacs `package-activate-all`: load every installed package now.
fn package_activate_all(cx: &mut Context) {
    let mut ccx = compositor::Context {
        editor: cx.editor,
        jobs: cx.jobs,
        scroll: None,
    };
    let n = package_activate_all_impl(&mut ccx);
    cx.editor.set_status(format!("Activated {n} package(s)"));
}

/// Emacs `package-quickstart-refresh`: write one file that loads every installed
/// package's autoloads, so startup does not have to walk the elpa directory. Emacs
/// writes `package-quickstart.el`; so does this, and `package-activate-all` reads
/// it when it is there.
fn package_quickstart_refresh(cx: &mut Context) {
    let installed = installed_packages();
    let mut out = String::from(
        ";; -*- lexical-binding: t -*-\n\
         ;; Generated by zmax package-quickstart-refresh. Do not edit.\n\n",
    );
    let mut count = 0;
    for inst in &installed {
        let autoloads = inst.dir.join(format!("{}-autoloads.el", inst.name));
        let entry = if autoloads.is_file() {
            autoloads
        } else {
            inst.dir.join(format!("{}.el", inst.name))
        };
        if !entry.is_file() {
            continue;
        }
        match std::fs::read_to_string(&entry) {
            Ok(src) => {
                out.push_str(&format!(";;; {} — {}\n", inst.name, entry.display()));
                out.push_str(&src);
                out.push_str("\n\n");
                count += 1;
            }
            Err(e) => log::warn!("package-quickstart: {}: {e}", entry.display()),
        }
    }
    let target = zmax_loader::config_dir().join("package-quickstart.el");
    match std::fs::write(&target, out) {
        Ok(()) => cx.editor.set_status(format!(
            "package-quickstart-refresh: {count} package(s) → {}",
            target.display()
        )),
        Err(e) => cx
            .editor
            .set_error(format!("package-quickstart-refresh: {e}")),
    }
}

/// Emacs `package-recompile`: byte-compile a package again.
///
/// Divergence, stated plainly: `elisprs` is an interpreter — there is no `.elc` and
/// nothing to byte-compile. What byte-compiling a package actually *checks* is that
/// every file in it reads and evaluates, and that is what this does: it re-evaluates
/// the package's elisp and reports the first file that fails.
fn package_recompile(cx: &mut Context) {
    prompt_then(cx, "Recompile package: ", |cx, input| {
        let name = input.trim().to_string();
        let Some(inst) = installed_packages().into_iter().find(|i| i.name == name) else {
            cx.editor
                .set_error(format!("package-recompile: {name} is not installed"));
            return;
        };
        match recompile_package(cx, &inst) {
            Ok(n) => cx
                .editor
                .set_status(format!("package-recompile: {name} — {n} file(s) evaluated")),
            Err(e) => cx.editor.set_error(format!("package-recompile: {e}")),
        }
    });
}

/// Emacs `package-recompile-all`: the same for every installed package.
fn package_recompile_all(cx: &mut Context) {
    let installed = installed_packages();
    let mut cx = compositor::Context {
        editor: cx.editor,
        jobs: cx.jobs,
        scroll: None,
    };
    let (mut ok, mut failed) = (0usize, Vec::new());
    for inst in &installed {
        match recompile_package(&mut cx, inst) {
            Ok(_) => ok += 1,
            Err(e) => failed.push(e),
        }
    }
    if failed.is_empty() {
        cx.editor.set_status(format!(
            "package-recompile-all: {ok} package(s) re-evaluated"
        ));
    } else {
        cx.editor.set_error(format!(
            "package-recompile-all: {ok} ok, {} failed: {}",
            failed.len(),
            failed.join("; ")
        ));
    }
}

/// Evaluate every `.el` file of an installed package, returning how many. This is
/// the check byte-compilation performs, done by the interpreter zmax has.
fn recompile_package(cx: &mut compositor::Context, inst: &Installed) -> Result<usize, String> {
    let entries = std::fs::read_dir(&inst.dir).map_err(|e| format!("{}: {e}", inst.name))?;
    let mut files: Vec<std::path::PathBuf> = entries
        .flatten()
        .map(|e| e.path())
        .filter(|p| p.extension().and_then(|e| e.to_str()) == Some("el"))
        .collect();
    files.sort();
    let mut n = 0;
    for file in files {
        let src = std::fs::read_to_string(&file).map_err(|e| format!("{}: {e}", file.display()))?;
        crate::commands::scripting::eval_elisp(cx, &src)
            .map_err(|e| format!("{}: {e}", file.display()))?;
        n += 1;
    }
    Ok(n)
}

/// The package under point in the menu, or an error if the menu has no rows.
fn current_package() -> Option<PackageDesc> {
    crate::ui::package_menu::with_menu(|m| m.current().map(|r| r.desc.clone()))
}

/// The report `describe-package` shows.
fn package_report(desc: &PackageDesc, installed: &[Installed]) -> String {
    let on_disk = installed.iter().find(|i| i.name == desc.name);
    let mut out = format!("Package — {}\n\n", desc.name);
    out.push_str(&format!("version:    {}\n", desc.version_string()));
    if let Some(inst) = on_disk {
        out.push_str(&format!(
            "installed:  {} ({})\n",
            pkg::version_string(&inst.version),
            inst.dir.display()
        ));
    } else {
        out.push_str("installed:  no\n");
    }
    if !desc.archive.is_empty() {
        out.push_str(&format!("archive:    {}\n", desc.archive));
    }
    out.push_str(&format!("kind:       {}\n", desc.kind.extension()));
    if let Some(url) = &desc.url {
        out.push_str(&format!("home page:  {url}\n"));
    }
    if let Some(m) = &desc.maintainer {
        out.push_str(&format!("maintainer: {m}\n"));
    }
    if !desc.keywords.is_empty() {
        out.push_str(&format!("keywords:   {}\n", desc.keywords.join(", ")));
    }
    if !desc.deps.is_empty() {
        let deps: Vec<String> = desc
            .deps
            .iter()
            .map(|(n, v)| format!("{n} {}", pkg::version_string(v)))
            .collect();
        out.push_str(&format!("requires:   {}\n", deps.join(", ")));
    }
    out.push_str(&format!("\n{}\n", desc.summary));
    out
}

/// Emacs `describe-package` (`C-h P`): show a package's metadata.
fn describe_package(cx: &mut Context) {
    with_archive_listing(cx, |cx| {
        prompt_then_cx(cx, "Describe package: ", |cx, input| {
            let name = input.trim().to_string();
            let desc =
                crate::ui::package_menu::with_menu(|m| m.find(&name).map(|r| r.desc.clone()));
            match desc {
                Some(desc) => {
                    let report = package_report(&desc, &installed_packages());
                    show_text_in_scratch(cx.editor, &report);
                }
                None => cx
                    .editor
                    .set_error(format!("describe-package: no package named `{name}`")),
            }
        });
    });
}

/// `RET` in the package menu: describe the package under point.
pub(crate) fn describe_current_package(cx: &mut compositor::Context) {
    match current_package() {
        Some(desc) => {
            let report = package_report(&desc, &installed_packages());
            show_text_in_scratch(cx.editor, &report);
        }
        None => cx.editor.set_error("package-menu: no package under point"),
    }
}

/// Emacs `package-browse-url` (`w` in the menu): open the package's home page.
pub(crate) fn browse_current_package_url(cx: &mut compositor::Context) {
    let Some(desc) = current_package() else {
        cx.editor.set_error("package-menu: no package under point");
        return;
    };
    match &desc.url {
        Some(url) => match open_in_browser(url) {
            Ok(()) => cx.editor.set_status(format!("Opening {url}")),
            Err(e) => cx.editor.set_error(format!("package-browse-url: {e}")),
        },
        None => cx.editor.set_error(format!(
            "package-browse-url: {} declares no home page",
            desc.name
        )),
    }
}

/// Emacs `package-menu-quick-help` (`?`).
pub(crate) fn show_package_quick_help(editor: &mut Editor) {
    show_text_in_scratch(editor, crate::ui::package_menu::QUICK_HELP);
}

/// Emacs `package-menu-execute` (`x`): carry out the marked installations and
/// deletions.
pub(crate) fn package_menu_execute_impl(cx: &mut compositor::Context) {
    let marked = crate::ui::package_menu::with_menu(|m| m.marked());
    if marked.is_empty() {
        cx.editor.set_status("package-menu: nothing marked");
        return;
    }
    let listing = crate::ui::package_menu::with_menu(|m| {
        m.rows()
            .iter()
            .filter(|r| !r.desc.archive.is_empty())
            .map(|r| r.desc.clone())
            .collect::<Vec<_>>()
    });
    let installed = installed_packages();

    // Deletions happen here and now (they are just a directory removal); the
    // installs go through the download job.
    let mut deleted = Vec::new();
    let mut errors = Vec::new();
    let mut to_install: Vec<PackageDesc> = Vec::new();
    for (name, mark, desc) in marked {
        match mark {
            PkgMark::Delete => match delete_package(&name) {
                Ok(()) => deleted.push(name),
                Err(e) => errors.push(e),
            },
            PkgMark::Install => {
                for d in pkg::install_order(&desc, &listing, &installed) {
                    if !to_install.iter().any(|p| p.name == d.name) {
                        to_install.push(d);
                    }
                }
            }
        }
    }
    crate::ui::package_menu::with_menu(PackageMenu::clear_marks);
    refresh_package_menu_rows();

    if !errors.is_empty() {
        cx.editor
            .set_error(format!("package-menu-execute: {}", errors.join("; ")));
    } else if !deleted.is_empty() && to_install.is_empty() {
        cx.editor
            .set_status(format!("Deleted {}", deleted.join(", ")));
    }
    if !to_install.is_empty() {
        install_packages(cx, to_install);
    }
}

// --- The `package-menu-*` commands (Emacs `package-menu-mode-map`) -----------
//
// Each acts on the package listing that `ui::package_menu` holds and the menu
// Component renders. The Component binds these to Emacs's real keys (`i`, `d`,
// `~`, `U`, `x`, `/ k`, …); these are the `M-x` names for the same operations, so
// the listing can be driven either way.

/// Emacs `package-menu-mark-install` (`i`).
fn package_menu_mark_install(cx: &mut Context) {
    match crate::ui::package_menu::with_menu(|m| m.mark_current(PkgMark::Install)) {
        Some(name) => cx
            .editor
            .set_status(format!("{name} marked for installation")),
        None => cx.editor.set_error(PACKAGE_MENU_EMPTY),
    }
}

/// Emacs `package-menu-mark-delete` (`d`).
fn package_menu_mark_delete(cx: &mut Context) {
    match crate::ui::package_menu::with_menu(|m| m.mark_current(PkgMark::Delete)) {
        Some(name) => cx.editor.set_status(format!("{name} marked for deletion")),
        None => cx.editor.set_error(PACKAGE_MENU_EMPTY),
    }
}

/// Emacs `package-menu-mark-unmark` (`u` / `DEL`).
fn package_menu_mark_unmark(cx: &mut Context) {
    match crate::ui::package_menu::with_menu(|m| m.unmark_current(1)) {
        Some(name) => cx.editor.set_status(format!("{name} unmarked")),
        None => cx.editor.set_error(PACKAGE_MENU_EMPTY),
    }
}

/// Emacs `package-menu-mark-upgrades` (`U`): mark every package the archive has a
/// newer version of.
fn package_menu_mark_upgrades(cx: &mut Context) {
    let n = crate::ui::package_menu::with_menu(PackageMenu::mark_upgrades);
    cx.editor
        .set_status(format!("{n} package(s) marked for upgrade"));
}

/// Emacs `package-menu-mark-obsolete-for-deletion` (`~`): mark every installed
/// version that a newer installed version supersedes.
fn package_menu_mark_obsolete_for_deletion(cx: &mut Context) {
    let installed = installed_packages();
    let n = crate::ui::package_menu::with_menu(|m| m.mark_obsolete_for_deletion(&installed));
    cx.editor
        .set_status(format!("{n} obsolete package(s) marked for deletion"));
}

/// Emacs `package-menu-execute` (`x`).
fn package_menu_execute(cx: &mut Context) {
    let mut cx = compositor::Context {
        editor: cx.editor,
        jobs: cx.jobs,
        scroll: None,
    };
    package_menu_execute_impl(&mut cx);
}

/// Emacs `package-menu-describe-package` (`RET`).
fn package_menu_describe_package(cx: &mut Context) {
    let mut cx = compositor::Context {
        editor: cx.editor,
        jobs: cx.jobs,
        scroll: None,
    };
    describe_current_package(&mut cx);
}

/// Emacs `package-browse-url` (`w`): open the package's home page.
fn package_browse_url(cx: &mut Context) {
    let mut cx = compositor::Context {
        editor: cx.editor,
        jobs: cx.jobs,
        scroll: None,
    };
    browse_current_package_url(&mut cx);
}

/// Emacs `package-menu-quick-help` (`?`).
fn package_menu_quick_help(cx: &mut Context) {
    show_package_quick_help(cx.editor);
}

/// Emacs `package-menu-hide-package` (`H`).
fn package_menu_hide_package(cx: &mut Context) {
    match crate::ui::package_menu::with_menu(PackageMenu::hide_current) {
        Some(name) => cx.editor.set_status(format!("{name} hidden")),
        None => cx.editor.set_error(PACKAGE_MENU_EMPTY),
    }
}

/// Emacs `package-menu-toggle-hiding` (`(`).
fn package_menu_toggle_hiding(cx: &mut Context) {
    let hiding = crate::ui::package_menu::with_menu(PackageMenu::toggle_hiding);
    cx.editor.set_status(if hiding {
        "package-menu: hidden packages are hidden"
    } else {
        "package-menu: hidden packages are shown"
    });
}

const PACKAGE_MENU_EMPTY: &str = "package-menu: no package listing — M-x list-packages loads one";

/// Apply a filter that reads no text (`/ m`, `/ u`).
fn package_menu_filter(cx: &mut Context, filter: pkg::Filter) {
    let label = filter.label();
    crate::ui::package_menu::with_menu(|m| m.add_filter(filter));
    let shown = crate::ui::package_menu::with_menu(|m| m.visible().len());
    cx.editor
        .set_status(format!("package-menu: {label} — {shown} package(s)"));
}

/// Read the filter's text at a prompt, then apply it. `make` turns what was typed
/// into the filter, so each `package-menu-filter-by-*` command is one line.
fn package_menu_filter_prompt(
    cx: &mut Context,
    label: &'static str,
    make: fn(String) -> pkg::Filter,
) {
    prompt_then(cx, label, move |cx, input| {
        let filter = make(input.trim().to_string());
        let name = filter.label();
        crate::ui::package_menu::with_menu(|m| m.add_filter(filter));
        let shown = crate::ui::package_menu::with_menu(|m| m.visible().len());
        cx.editor
            .set_status(format!("package-menu: {name} — {shown} package(s)"));
    });
}

/// Emacs `package-menu-filter-by-name` (`/ n`).
fn package_menu_filter_by_name(cx: &mut Context) {
    package_menu_filter_prompt(cx, "Filter by name: ", pkg::Filter::Name);
}

/// Emacs `package-menu-filter-by-description` (`/ d`).
fn package_menu_filter_by_description(cx: &mut Context) {
    package_menu_filter_prompt(cx, "Filter by description: ", pkg::Filter::Description);
}

